export type PrismaDelegate = {
  findMany?: (args?: unknown) => Promise<unknown[]>;
  findUnique?: (args?: unknown) => Promise<unknown | null>;
  findFirst?: (args?: unknown) => Promise<unknown | null>;
  count?: (args?: unknown) => Promise<number>;
};

export type AdminModuleOptions = {
  prisma: PrismaClient;
  appLocals?: Record<string, unknown>;
  store?: AdminFileStore;
  providerStore?: AdminProviderConfigStore;
  getRuntimeHealth?: () => Record<string, unknown>;
};


type StreamBillingLedgerReadOnlyDelegateAdapter = {
  readonly count: (args?: unknown) => Promise<number>;
  readonly findMany: (args?: unknown) => Promise<unknown[]>;
  readonly findFirst: (args?: unknown) => Promise<unknown | null>;
  readonly groupBy: (args?: unknown) => Promise<unknown[]>;
  readonly aggregate: (args?: unknown) => Promise<unknown>;
};

type StreamBillingLedgerReadOnlyDelegateName =
  | "streamPurchaseIntent"
  | "streamPurchaseClassification"
  | "streamGooglePurchaseVerification"
  | "streamAppendOnlyLedgerEntry"
  | "streamLedgerHold"
  | "streamCreatorEarningState"
  | "streamMerchantSettlementState"
  | "streamRefundVoidAdjustment"
  | "streamIdempotencyKey"
  | "streamProviderGateSnapshot";

function createStreamBillingLedgerReadOnlyPrismaDelegateAdapter(
  client: PrismaClient,
): Readonly<Record<StreamBillingLedgerReadOnlyDelegateName, StreamBillingLedgerReadOnlyDelegateAdapter>> {
  const source = client as unknown as Record<string, {
    readonly count?: (args?: never) => Promise<number>;
    readonly findMany?: (args?: never) => Promise<unknown[]>;
    readonly findFirst?: (args?: never) => Promise<unknown | null>;
    readonly groupBy?: (args?: never) => Promise<unknown[]>;
    readonly aggregate?: (args?: never) => Promise<unknown>;
  }>;

  const names: readonly StreamBillingLedgerReadOnlyDelegateName[] = [
    "streamPurchaseIntent",
    "streamPurchaseClassification",
    "streamGooglePurchaseVerification",
    "streamAppendOnlyLedgerEntry",
    "streamLedgerHold",
    "streamCreatorEarningState",
    "streamMerchantSettlementState",
    "streamRefundVoidAdjustment",
    "streamIdempotencyKey",
    "streamProviderGateSnapshot",
  ] as const;

  const adapted = {} as Record<StreamBillingLedgerReadOnlyDelegateName, StreamBillingLedgerReadOnlyDelegateAdapter>;

  for (const name of names) {
    const delegate = source[name];

    adapted[name] = {
      count: (args?: unknown) => {
        if (!delegate || typeof delegate.count !== "function") return Promise.resolve(0);
        return delegate.count(args as never);
      },
      findMany: (args?: unknown) => {
        if (!delegate || typeof delegate.findMany !== "function") return Promise.resolve([]);
        return delegate.findMany(args as never);
      },
      findFirst: (args?: unknown) => {
        if (!delegate || typeof delegate.findFirst !== "function") return Promise.resolve(null);
        return delegate.findFirst(args as never);
      },
      groupBy: (args?: unknown) => {
        if (!delegate || typeof delegate.groupBy !== "function") return Promise.resolve([]);
        return delegate.groupBy(args as never);
      },
      aggregate: (args?: unknown) => {
        if (!delegate || typeof delegate.aggregate !== "function") return Promise.resolve({});
        return delegate.aggregate(args as never);
      },
    };
  }

  return adapted;
}

function getDelegate(client: PrismaClient, candidates: string[]): PrismaDelegate | null {
  const record = client as unknown as Record<string, unknown>;

  for (const candidate of candidates) {
    const delegate = record[candidate] as PrismaDelegate | undefined;
    if (delegate && typeof delegate === "object") return delegate;
  }

  return null;
}

const ADMIN_MESSENGER_DB_TIMEOUT_MS = Math.max(5000, Number(process.env.ADMIN_MESSENGER_DB_TIMEOUT_MS || 15000));
const ADMIN_MESSENGER_DB_MAX_TAKE = Math.max(25, Math.min(300, Number(process.env.ADMIN_MESSENGER_DB_MAX_TAKE || 120)));
const adminMessengerDbTimeoutLogState = new Map<string, number>();

function shouldLogAdminMessengerDbTimeout(label: string): boolean {
  const now = Date.now();
  const previous = adminMessengerDbTimeoutLogState.get(label) ?? 0;
  if (now - previous < 30000) return false;
  adminMessengerDbTimeoutLogState.set(label, now);
  return true;
}

async function withAdminMessengerDbTimeout<T>(label: string, operation: Promise<T>, fallback: T): Promise<T> {
  let settled = false;
  let timer: NodeJS.Timeout | null = null;
  const timeout = new Promise<T>((resolve) => {
    timer = setTimeout(() => {
      if (!settled) {
        if (shouldLogAdminMessengerDbTimeout(label)) console.warn(`[sabi-admin:messenger-db-timeout] ${label} exceeded ${ADMIN_MESSENGER_DB_TIMEOUT_MS}ms`);
        resolve(fallback);
      }
    }, ADMIN_MESSENGER_DB_TIMEOUT_MS);
  });

  try {
    const result = await Promise.race([operation, timeout]);
    settled = true;
    return result;
  } catch (error) {
    settled = true;
    console.warn(`[sabi-admin:messenger-db-error] ${label}`, error);
    return fallback;
  } finally {
    if (timer) clearTimeout(timer);
  }
}

function isAdminMessengerPlainRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}

function isAdminMessengerPresenceDelegateLabel(label: string): boolean {
  const normalized = label.toLowerCase();
  return normalized.includes("messengerpresence") || normalized.includes("presence") || normalized.includes("onlineuser") || normalized.includes("usersession") || normalized.includes("authsession");
}

function normalizeAdminMessengerPresenceWhereForKnownSchema(value: unknown): unknown {
  if (!isAdminMessengerPlainRecord(value)) return value;
  const where: Record<string, unknown> = { ...value };
  const lastSeenAt = where.lastSeenAt;
  if (lastSeenAt !== undefined && where.lastSeen === undefined) {
    where.lastSeen = lastSeenAt;
  }
  delete where.lastSeenAt;

  for (const key of ["AND", "OR", "NOT"]) {
    const child = where[key];
    if (Array.isArray(child)) {
      where[key] = child.map((item) => normalizeAdminMessengerPresenceWhereForKnownSchema(item));
    } else if (isAdminMessengerPlainRecord(child)) {
      where[key] = normalizeAdminMessengerPresenceWhereForKnownSchema(child);
    }
  }

  return where;
}

function normalizeAdminMessengerPresenceOrderByForKnownSchema(value: unknown): unknown {
  if (Array.isArray(value)) return value.map((item) => normalizeAdminMessengerPresenceOrderByForKnownSchema(item));
  if (!isAdminMessengerPlainRecord(value)) return value;
  const orderBy: Record<string, unknown> = { ...value };
  const createdAtOrder = orderBy.createdAt;
  if (createdAtOrder !== undefined && orderBy.updatedAt === undefined) {
    orderBy.updatedAt = createdAtOrder;
  }
  delete orderBy.createdAt;
  return orderBy;
}

function normalizeAdminMessengerPrismaArgsForKnownSchema(label: string, args?: unknown): unknown {
  if (!isAdminMessengerPlainRecord(args) || !isAdminMessengerPresenceDelegateLabel(label)) return args;

  const normalized: Record<string, unknown> = { ...args };

  if (isAdminMessengerPlainRecord(normalized.where)) {
    normalized.where = normalizeAdminMessengerPresenceWhereForKnownSchema(normalized.where);
  }

  if (normalized.orderBy !== undefined) {
    normalized.orderBy = normalizeAdminMessengerPresenceOrderByForKnownSchema(normalized.orderBy);
  }

  return normalized;
}

async function safeAdminFindMany(delegate: PrismaDelegate, label: string, args?: unknown): Promise<unknown[]> {
  if (typeof delegate.findMany !== "function") return [];
  const normalizedArgs = normalizeAdminMessengerPrismaArgsForKnownSchema(label, args);
  const rows = await withAdminMessengerDbTimeout(label, delegate.findMany(normalizedArgs), [] as unknown[]);
  return Array.isArray(rows) ? rows : [];
}

async function safeAdminFindFirst(delegate: PrismaDelegate, label: string, args?: unknown): Promise<unknown | null> {
  if (typeof delegate.findFirst !== "function") return null;
  const normalizedArgs = normalizeAdminMessengerPrismaArgsForKnownSchema(label, args);
  return withAdminMessengerDbTimeout(label, delegate.findFirst(normalizedArgs), null);
}

async function safeAdminFindUnique(delegate: PrismaDelegate, label: string, args?: unknown): Promise<unknown | null> {
  if (typeof delegate.findUnique !== "function") return null;
  const normalizedArgs = normalizeAdminMessengerPrismaArgsForKnownSchema(label, args);
  return withAdminMessengerDbTimeout(label, delegate.findUnique(normalizedArgs), null);
}

async function safeAdminCount(delegate: PrismaDelegate, label: string, args?: unknown): Promise<number> {
  if (typeof delegate.count !== "function") return 0;
  const normalizedArgs = normalizeAdminMessengerPrismaArgsForKnownSchema(label, args);
  const count = await withAdminMessengerDbTimeout(label, delegate.count(normalizedArgs), 0);
  return Number.isFinite(count) ? count : 0;
}

function readLimit(req: Request, fallback = 50, max = 200): number {
  const raw = Array.isArray(req.query.limit) ? req.query.limit[0] : req.query.limit;
  const value = Number(raw);
  if (!Number.isFinite(value) || value <= 0) return fallback;
  return Math.min(Math.floor(value), max);
}

function readQueryText(req: Request): string | null {
  const raw = Array.isArray(req.query.q) ? req.query.q[0] : req.query.q;
  if (typeof raw !== "string") return null;
  const trimmed = raw.trim();
  return trimmed ? trimmed : null;
}

function sanitizeUser(value: unknown): Record<string, unknown> | unknown {
  if (!value || typeof value !== "object") return value;
  const source = value as Record<string, unknown>;
  const sanitized: Record<string, unknown> = { ...source };
  delete sanitized.password;
  delete sanitized.passwordHash;
  delete sanitized.refreshToken;
  delete sanitized.accessToken;
  delete sanitized.otp;
  delete sanitized.otpCode;
  return sanitized;
}

function getParam(req: Request, name: string): string {
  const value = req.params[name];
  return typeof value === "string" ? value : "";
}


function readString(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const trimmed = value.trim();
  return trimmed ? trimmed : undefined;
}

function readStringArray(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return value.filter((item): item is string => typeof item === "string" && Boolean(item.trim())).map((item) => item.trim());
}

function readBodyObject(req: Request): Record<string, unknown> {
  return req.body && typeof req.body === "object" ? (req.body as Record<string, unknown>) : {};
}


type AdminMessengerStoredFeatureFlag = {
  key: string;
  enabled: boolean;
  updatedBy: string;
  updatedAt: string;
  note?: string;
};

type AdminMessengerStoredLaunchBlocker = {
  id: string;
  key: string;
  title: string;
  message: string;
  severity: "warning" | "critical";
  status: "active" | "resolved";
  createdBy: string;
  createdAt: string;
  resolvedBy?: string;
  resolvedAt?: string;
  resolutionNote?: string;
};

type AdminMessengerStoredControlState = {
  featureFlags: AdminMessengerStoredFeatureFlag[];
  launchBlockers: AdminMessengerStoredLaunchBlocker[];
  updatedAt: string;
};

const ADMIN_MESSENGER_CONTROL_FILE = path.join(process.cwd(), ".data", "admin", "messenger-control.json");

function createAdminLocalId(prefix: string): string {
  return `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

function defaultMessengerControlState(): AdminMessengerStoredControlState {
  return { featureFlags: [], launchBlockers: [], updatedAt: new Date().toISOString() };
}

function readMessengerControlState(): AdminMessengerStoredControlState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_CONTROL_FILE)) return defaultMessengerControlState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_CONTROL_FILE, "utf8")) as Partial<AdminMessengerStoredControlState>;
    return {
      featureFlags: Array.isArray(parsed.featureFlags) ? parsed.featureFlags.filter((item): item is AdminMessengerStoredFeatureFlag => Boolean(item && typeof item.key === "string" && typeof item.enabled === "boolean")) : [],
      launchBlockers: Array.isArray(parsed.launchBlockers) ? parsed.launchBlockers.filter((item): item is AdminMessengerStoredLaunchBlocker => Boolean(item && typeof item.id === "string" && typeof item.key === "string")) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerControlState();
  }
}

function writeMessengerControlState(state: AdminMessengerStoredControlState): AdminMessengerStoredControlState {
  const next = { ...state, updatedAt: new Date().toISOString() };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_CONTROL_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_CONTROL_FILE, JSON.stringify(next, null, 2));
  return next;
}


type AdminMessengerContentQualitySeverity = "low" | "medium" | "high" | "critical";
type AdminMessengerContentQualitySignalStatus = "open" | "acknowledged" | "quarantined" | "resolved" | "released";
type AdminMessengerContentQualitySignalKind =
  | "spam"
  | "flood"
  | "scam"
  | "phishing"
  | "bot_abuse"
  | "group_raid"
  | "channel_flood"
  | "promotion_abuse"
  | "duplicate_content"
  | "unsafe_public_content"
  | "unknown";
type AdminMessengerContentQualityTargetKind = "user" | "chat" | "group" | "channel" | "bot" | "promotion" | "message_metadata" | "unknown";

type AdminMessengerContentQualitySettings = {
  centerEnabled: boolean;
  publicContentQualityRequired: boolean;
  antiSpamEnabled: boolean;
  rateLimitEnabled: boolean;
  duplicateContentGuardEnabled: boolean;
  linkSpamGuardEnabled: boolean;
  botAbuseGuardEnabled: boolean;
  groupRaidGuardEnabled: boolean;
  channelFloodGuardEnabled: boolean;
  promotionAbuseGuardEnabled: boolean;
  quarantineEnabled: boolean;
  manualReviewRequiredForHighRisk: boolean;
  ownerApprovalRequiredForMassAction: boolean;
  rawPrivateContentStorageAllowed: false;
  maxMessagesPerMinute: number;
  maxForwardsPerHour: number;
  duplicateWindowMinutes: number;
  publicQualityMinimumScore: number;
  promotionQualityMinimumScore: number;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerContentQualitySignal = {
  id: string;
  kind: AdminMessengerContentQualitySignalKind;
  targetKind: AdminMessengerContentQualityTargetKind;
  targetId: string;
  status: AdminMessengerContentQualitySignalStatus;
  severity: AdminMessengerContentQualitySeverity;
  reason: string;
  source: "admin" | "ai_safety" | "runtime_guard" | "user_report" | "system";
  score: number;
  metadataOnly: true;
  rawContentIncluded: false;
  evidenceHash: string;
  traceHash: string;
  createdBy: string;
  createdAt: string;
  updatedBy: string;
  updatedAt: string;
  acknowledgedBy?: string;
  acknowledgedAt?: string;
  quarantinedBy?: string;
  quarantinedAt?: string;
  resolvedBy?: string;
  resolvedAt?: string;
  releasedBy?: string;
  releasedAt?: string;
  note?: string;
};

type AdminMessengerContentQualityState = {
  settings: AdminMessengerContentQualitySettings;
  signals: AdminMessengerContentQualitySignal[];
  updatedAt: string;
};

const ADMIN_MESSENGER_CONTENT_QUALITY_FILE = path.join(process.cwd(), ".data", "admin", "messenger-content-quality.json");

function defaultMessengerContentQualitySettings(): AdminMessengerContentQualitySettings {
  const now = new Date().toISOString();
  return {
    centerEnabled: true,
    publicContentQualityRequired: true,
    antiSpamEnabled: true,
    rateLimitEnabled: true,
    duplicateContentGuardEnabled: true,
    linkSpamGuardEnabled: true,
    botAbuseGuardEnabled: true,
    groupRaidGuardEnabled: true,
    channelFloodGuardEnabled: true,
    promotionAbuseGuardEnabled: true,
    quarantineEnabled: true,
    manualReviewRequiredForHighRisk: true,
    ownerApprovalRequiredForMassAction: true,
    rawPrivateContentStorageAllowed: false,
    maxMessagesPerMinute: 30,
    maxForwardsPerHour: 60,
    duplicateWindowMinutes: 10,
    publicQualityMinimumScore: 75,
    promotionQualityMinimumScore: 80,
    updatedBy: "system",
    updatedAt: now,
  };
}

function defaultMessengerContentQualityState(): AdminMessengerContentQualityState {
  return { settings: defaultMessengerContentQualitySettings(), signals: [], updatedAt: new Date().toISOString() };
}

function isMessengerContentQualitySignalKind(value: string): value is AdminMessengerContentQualitySignalKind {
  return ["spam", "flood", "scam", "phishing", "bot_abuse", "group_raid", "channel_flood", "promotion_abuse", "duplicate_content", "unsafe_public_content", "unknown"].includes(value);
}

function isMessengerContentQualityTargetKind(value: string): value is AdminMessengerContentQualityTargetKind {
  return ["user", "chat", "group", "channel", "bot", "promotion", "message_metadata", "unknown"].includes(value);
}

function isMessengerContentQualitySeverity(value: string): value is AdminMessengerContentQualitySeverity {
  return ["low", "medium", "high", "critical"].includes(value);
}

function isMessengerContentQualityStatus(value: string): value is AdminMessengerContentQualitySignalStatus {
  return ["open", "acknowledged", "quarantined", "resolved", "released"].includes(value);
}

function normalizeMessengerContentQualitySettings(value: unknown): AdminMessengerContentQualitySettings {
  const defaults = defaultMessengerContentQualitySettings();
  const source = value && typeof value === "object" ? (value as Record<string, unknown>) : {};
  return {
    centerEnabled: readBoolean(source.centerEnabled, defaults.centerEnabled),
    publicContentQualityRequired: readBoolean(source.publicContentQualityRequired, defaults.publicContentQualityRequired),
    antiSpamEnabled: readBoolean(source.antiSpamEnabled, defaults.antiSpamEnabled),
    rateLimitEnabled: readBoolean(source.rateLimitEnabled, defaults.rateLimitEnabled),
    duplicateContentGuardEnabled: readBoolean(source.duplicateContentGuardEnabled, defaults.duplicateContentGuardEnabled),
    linkSpamGuardEnabled: readBoolean(source.linkSpamGuardEnabled, defaults.linkSpamGuardEnabled),
    botAbuseGuardEnabled: readBoolean(source.botAbuseGuardEnabled, defaults.botAbuseGuardEnabled),
    groupRaidGuardEnabled: readBoolean(source.groupRaidGuardEnabled, defaults.groupRaidGuardEnabled),
    channelFloodGuardEnabled: readBoolean(source.channelFloodGuardEnabled, defaults.channelFloodGuardEnabled),
    promotionAbuseGuardEnabled: readBoolean(source.promotionAbuseGuardEnabled, defaults.promotionAbuseGuardEnabled),
    quarantineEnabled: readBoolean(source.quarantineEnabled, defaults.quarantineEnabled),
    manualReviewRequiredForHighRisk: readBoolean(source.manualReviewRequiredForHighRisk, defaults.manualReviewRequiredForHighRisk),
    ownerApprovalRequiredForMassAction: readBoolean(source.ownerApprovalRequiredForMassAction, defaults.ownerApprovalRequiredForMassAction),
    rawPrivateContentStorageAllowed: false,
    maxMessagesPerMinute: Math.max(1, Math.min(600, readNumber(source.maxMessagesPerMinute, defaults.maxMessagesPerMinute))),
    maxForwardsPerHour: Math.max(1, Math.min(2000, readNumber(source.maxForwardsPerHour, defaults.maxForwardsPerHour))),
    duplicateWindowMinutes: Math.max(1, Math.min(1440, readNumber(source.duplicateWindowMinutes, defaults.duplicateWindowMinutes))),
    publicQualityMinimumScore: Math.max(1, Math.min(100, readNumber(source.publicQualityMinimumScore, defaults.publicQualityMinimumScore))),
    promotionQualityMinimumScore: Math.max(1, Math.min(100, readNumber(source.promotionQualityMinimumScore, defaults.promotionQualityMinimumScore))),
    updatedBy: readString(source.updatedBy) ?? defaults.updatedBy,
    updatedAt: readString(source.updatedAt) ?? defaults.updatedAt,
  };
}

function normalizeMessengerContentQualitySignal(value: unknown): AdminMessengerContentQualitySignal | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  const targetId = readString(source.targetId);
  if (!id || !targetId) return null;
  const kindRaw = readString(source.kind) ?? "unknown";
  const targetKindRaw = readString(source.targetKind) ?? "unknown";
  const statusRaw = readString(source.status) ?? "open";
  const severityRaw = readString(source.severity) ?? "medium";
  return {
    id,
    kind: isMessengerContentQualitySignalKind(kindRaw) ? kindRaw : "unknown",
    targetKind: isMessengerContentQualityTargetKind(targetKindRaw) ? targetKindRaw : "unknown",
    targetId,
    status: isMessengerContentQualityStatus(statusRaw) ? statusRaw : "open",
    severity: isMessengerContentQualitySeverity(severityRaw) ? severityRaw : "medium",
    reason: readString(source.reason) ?? "admin_review",
    source: (["admin", "ai_safety", "runtime_guard", "user_report", "system"].includes(readString(source.source) ?? "") ? readString(source.source) : "admin") as AdminMessengerContentQualitySignal["source"],
    score: Math.max(0, Math.min(100, readNumber(source.score, 50))),
    metadataOnly: true,
    rawContentIncluded: false,
    evidenceHash: readString(source.evidenceHash) ?? createMessengerContentQualityTraceHash({ id, targetId, reason: readString(source.reason) ?? "admin_review" }),
    traceHash: readString(source.traceHash) ?? createMessengerContentQualityTraceHash({ id, targetId, status: statusRaw }),
    createdBy: readString(source.createdBy) ?? "system",
    createdAt: readString(source.createdAt) ?? new Date().toISOString(),
    updatedBy: readString(source.updatedBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? new Date().toISOString(),
    acknowledgedBy: readString(source.acknowledgedBy),
    acknowledgedAt: readString(source.acknowledgedAt),
    quarantinedBy: readString(source.quarantinedBy),
    quarantinedAt: readString(source.quarantinedAt),
    resolvedBy: readString(source.resolvedBy),
    resolvedAt: readString(source.resolvedAt),
    releasedBy: readString(source.releasedBy),
    releasedAt: readString(source.releasedAt),
    note: readString(source.note),
  };
}

function readMessengerContentQualityState(): AdminMessengerContentQualityState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_CONTENT_QUALITY_FILE)) return defaultMessengerContentQualityState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_CONTENT_QUALITY_FILE, "utf8")) as Partial<AdminMessengerContentQualityState>;
    return {
      settings: normalizeMessengerContentQualitySettings(parsed.settings),
      signals: Array.isArray(parsed.signals) ? parsed.signals.map(normalizeMessengerContentQualitySignal).filter((item): item is AdminMessengerContentQualitySignal => Boolean(item)) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerContentQualityState();
  }
}

function writeMessengerContentQualityState(state: AdminMessengerContentQualityState): AdminMessengerContentQualityState {
  const next = { ...state, updatedAt: new Date().toISOString() };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_CONTENT_QUALITY_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_CONTENT_QUALITY_FILE, JSON.stringify(next, null, 2));
  return next;
}

function createMessengerContentQualityTraceHash(value: unknown): string {
  return crypto.createHash("sha256").update(JSON.stringify(value)).digest("hex");
}

function createMessengerContentQualitySignal(body: Record<string, unknown>, adminId: string): AdminMessengerContentQualitySignal {
  const targetId = readString(body.targetId);
  if (!targetId) throw new Error("messenger_content_quality_target_id_required");
  const now = new Date().toISOString();
  const kindRaw = readString(body.kind) ?? "unknown";
  const targetKindRaw = readString(body.targetKind) ?? "unknown";
  const severityRaw = readString(body.severity) ?? "medium";
  const reason = readString(body.reason) ?? "admin_review";
  const id = createAdminLocalId("messenger_content_quality_signal");
  const sourceRaw = readString(body.source) ?? "admin";
  const payload = { id, kind: kindRaw, targetKind: targetKindRaw, targetId, severity: severityRaw, reason, createdAt: now, metadataOnly: true };
  return {
    id,
    kind: isMessengerContentQualitySignalKind(kindRaw) ? kindRaw : "unknown",
    targetKind: isMessengerContentQualityTargetKind(targetKindRaw) ? targetKindRaw : "unknown",
    targetId,
    status: "open",
    severity: isMessengerContentQualitySeverity(severityRaw) ? severityRaw : "medium",
    reason,
    source: (["admin", "ai_safety", "runtime_guard", "user_report", "system"].includes(sourceRaw) ? sourceRaw : "admin") as AdminMessengerContentQualitySignal["source"],
    score: Math.max(0, Math.min(100, readNumber(body.score, severityRaw === "critical" ? 95 : severityRaw === "high" ? 80 : 55))),
    metadataOnly: true,
    rawContentIncluded: false,
    evidenceHash: createMessengerContentQualityTraceHash({ ...payload, evidence: readString(body.evidenceHash) ?? "metadata_only" }),
    traceHash: createMessengerContentQualityTraceHash(payload),
    createdBy: adminId,
    createdAt: now,
    updatedBy: adminId,
    updatedAt: now,
    note: readString(body.note),
  };
}

function updateMessengerContentQualitySignalStatus(id: string, status: AdminMessengerContentQualitySignalStatus, body: Record<string, unknown>, adminId: string): AdminMessengerContentQualitySignal {
  const state = readMessengerContentQualityState();
  const now = new Date().toISOString();
  const nextSignals = state.signals.map((item) => {
    if (item.id !== id) return item;
    const updated: AdminMessengerContentQualitySignal = {
      ...item,
      status,
      updatedBy: adminId,
      updatedAt: now,
      note: readString(body.note) ?? item.note,
      traceHash: createMessengerContentQualityTraceHash({ id: item.id, status, targetId: item.targetId, updatedAt: now }),
    };
    if (status === "acknowledged") {
      updated.acknowledgedBy = adminId;
      updated.acknowledgedAt = now;
    }
    if (status === "quarantined") {
      updated.quarantinedBy = adminId;
      updated.quarantinedAt = now;
    }
    if (status === "resolved") {
      updated.resolvedBy = adminId;
      updated.resolvedAt = now;
    }
    if (status === "released") {
      updated.releasedBy = adminId;
      updated.releasedAt = now;
    }
    return updated;
  });
  const updated = nextSignals.find((item) => item.id === id);
  if (!updated) throw new Error("messenger_content_quality_signal_not_found");
  writeMessengerContentQualityState({ ...state, signals: nextSignals });
  return updated;
}


type AdminMessengerGrowthPromotionTargetKind = "channel" | "group" | "bot";
type AdminMessengerGrowthPromotionStatus = "draft" | "pending_approval" | "approved" | "active" | "paused" | "completed" | "rejected";
type AdminMessengerGreetingOccasion = "birthday" | "holiday" | "custom";
type AdminMessengerGreetingMode = "automatic" | "manual";
