function normalizeMessengerGreetingAutomationRun(value: unknown): AdminMessengerGreetingAutomationRun | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  if (!id) return null;
  const now = new Date().toISOString();
  const createdAt = readString(source.createdAt) ?? now;
  const occasion = normalizeMessengerGreetingOccasion(source.occasion);
  const runSource: AdminMessengerGreetingAutomationRun["source"] = source.source === "holiday_calendar" || source.source === "manual_seed_list" || source.source === "verified_profile_birthdays" ? source.source : "manual_seed_list";
  const status: AdminMessengerGreetingAutomationRun["status"] = source.status === "dry_run" || source.status === "completed" || source.status === "blocked" ? source.status : "blocked";
  const base = {
    id,
    occasion,
    mode: "automatic" as const,
    source: runSource,
    status,
    holidayKey: readString(source.holidayKey),
    templateId: readString(source.templateId),
    scheduledAt: readString(source.scheduledAt) ?? now,
    language: readString(source.language),
    targetUserCount: Math.max(0, Math.floor(Number(source.targetUserCount) || 0)),
    createdTaskCount: Math.max(0, Math.floor(Number(source.createdTaskCount) || 0)),
    skippedDuplicate: Math.max(0, Math.floor(Number(source.skippedDuplicate) || 0)),
    skippedByCooldown: Math.max(0, Math.floor(Number(source.skippedByCooldown) || 0)),
    skippedByDailyLimit: Math.max(0, Math.floor(Number(source.skippedByDailyLimit) || 0)),
    skippedMissingTemplate: Math.max(0, Math.floor(Number(source.skippedMissingTemplate) || 0)),
    rawPrivateContentIncluded: false as const,
    createdBy: readString(source.createdBy) ?? "system",
    createdAt,
    note: readString(source.note),
  };
  return { ...base, traceHash: readString(source.traceHash) ?? createMessengerGrowthTraceHash({ kind: "automation_run", id, createdAt }) };
}

function normalizeMessengerGreetingTask(value: unknown): AdminMessengerGreetingTask | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  const targetUserId = readString(source.targetUserId);
  if (!id || !targetUserId) return null;
  const now = new Date().toISOString();
  const createdAt = readString(source.createdAt) ?? now;
  const updatedAt = readString(source.updatedAt) ?? createdAt;
  const scheduledAt = readString(source.scheduledAt) ?? now;
  const occasion = normalizeMessengerGreetingOccasion(source.occasion);
  const mode = normalizeMessengerGreetingMode(source.mode);
  const contactUserId = readString(source.contactUserId);
  const holidayKey = readString(source.holidayKey);
  const dedupeKey = readString(source.dedupeKey) ?? [occasion, mode, targetUserId, contactUserId ?? "self", holidayKey ?? scheduledAt.slice(0, 10)].join(":");
  const base = {
    id,
    occasion,
    mode,
    status: normalizeMessengerGreetingStatus(source.status, mode === "automatic" ? "queued" : "draft"),
    templateId: readString(source.templateId),
    targetUserId,
    contactUserId,
    scheduledAt,
    holidayKey,
    language: readString(source.language),
    dedupeKey,
    approvedBy: readString(source.approvedBy),
    approvedAt: readString(source.approvedAt),
    sentBy: readString(source.sentBy),
    sentAt: readString(source.sentAt),
    cancelledBy: readString(source.cancelledBy),
    cancelledAt: readString(source.cancelledAt),
    failureReason: readString(source.failureReason),
    rawPrivateContentIncluded: false as const,
    createdBy: readString(source.createdBy) ?? "system",
    createdAt,
    updatedBy: readString(source.updatedBy) ?? "system",
    updatedAt,
    note: readString(source.note),
  };
  return { ...base, traceHash: readString(source.traceHash) ?? createMessengerGrowthTraceHash({ kind: "greeting", id, targetUserId, dedupeKey, updatedAt }) };
}

