function readMessengerGrowthPromotionState(): AdminMessengerGrowthPromotionState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_GROWTH_PROMOTION_FILE)) return defaultMessengerGrowthPromotionState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_GROWTH_PROMOTION_FILE, "utf8")) as Partial<AdminMessengerGrowthPromotionState>;
    return {
      settings: normalizeMessengerGrowthSettings(parsed.settings),
      promotions: Array.isArray(parsed.promotions) ? parsed.promotions.map(normalizeMessengerPromotionCampaign).filter((item): item is AdminMessengerGrowthPromotionCampaign => Boolean(item)) : [],
      greetingTemplates: Array.isArray(parsed.greetingTemplates) ? parsed.greetingTemplates.map(normalizeMessengerGreetingTemplate).filter((item): item is AdminMessengerGreetingTemplate => Boolean(item)) : defaultMessengerGrowthPromotionState().greetingTemplates,
      greetingTasks: Array.isArray(parsed.greetingTasks) ? parsed.greetingTasks.map(normalizeMessengerGreetingTask).filter((item): item is AdminMessengerGreetingTask => Boolean(item)) : [],
      greetingHolidays: Array.isArray(parsed.greetingHolidays) ? parsed.greetingHolidays.map(normalizeMessengerGreetingHoliday).filter((item): item is AdminMessengerGreetingHoliday => Boolean(item)) : defaultMessengerGrowthPromotionState().greetingHolidays,
      greetingAutomationRuns: Array.isArray(parsed.greetingAutomationRuns) ? parsed.greetingAutomationRuns.map(normalizeMessengerGreetingAutomationRun).filter((item): item is AdminMessengerGreetingAutomationRun => Boolean(item)) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerGrowthPromotionState();
  }
}

function writeMessengerGrowthPromotionState(state: AdminMessengerGrowthPromotionState): AdminMessengerGrowthPromotionState {
  const next = { ...state, updatedAt: new Date().toISOString(), settings: { ...state.settings, rawPrivateContentAllowed: false as const, profileBirthdaySource: "verified_profile_only" as const } };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_GROWTH_PROMOTION_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_GROWTH_PROMOTION_FILE, JSON.stringify(next, null, 2));
  return next;
}

function readMessengerFlagEnabled(value: unknown): boolean | null {
  if (typeof value === "boolean") return value;
  if (typeof value === "string") {
    const normalized = value.trim().toLowerCase();
    if (["true", "1", "yes", "enabled", "on"].includes(normalized)) return true;
    if (["false", "0", "no", "disabled", "off"].includes(normalized)) return false;
  }
  return null;
}

function activeMessengerLaunchBlockers(): AdminMessengerStoredLaunchBlocker[] {
  return readMessengerControlState().launchBlockers.filter((item) => item.status === "active");
}

