const ADMIN_MESSENGER_MODERATION_CONTROL_FILE = path.join(process.cwd(), ".data", "admin", "messenger-moderation-control.json");

function defaultMessengerPremiumSettings(): AdminMessengerPremiumSettings {
  const now = new Date().toISOString();
  return {
    aiTranslationEnabled: false,
    premiumStickersEnabled: true,
    gift3dPremiumEnabled: true,
    animatedEmojiEnabled: true,
    paidBotsEnabled: true,
    coinPaymentsRequired: true,
    adminReviewForPremiumAbuse: true,
    updatedBy: "system",
    updatedAt: now,
  };
}

function defaultMessengerModerationControlState(): AdminMessengerModerationControlState {
  return { reports: [], premiumSettings: defaultMessengerPremiumSettings(), updatedAt: new Date().toISOString() };
}

function normalizeMessengerModerationStatus(value: unknown, fallback: AdminMessengerModerationStatus): AdminMessengerModerationStatus {
  return value === "open" || value === "in_review" || value === "resolved" || value === "rejected" ? value : fallback;
}

function normalizeMessengerModerationSeverity(value: unknown): AdminMessengerModerationSeverity {
  return value === "critical" || value === "high" || value === "medium" || value === "low" ? value : "medium";
}

function normalizeMessengerModerationKind(value: unknown): AdminMessengerModerationKind {
  const allowed: AdminMessengerModerationKind[] = ["message", "media", "group", "channel", "bot", "user", "call", "sticker", "gift"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerModerationKind) ? value as AdminMessengerModerationKind : "message";
}

function normalizeMessengerModerationSource(value: unknown): AdminMessengerModerationSource {
  return value === "ai_signal" || value === "admin_manual" || value === "system" || value === "user_report" ? value : "admin_manual";
}

function readMessengerModerationControlState(): AdminMessengerModerationControlState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_MODERATION_CONTROL_FILE)) return defaultMessengerModerationControlState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_MODERATION_CONTROL_FILE, "utf8")) as Partial<AdminMessengerModerationControlState>;
    const defaults = defaultMessengerModerationControlState();
    const rawPremium = parsed.premiumSettings && typeof parsed.premiumSettings === "object" ? parsed.premiumSettings : defaults.premiumSettings;
    const rawPremiumRecord = rawPremium as Record<string, unknown>;
    const premiumSettings: AdminMessengerPremiumSettings = {
      aiTranslationEnabled: readBoolean(rawPremiumRecord.aiTranslationEnabled, defaults.premiumSettings.aiTranslationEnabled),
      premiumStickersEnabled: readBoolean(rawPremiumRecord.premiumStickersEnabled, defaults.premiumSettings.premiumStickersEnabled),
      gift3dPremiumEnabled: readBoolean(rawPremiumRecord.gift3dPremiumEnabled, defaults.premiumSettings.gift3dPremiumEnabled),
      animatedEmojiEnabled: readBoolean(rawPremiumRecord.animatedEmojiEnabled, defaults.premiumSettings.animatedEmojiEnabled),
      paidBotsEnabled: readBoolean(rawPremiumRecord.paidBotsEnabled, defaults.premiumSettings.paidBotsEnabled),
      coinPaymentsRequired: readBoolean(rawPremiumRecord.coinPaymentsRequired, defaults.premiumSettings.coinPaymentsRequired),
      adminReviewForPremiumAbuse: readBoolean(rawPremiumRecord.adminReviewForPremiumAbuse, defaults.premiumSettings.adminReviewForPremiumAbuse),
      updatedBy: typeof rawPremiumRecord.updatedBy === "string" ? rawPremiumRecord.updatedBy : defaults.premiumSettings.updatedBy,
      updatedAt: typeof rawPremiumRecord.updatedAt === "string" ? rawPremiumRecord.updatedAt : defaults.premiumSettings.updatedAt,
    };
    const reports = Array.isArray(parsed.reports) ? parsed.reports.filter((item): item is AdminMessengerModerationReport => Boolean(item && typeof item.id === "string" && typeof item.title === "string")).map((item) => ({
      ...item,
      source: normalizeMessengerModerationSource(item.source),
      kind: normalizeMessengerModerationKind(item.kind),
      severity: normalizeMessengerModerationSeverity(item.severity),
      status: normalizeMessengerModerationStatus(item.status, "open"),
    })) : [];
    return { reports, premiumSettings, updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString() };
  } catch {
    return defaultMessengerModerationControlState();
  }
}

function writeMessengerModerationControlState(state: AdminMessengerModerationControlState): AdminMessengerModerationControlState {
  const next = { ...state, updatedAt: new Date().toISOString() };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_MODERATION_CONTROL_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_MODERATION_CONTROL_FILE, JSON.stringify(next, null, 2));
  return next;
}

function buildMessengerModerationDashboard(): AdminMessengerModerationDashboard {
  const control = readMessengerModerationControlState();
  const activePremiumValues = Object.entries(control.premiumSettings).filter(([key, value]) => key.endsWith("Enabled") && value === true).length;
  const openReports = control.reports.filter((item) => item.status === "open").length;
  const inReviewReports = control.reports.filter((item) => item.status === "in_review").length;
  const resolvedReports = control.reports.filter((item) => item.status === "resolved" || item.status === "rejected").length;
  const criticalReports = control.reports.filter((item) => item.status !== "resolved" && item.status !== "rejected" && item.severity === "critical").length;
  return {
    generatedAt: new Date().toISOString(),
    summary: { openReports, inReviewReports, resolvedReports, criticalReports, premiumControlsEnabled: activePremiumValues },
    premiumSettings: control.premiumSettings,
    recentReports: control.reports.slice(0, 50),
    rules: [
      "messenger_admin_moderation_does_not_delete_user_content_directly",
      "messenger_reports_create_review_signals_for_human_admin_decision",
      "premium_messenger_features_are_controlled_from_admin",
      "bots_remain_premium_paid_and_ai_ready",
      "all_messenger_moderation_actions_are_audited",
    ],
  };
}


