const ADMIN_MESSENGER_SAFETY_CONTROL_FILE = path.join(process.cwd(), ".data", "admin", "messenger-safety-control.json");

function messengerSafetyCategories(): Array<{ key: AdminMessengerSafetyCategory; severity: "high" | "critical"; enabled: boolean; description: string }> {
  return [
    { key: "terrorism_or_attack_planning", severity: "critical", enabled: true, description: "Terrorism, attack planning, violent extremism coordination or support." },
    { key: "assassination_or_serious_violence", severity: "critical", enabled: true, description: "Assassination attempts, targeted serious violence, kidnapping threats or imminent harm." },
    { key: "human_trafficking", severity: "critical", enabled: true, description: "Human trafficking, forced labor, exploitation, recruitment or transport coordination." },
    { key: "narcotics_or_psychotropic_trafficking", severity: "critical", enabled: true, description: "Production, sale, distribution, delivery, concealment or payment routing for narcotics/psychotropic substances." },
    { key: "money_laundering_or_aml", severity: "critical", enabled: true, description: "Money laundering, suspicious transfer routing, mule accounts, KYC/AML evasion." },
    { key: "fraud_or_scam", severity: "high", enabled: true, description: "Fraud, scam coordination, social engineering or payment deception." },
    { key: "weapons_or_explosives", severity: "critical", enabled: true, description: "Illegal weapons, explosives or attack materials coordination." },
    { key: "child_exploitation", severity: "critical", enabled: true, description: "Child exploitation, grooming or related abuse signals." },
    { key: "kyc_bypass_or_identity_fraud", severity: "high", enabled: true, description: "Identity fraud, account takeover, KYC bypass or fake verification." },
    { key: "other_critical_safety", severity: "high", enabled: true, description: "Other serious safety/compliance risk requiring admin review." },
  ];
}

function normalizeMessengerSafetyCategory(value: unknown): AdminMessengerSafetyCategory {
  const keys = new Set(messengerSafetyCategories().map((item) => item.key));
  return typeof value === "string" && keys.has(value as AdminMessengerSafetyCategory) ? value as AdminMessengerSafetyCategory : "other_critical_safety";
}

function normalizeMessengerSafetySource(value: unknown): AdminMessengerSafetyReportSource {
  return value === "ai_signal" || value === "admin_manual" || value === "user_report" || value === "system" ? value : "admin_manual";
}

function normalizeMessengerSafetyStatus(value: unknown, fallback: AdminMessengerSafetyReportStatus = "new"): AdminMessengerSafetyReportStatus {
  const allowed: AdminMessengerSafetyReportStatus[] = ["new", "under_review", "target_restricted", "evidence_preserved", "authority_report_prepared", "authority_notified", "resolved", "rejected"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerSafetyReportStatus) ? value as AdminMessengerSafetyReportStatus : fallback;
}

function normalizeConfidence(value: unknown): number {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return 0;
  return Math.max(0, Math.min(1, numeric));
}

function messengerSafetyCategorySeverity(category: AdminMessengerSafetyCategory): "high" | "critical" {
  return messengerSafetyCategories().find((item) => item.key === category)?.severity ?? "high";
}

function defaultMessengerSafetySettings(): AdminMessengerSafetySettings {
  return {
    aiSafetySignalsEnabled: true,
    criticalSignalAutoCreateReport: true,
    autoRestrictCriticalAfterAdminReview: true,
    evidencePreservationEnabled: true,
    lawEnforcementCooperationEnabled: true,
    rootOwnerApprovalForExternalExport: true,
    notifyUserAboutInternalReport: false,
    updatedBy: "system",
    updatedAt: new Date().toISOString(),
  };
}

function defaultMessengerSafetyControlState(): AdminMessengerSafetyControlState {
  return { reports: [], caseReviews: [], authorityRequests: [], aiSignals: [], evidenceVault: [], restrictions: [], guardEventLog: [], escalations: [], retentionLegalHolds: [], exportVerifications: [], accessControlChecks: [], staffAssignments: [], incidentResponses: [], emergencyActions: [], recoveryReviews: [], policyFeedbackItems: [], policyRegistry: [], policyDeployments: [], policyTrainingAcknowledgements: [], settings: defaultMessengerSafetySettings(), updatedAt: new Date().toISOString() };
}

function normalizeMessengerSafetyRestrictionScope(value: unknown, fallback: AdminMessengerSafetyRestrictionScope = "target_safety_hold"): AdminMessengerSafetyRestrictionScope {
  const allowed: AdminMessengerSafetyRestrictionScope[] = ["user_messaging_lock", "chat_freeze", "message_visibility_hold", "group_restriction", "channel_restriction", "bot_restriction", "evidence_preservation_lock", "target_safety_hold"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerSafetyRestrictionScope) ? value as AdminMessengerSafetyRestrictionScope : fallback;
}

function normalizeMessengerSafetyRestrictionStatus(value: unknown, fallback: AdminMessengerSafetyRestrictionStatus = "pending_owner_decision"): AdminMessengerSafetyRestrictionStatus {
  const allowed: AdminMessengerSafetyRestrictionStatus[] = ["pending_owner_decision", "active", "released", "rejected", "expired"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerSafetyRestrictionStatus) ? value as AdminMessengerSafetyRestrictionStatus : fallback;
}

function buildMessengerSafetyRestrictionChecklist(restriction: Pick<AdminMessengerSafetyRestriction, "targetId" | "legalBasis" | "linkedReportIds" | "linkedCaseIds" | "linkedEvidenceIds" | "ownerApprovalRequired" | "ownerApprovedBy" | "timeline">): AdminMessengerSafetyRestriction["checklist"] {
  return {
    targetIdentified: Boolean(restriction.targetId),
    legalBasisProvided: Boolean(restriction.legalBasis),
    evidenceLinked: Boolean((restriction.linkedEvidenceIds ?? []).length),
    reportOrCaseLinked: Boolean((restriction.linkedReportIds ?? []).length || (restriction.linkedCaseIds ?? []).length),
    ownerApproved: !restriction.ownerApprovalRequired || Boolean(restriction.ownerApprovedBy),
    auditWritten: Boolean((restriction.timeline ?? []).length),
    userNotNotified: true,
    rawContentHidden: true,
  };
}

function normalizeMessengerSafetyRestrictionItem(value: unknown): AdminMessengerSafetyRestriction | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  const targetId = readString(source.targetId);
  if (!id || !targetId) return null;
  const now = new Date().toISOString();
  const createdAt = readString(source.createdAt) ?? now;
  const status = normalizeMessengerSafetyRestrictionStatus(source.status);
  const ownerApprovalRequired = readBoolean(source.ownerApprovalRequired, true);
  const restriction: AdminMessengerSafetyRestriction = {
    id,
    scope: normalizeMessengerSafetyRestrictionScope(source.scope),
    status,
    category: normalizeMessengerSafetyCategory(source.category),
    severity: source.severity === "critical" ? "critical" : "high",
    targetType: readString(source.targetType) ?? "target",
    targetId,
    relatedUserId: readString(source.relatedUserId),
    relatedChatId: readString(source.relatedChatId),
    relatedMessageId: readString(source.relatedMessageId),
    linkedReportIds: readStringArray(source.linkedReportIds),
    linkedCaseIds: readStringArray(source.linkedCaseIds),
    linkedAiSignalIds: readStringArray(source.linkedAiSignalIds),
    linkedEvidenceIds: readStringArray(source.linkedEvidenceIds),
    reason: readString(source.reason) ?? "messenger_safety_restriction",
    legalBasis: readString(source.legalBasis) ?? "internal_safety_review",
    ownerApprovalRequired,
    ownerApprovedBy: readString(source.ownerApprovedBy),
    ownerApprovedAt: readString(source.ownerApprovedAt),
    activeFrom: readString(source.activeFrom),
    expiresAt: readString(source.expiresAt),
    releasedBy: readString(source.releasedBy),
    releasedAt: readString(source.releasedAt),
    releaseReason: readString(source.releaseReason),
    rejectedBy: readString(source.rejectedBy),
    rejectedAt: readString(source.rejectedAt),
    rejectionReason: readString(source.rejectionReason),
    enforcementRef: readString(source.enforcementRef),
    checklist: { targetIdentified: true, legalBasisProvided: true, evidenceLinked: false, reportOrCaseLinked: false, ownerApproved: false, auditWritten: false, userNotNotified: true, rawContentHidden: true },
    timeline: Array.isArray(source.timeline) ? source.timeline.filter((item): item is { event: string; by: string; at: string; note?: string; metadata?: Record<string, unknown> } => Boolean(item && typeof item === "object" && typeof (item as Record<string, unknown>).event === "string" && typeof (item as Record<string, unknown>).by === "string" && typeof (item as Record<string, unknown>).at === "string")) : [],
    metadata: source.metadata && typeof source.metadata === "object" ? source.metadata as Record<string, unknown> : undefined,
    createdBy: readString(source.createdBy) ?? "system",
    createdAt,
    updatedBy: readString(source.updatedBy) ?? readString(source.createdBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? createdAt,
  };
  return { ...restriction, checklist: buildMessengerSafetyRestrictionChecklist(restriction) };
}

function createMessengerSafetyRestriction(state: AdminMessengerSafetyControlState, input: {
  scope?: unknown;
  status?: unknown;
  category?: unknown;
  severity?: unknown;
  targetType?: unknown;
  targetId?: unknown;
  relatedUserId?: unknown;
  relatedChatId?: unknown;
  relatedMessageId?: unknown;
  linkedReportIds?: unknown;
  linkedCaseIds?: unknown;
  linkedAiSignalIds?: unknown;
  linkedEvidenceIds?: unknown;
  reason?: unknown;
  legalBasis?: unknown;
  expiresAt?: unknown;
  metadata?: unknown;
}, by: string, event = "restriction_created"): AdminMessengerSafetyRestriction | null {
  const targetId = readString(input.targetId);
  if (!targetId) return null;
  const now = new Date().toISOString();
  const category = normalizeMessengerSafetyCategory(input.category);
  const normalizedStatus = normalizeMessengerSafetyRestrictionStatus(input.status, "pending_owner_decision");
  const restriction: AdminMessengerSafetyRestriction = {
    id: createAdminLocalId("msg_rst"),
    scope: normalizeMessengerSafetyRestrictionScope(input.scope),
    status: normalizedStatus,
    category,
    severity: input.severity === "critical" ? "critical" : messengerSafetyCategorySeverity(category),
    targetType: readString(input.targetType) ?? "target",
    targetId,
    relatedUserId: readString(input.relatedUserId),
    relatedChatId: readString(input.relatedChatId),
    relatedMessageId: readString(input.relatedMessageId),
    linkedReportIds: readStringArray(input.linkedReportIds),
    linkedCaseIds: readStringArray(input.linkedCaseIds),
    linkedAiSignalIds: readStringArray(input.linkedAiSignalIds),
    linkedEvidenceIds: readStringArray(input.linkedEvidenceIds),
    reason: readString(input.reason) ?? category,
    legalBasis: readString(input.legalBasis) ?? "internal_safety_review",
    ownerApprovalRequired: true,
    expiresAt: readString(input.expiresAt),
    enforcementRef: normalizedStatus === "active" ? createAdminLocalId("msg_enf") : undefined,
    checklist: { targetIdentified: true, legalBasisProvided: true, evidenceLinked: false, reportOrCaseLinked: false, ownerApproved: false, auditWritten: true, userNotNotified: true, rawContentHidden: true },
    timeline: [{ event, by, at: now, note: readString(input.reason), metadata: { source: "messenger_safety_restriction_center" } }],
    metadata: input.metadata && typeof input.metadata === "object" ? input.metadata as Record<string, unknown> : undefined,
    createdBy: by,
    createdAt: now,
    updatedBy: by,
    updatedAt: now,
  };
  return { ...restriction, checklist: buildMessengerSafetyRestrictionChecklist(restriction) };
}

function refreshMessengerSafetyRestriction(restriction: AdminMessengerSafetyRestriction): AdminMessengerSafetyRestriction {
  const expired = restriction.status === "active" && restriction.expiresAt && Number.isFinite(Date.parse(restriction.expiresAt)) && Date.parse(restriction.expiresAt) <= Date.now();
  const next = expired ? { ...restriction, status: "expired" as const, updatedAt: new Date().toISOString(), updatedBy: "system" } : restriction;
  return { ...next, checklist: buildMessengerSafetyRestrictionChecklist(next) };
}

function applyMessengerSafetyRestrictionStatus(state: AdminMessengerSafetyControlState, id: string, status: AdminMessengerSafetyRestrictionStatus, by: string, note?: string): { state: AdminMessengerSafetyControlState; restriction?: AdminMessengerSafetyRestriction } {
  const now = new Date().toISOString();
  let changed: AdminMessengerSafetyRestriction | undefined;
  const restrictions = state.restrictions.map((item) => {
    if (item.id !== id) return item;
    let next: AdminMessengerSafetyRestriction = { ...item, status, updatedBy: by, updatedAt: now, timeline: [{ event: `restriction_status:${status}`, by, at: now, note }, ...(item.timeline ?? [])] };
    if (status === "active") next = { ...next, ownerApprovedBy: by, ownerApprovedAt: now, activeFrom: item.activeFrom ?? now, enforcementRef: item.enforcementRef ?? createAdminLocalId("msg_enf") };
    if (status === "released") next = { ...next, releasedBy: by, releasedAt: now, releaseReason: note };
    if (status === "rejected") next = { ...next, rejectedBy: by, rejectedAt: now, rejectionReason: note };
    changed = refreshMessengerSafetyRestriction(next);
    return changed;
  });
  return { state: { ...state, restrictions }, restriction: changed };
}

function normalizeMessengerSafetyEnforcementAction(value: unknown): AdminMessengerSafetyEnforcementAction {
  const allowed: AdminMessengerSafetyEnforcementAction[] = ["send_message", "edit_message", "delete_message", "forward_message", "upload_media", "view_message", "join_group", "post_group", "join_channel", "post_channel", "start_bot", "message_bot", "any_messenger_action"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerSafetyEnforcementAction) ? value as AdminMessengerSafetyEnforcementAction : "any_messenger_action";
}

function enforcementActionsForMessengerSafetyScope(scope: AdminMessengerSafetyRestrictionScope): AdminMessengerSafetyEnforcementAction[] {
  if (scope === "user_messaging_lock") return ["send_message", "edit_message", "delete_message", "forward_message", "upload_media", "message_bot", "post_group", "post_channel"];
  if (scope === "chat_freeze") return ["send_message", "edit_message", "delete_message", "forward_message", "upload_media"];
  if (scope === "message_visibility_hold") return ["view_message", "edit_message", "delete_message", "forward_message"];
  if (scope === "group_restriction") return ["join_group", "post_group", "send_message", "upload_media"];
  if (scope === "channel_restriction") return ["join_channel", "post_channel", "send_message", "upload_media"];
  if (scope === "bot_restriction") return ["start_bot", "message_bot"];
  if (scope === "evidence_preservation_lock") return ["edit_message", "delete_message", "forward_message", "view_message"];
  return ["any_messenger_action"];
}

function enforcementDecisionForMessengerSafetyScope(scope: AdminMessengerSafetyRestrictionScope): AdminMessengerSafetyEnforcementDecision {
  if (scope === "message_visibility_hold" || scope === "evidence_preservation_lock") return "hold_for_review";
  return "deny";
}

function isMessengerSafetyRestrictionActiveForEnforcement(restriction: AdminMessengerSafetyRestriction): boolean {
  const item = refreshMessengerSafetyRestriction(restriction);
  if (item.status !== "active") return false;
  if (item.ownerApprovalRequired && !item.ownerApprovedBy) return false;
  if (!item.targetId) return false;
  return true;
}

function buildMessengerSafetyEnforcementRule(restriction: AdminMessengerSafetyRestriction): AdminMessengerSafetyEnforcementRule {
  const refreshed = refreshMessengerSafetyRestriction(restriction);
  const enforcementRef = refreshed.enforcementRef ?? `msg_enf_virtual_${refreshed.id}`;
  return {
    id: `${enforcementRef}:${refreshed.id}`,
    restrictionId: refreshed.id,
    enforcementRef,
    scope: refreshed.scope,
    decision: enforcementDecisionForMessengerSafetyScope(refreshed.scope),
    actions: enforcementActionsForMessengerSafetyScope(refreshed.scope),
    targetType: refreshed.targetType,
    targetId: refreshed.targetId,
    relatedUserId: refreshed.relatedUserId,
    relatedChatId: refreshed.relatedChatId,
    relatedMessageId: refreshed.relatedMessageId,
    category: refreshed.category,
    severity: refreshed.severity,
    reason: refreshed.reason,
    legalBasis: refreshed.legalBasis,
    activeFrom: refreshed.activeFrom,
    expiresAt: refreshed.expiresAt,
    linkedReportIds: refreshed.linkedReportIds,
    linkedCaseIds: refreshed.linkedCaseIds,
    linkedAiSignalIds: refreshed.linkedAiSignalIds,
    linkedEvidenceIds: refreshed.linkedEvidenceIds,
    integrity: {
      ownerApproved: !refreshed.ownerApprovalRequired || Boolean(refreshed.ownerApprovedBy),
      evidenceLinked: Boolean(refreshed.linkedEvidenceIds.length),
      auditLinked: Boolean(refreshed.timeline.length),
      rawContentHidden: true,
      userNotNotified: true,
    },
  };
}

function buildMessengerSafetyEnforcementRules(state: AdminMessengerSafetyControlState): AdminMessengerSafetyEnforcementRule[] {
  return state.restrictions.filter(isMessengerSafetyRestrictionActiveForEnforcement).map(buildMessengerSafetyEnforcementRule);
}

function buildMessengerSafetyEnforcementPolicy(): string[] {
  return [
    "runtime_enforcement_uses_active_owner_approved_restrictions_only",
    "messenger_runtime_checks_user_chat_message_group_channel_bot_ids_before_sensitive_actions",
    "raw_message_body_must_not_be_sent_to_admin_enforcement_check",
    "deny_or_hold_result_must_be_respected_before_message_send_or_visibility_change",
    "all_enforcement_snapshots_and_checks_are_audited",
  ];
}

function buildMessengerSafetyEnforcementSnapshot(req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyEnforcementSnapshot {
  const state = readMessengerSafetyControlState();
  const refreshedRestrictions = state.restrictions.map(refreshMessengerSafetyRestriction);
  const rules = buildMessengerSafetyEnforcementRules({ ...state, restrictions: refreshedRestrictions });
  const expiredIgnored = refreshedRestrictions.filter((item) => item.status === "expired").length;
  const auditIntegrity = store.verifyAuditIntegrity();
  return {
    ok: true,
    policyVersion: "messenger-safety-enforcement-v1",
    generatedAt: new Date().toISOString(),
    generatedBy: req?.admin?.id ?? "system",
    summary: {
      activeRules: rules.length,
      denyRules: rules.filter((item) => item.decision === "deny").length,
      holdRules: rules.filter((item) => item.decision === "hold_for_review").length,
      userLocks: rules.filter((item) => item.scope === "user_messaging_lock").length,
      chatFreezes: rules.filter((item) => item.scope === "chat_freeze").length,
      messageHolds: rules.filter((item) => item.scope === "message_visibility_hold" || item.scope === "evidence_preservation_lock").length,
      groupRestrictions: rules.filter((item) => item.scope === "group_restriction").length,
      channelRestrictions: rules.filter((item) => item.scope === "channel_restriction").length,
      botRestrictions: rules.filter((item) => item.scope === "bot_restriction").length,
      expiredIgnored,
    },
    rules,
    vaultIntegrity: verifyMessengerEvidenceVaultIntegrity(state.evidenceVault),
    auditIntegrity,
    auditAnchorHash: auditIntegrity.anchorHash,
    integrationContract: {
      endpoint: "/api/admin/messenger/safety/enforcement/check",
      requiredInputs: ["action", "userId", "chatId", "messageId", "targetType", "targetId"],
      responseRule: "deny_or_hold_when_any_active_rule_matches",
      rawContentPolicy: "do_not_send_raw_message_body_to_admin_enforcement",
    },
    policy: buildMessengerSafetyEnforcementPolicy(),
  };
}

function messengerSafetyEnforcementRuleMatches(rule: AdminMessengerSafetyEnforcementRule, input: AdminMessengerSafetyEnforcementCheckInput): boolean {
  const action = normalizeMessengerSafetyEnforcementAction(input.action);
  if (!rule.actions.includes("any_messenger_action") && action !== "any_messenger_action" && !rule.actions.includes(action)) return false;
  const targetCandidates = new Set<string>([
    readString(input.targetId),
    readString(input.userId),
    readString(input.chatId),
    readString(input.messageId),
    readString(input.groupId),
    readString(input.channelId),
    readString(input.botId),
  ].filter((item): item is string => Boolean(item)));
  if (targetCandidates.has(rule.targetId)) return true;
  if (rule.relatedUserId && targetCandidates.has(rule.relatedUserId)) return true;
  if (rule.relatedChatId && targetCandidates.has(rule.relatedChatId)) return true;
  if (rule.relatedMessageId && targetCandidates.has(rule.relatedMessageId)) return true;
  if (rule.scope === "user_messaging_lock" && input.userId && rule.targetId === input.userId) return true;
  if (rule.scope === "chat_freeze" && input.chatId && rule.targetId === input.chatId) return true;
  if ((rule.scope === "message_visibility_hold" || rule.scope === "evidence_preservation_lock") && input.messageId && rule.targetId === input.messageId) return true;
  if (rule.scope === "group_restriction" && input.groupId && rule.targetId === input.groupId) return true;
  if (rule.scope === "channel_restriction" && input.channelId && rule.targetId === input.channelId) return true;
  if (rule.scope === "bot_restriction" && input.botId && rule.targetId === input.botId) return true;
  return false;
}

function checkMessengerSafetyEnforcement(input: AdminMessengerSafetyEnforcementCheckInput, req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyEnforcementCheckResult {
  const snapshot = buildMessengerSafetyEnforcementSnapshot(req, store);
  const matchedRules = snapshot.rules.filter((rule) => messengerSafetyEnforcementRuleMatches(rule, input));
  const deny = matchedRules.some((rule) => rule.decision === "deny");
  const hold = matchedRules.some((rule) => rule.decision === "hold_for_review");
  const decision: AdminMessengerSafetyEnforcementDecision = deny ? "deny" : hold ? "hold_for_review" : "allow";
  return {
    ok: true,
    allowed: decision === "allow",
    decision,
    action: normalizeMessengerSafetyEnforcementAction(input.action),
    matchedRules,
    reason: matchedRules[0]?.reason,
    checkedAt: new Date().toISOString(),
    policyVersion: "messenger-safety-enforcement-v1",
    rawContentHidden: true,
    userNotNotified: true,
  };
}

function buildMessengerSafetyRuntimeBridgeGuardedActions(): AdminMessengerSafetyRuntimeGuardedAction[] {
  return [
    { key: "chat.send_message", layer: "chat_room", messengerEvent: "messenger.chat.message.send.before", enforcementAction: "send_message", requiredIds: ["actorUserId", "chatId", "clientMessageId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "chat.edit_message", layer: "chat_room", messengerEvent: "messenger.chat.message.edit.before", enforcementAction: "edit_message", requiredIds: ["actorUserId", "chatId", "messageId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "chat.delete_message", layer: "chat_room", messengerEvent: "messenger.chat.message.delete.before", enforcementAction: "delete_message", requiredIds: ["actorUserId", "chatId", "messageId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "chat.forward_message", layer: "chat_room", messengerEvent: "messenger.chat.message.forward.before", enforcementAction: "forward_message", requiredIds: ["actorUserId", "chatId", "messageId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "media.upload", layer: "media", messengerEvent: "messenger.media.upload.before", enforcementAction: "upload_media", requiredIds: ["actorUserId", "chatId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "message.view", layer: "message_visibility", messengerEvent: "messenger.chat.message.view.before", enforcementAction: "view_message", requiredIds: ["actorUserId", "chatId", "messageId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "group.join", layer: "groups", messengerEvent: "messenger.group.join.before", enforcementAction: "join_group", requiredIds: ["actorUserId", "groupId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "group.post", layer: "groups", messengerEvent: "messenger.group.post.before", enforcementAction: "post_group", requiredIds: ["actorUserId", "groupId", "chatId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "channel.join", layer: "channels", messengerEvent: "messenger.channel.join.before", enforcementAction: "join_channel", requiredIds: ["actorUserId", "channelId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "channel.post", layer: "channels", messengerEvent: "messenger.channel.post.before", enforcementAction: "post_channel", requiredIds: ["actorUserId", "channelId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "bot.start", layer: "bots", messengerEvent: "messenger.bot.start.before", enforcementAction: "start_bot", requiredIds: ["actorUserId", "botId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
    { key: "bot.message", layer: "bots", messengerEvent: "messenger.bot.message.before", enforcementAction: "message_bot", requiredIds: ["actorUserId", "botId", "chatId"], enabled: true, decisionPolicy: "deny_blocks_immediately_hold_requires_review_allow_continues", rawContentPolicy: "ids_and_hashes_only" },
  ];
}

function normalizeMessengerSafetyRuntimeAction(value: unknown): AdminMessengerSafetyRuntimeGuardedAction {
  const fallback = buildMessengerSafetyRuntimeBridgeGuardedActions()[0];
  const key = readString(value);
  return buildMessengerSafetyRuntimeBridgeGuardedActions().find((item) => item.key === key || item.enforcementAction === key) ?? fallback;
}

function buildMessengerSafetyRuntimeBridgePolicy(): string[] {
  return [
    "runtime_bridge_must_be_called_before_message_group_channel_bot_actions",
    "messenger_runtime_bridge_accepts_ids_hashes_and_context_only",
    "raw_message_text_media_and_files_must_never_be_sent_to_admin_runtime_bridge",
    "deny_blocks_action_and_hold_for_review_pauses_visibility_or_send_flow",
    "all_runtime_bridge_checks_are_audited_for_security_service_traceability",
  ];
}

function buildMessengerSafetyRuntimeBridgeSnapshot(req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyRuntimeBridgeSnapshot {
  const guardedActions = buildMessengerSafetyRuntimeBridgeGuardedActions();
  const enforcementSnapshot = buildMessengerSafetyEnforcementSnapshot(req, store);
  const enabledGuardedActions = guardedActions.filter((item) => item.enabled).length;
  return {
    ok: true,
    bridgeVersion: "messenger-safety-runtime-bridge-v1",
    generatedAt: new Date().toISOString(),
    generatedBy: req?.admin?.id ?? "system",
    mode: "enforce",
    summary: {
      guardedActions: guardedActions.length,
      enabledGuardedActions,
      activeRules: enforcementSnapshot.summary.activeRules,
      denyRules: enforcementSnapshot.summary.denyRules,
      holdRules: enforcementSnapshot.summary.holdRules,
      rawContentAllowed: false,
      messengerRuntimeReady: enabledGuardedActions > 0,
    },
    guardedActions,
    enforcementSnapshot,
    runtimeContract: {
      checkEndpoint: "/api/admin/messenger/safety/runtime-bridge/check",
      snapshotEndpoint: "/api/admin/messenger/safety/runtime-bridge/snapshot",
      method: "POST",
      authentication: "admin_or_internal_service_token_required",
      inputPolicy: "send_only_ids_hashes_and_action_context",
      rawContentPolicy: "never_send_raw_message_text_media_or_files",
      responsePolicy: "messenger_must_block_deny_and_hold_for_review_before_action_executes",
    },
    policy: buildMessengerSafetyRuntimeBridgePolicy(),
  };
}

function checkMessengerSafetyRuntimeBridge(input: AdminMessengerSafetyRuntimeBridgeCheckInput, req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyRuntimeBridgeCheckResult {
  const guarded = normalizeMessengerSafetyRuntimeAction(input.runtimeAction ?? input.action);
  const rawContentPresent = readBoolean(input.rawContentPresent, false);
  const enforcementInput: AdminMessengerSafetyEnforcementCheckInput = {
    action: guarded.enforcementAction,
    targetType: input.targetType,
    targetId: input.targetId,
    userId: input.userId ?? input.actorUserId,
    chatId: input.chatId ?? input.conversationId,
    messageId: input.messageId,
    groupId: input.groupId,
    channelId: input.channelId,
    botId: input.botId,
  };
  const enforcement = checkMessengerSafetyEnforcement(enforcementInput, req, store);
  const decision: AdminMessengerSafetyEnforcementDecision = rawContentPresent ? "hold_for_review" : enforcement.decision;
  const mustBlock = decision === "deny";
  const mustHoldForReview = decision === "hold_for_review";
  return {
    ok: true,
    allowed: decision === "allow",
    mustBlock,
    mustHoldForReview,
    decision,
    runtimeAction: guarded.key,
    enforcementAction: guarded.enforcementAction,
    matchedRules: enforcement.matchedRules,
    messengerInstruction: mustBlock ? "block_action" : mustHoldForReview ? "hold_for_safety_review" : "continue",
    checkedAt: new Date().toISOString(),
    bridgeVersion: "messenger-safety-runtime-bridge-v1",
    rawContentHidden: true,
    userNotNotified: true,
    requiredClientBehavior: [
      "do_not_notify_target_about_internal_safety_review",
      "do_not_send_raw_message_body_to_admin_runtime_bridge",
      "respect_deny_or_hold_before_committing_message_or_visibility_change",
      rawContentPresent ? "raw_content_detected_hold_for_review" : "ids_only_check_completed",
    ],
  };
}


function toMessengerSafetyGuardFunctionName(key: string): string {
  return `guard${key.split(/[._-]/g).filter(Boolean).map((part) => part.slice(0, 1).toUpperCase() + part.slice(1)).join("")}`;
}

function buildMessengerSafetyClientGuards(): AdminMessengerSafetyClientGuard[] {
  const runtimeActions = buildMessengerSafetyRuntimeBridgeGuardedActions();
  const platforms: AdminMessengerSafetyClientGuardPlatform[] = ["mobile", "web", "backend", "socket_gateway"];
  return runtimeActions.flatMap((action) => platforms.map((platform) => ({
    key: `${platform}.${action.key}`,
    platform,
    layer: action.layer,
    runtimeAction: action.key,
    enforcementAction: action.enforcementAction,
    guardFunction: platform === "socket_gateway" ? `${toMessengerSafetyGuardFunctionName(action.key)}SocketGate` : toMessengerSafetyGuardFunctionName(action.key),
    beforeEvent: action.messengerEvent,
    requiredIds: action.requiredIds,
    optionalIds: ["peerUserId", "targetType", "targetId", "messageHash", "attachmentHash", "evidenceHash"],
    bridgeEndpoint: "/api/admin/messenger/safety/runtime-bridge/check",
    enabled: true,
    successBehavior: "continue_action",
    denyBehavior: "block_locally_before_commit",
    holdBehavior: "pause_send_or_visibility_and_mark_pending_review",
    userMessageKey: "messenger.safetyActionUnavailable",
    rawContentPolicy: "never_forward_raw_message_text_media_or_files",
    auditPolicy: "server_side_runtime_bridge_audits_every_check",
  })));
}

function buildMessengerSafetyClientGuardsPolicy(): string[] {
  return [
    "client_guards_must_run_before_message_commit_upload_visibility_group_channel_or_bot_action",
    "client_guards_send_only_ids_hashes_and_runtime_action_context",
    "client_guards_must_not_show_internal_reason_or_authority_status_to_target_user",
    "deny_result_blocks_locally_before_database_or_socket_commit",
    "hold_result_pauses_send_or_visibility_flow_for_admin_review",
    "socket_gateway_guard_rechecks_server_side_even_if_mobile_guard_passed",
  ];
}

function buildMessengerSafetyClientGuardAdapterTemplate(): string[] {
  return [
    "export type MessengerSafetyGuardDecision = 'continue' | 'block_action' | 'hold_for_safety_review';",
    "export type MessengerSafetyGuardPayload = { runtimeAction: string; actorUserId?: string; peerUserId?: string; chatId?: string; messageId?: string; clientMessageId?: string; groupId?: string; channelId?: string; botId?: string; targetType?: string; targetId?: string; messageHash?: string; attachmentHash?: string; rawContentPresent?: false; };",
    "export async function guardMessengerSafetyAction(payload: MessengerSafetyGuardPayload): Promise<MessengerSafetyGuardDecision> {",
    "  // Send IDs/hashes/context only. Never send raw message text, media bytes, files, captions, or decrypted content.",
    "  // Call POST /api/admin/messenger/safety/runtime-bridge/check before local commit, socket emit, upload, visibility change, group/channel/bot action.",
    "  // continue => execute action; block_action => stop locally with generic user message; hold_for_safety_review => pause and mark pending review.",
    "  return 'continue';",
    "}",
  ];
}

function normalizeMessengerSafetyClientGuard(value: unknown, platform?: unknown): AdminMessengerSafetyClientGuard | undefined {
  const key = readString(value);
  const normalizedPlatform = readString(platform);
  const guards = buildMessengerSafetyClientGuards();
  return guards.find((item) => item.key === key)
    ?? guards.find((item) => item.runtimeAction === key && (!normalizedPlatform || item.platform === normalizedPlatform))
    ?? guards.find((item) => item.enforcementAction === key && (!normalizedPlatform || item.platform === normalizedPlatform));
}

function readMessengerSafetyClientGuardInputId(input: AdminMessengerSafetyClientGuardValidationInput, idKey: string): string | undefined {
  const record = input as unknown as Record<string, unknown>;
  if (idKey === "actorUserId") return readString(record.actorUserId) ?? readString(record.userId);
  if (idKey === "chatId") return readString(record.chatId) ?? readString(record.conversationId);
  return readString(record[idKey]);
}

function buildMessengerSafetyClientGuardsSnapshot(req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyClientGuardsSnapshot {
  const guards = buildMessengerSafetyClientGuards();
  const runtimeBridge = buildMessengerSafetyRuntimeBridgeSnapshot(req, store);
  return {
    ok: true,
    guardVersion: "messenger-safety-client-guards-v1",
    generatedAt: new Date().toISOString(),
    generatedBy: req?.admin?.id ?? "system",
    summary: {
      totalGuards: guards.length,
      enabledGuards: guards.filter((item) => item.enabled).length,
      mobileGuards: guards.filter((item) => item.platform === "mobile").length,
      webGuards: guards.filter((item) => item.platform === "web").length,
      backendGuards: guards.filter((item) => item.platform === "backend").length,
      socketGatewayGuards: guards.filter((item) => item.platform === "socket_gateway").length,
      activeRuntimeRules: runtimeBridge.summary.activeRules,
      rawContentAllowed: false,
      messengerClientReady: guards.some((item) => item.platform === "mobile" && item.enabled) && guards.some((item) => item.platform === "socket_gateway" && item.enabled),
    },
    guards,
    runtimeBridge,
    implementationContract: {
      bridgeEndpoint: "/api/admin/messenger/safety/runtime-bridge/check",
      method: "POST",
      mustRunBefore: Array.from(new Set(guards.map((item) => item.beforeEvent))),
      inputPolicy: "ids_hashes_and_action_context_only",
      rawContentPolicy: "never_send_raw_message_text_media_or_files",
      responsePolicy: "block_deny_hold_review_allow_continue",
      suggestedMobileAdapter: "src/core/kernel/messenger/safety/messengerSafetyRuntimeGuard.ts",
      suggestedSocketGatewayGuard: "src/core/kernel/messenger/safety/messengerSafetySocketGuard.ts",
    },
    adapterTemplate: buildMessengerSafetyClientGuardAdapterTemplate(),
    policy: buildMessengerSafetyClientGuardsPolicy(),
  };
}

function validateMessengerSafetyClientGuard(input: AdminMessengerSafetyClientGuardValidationInput, req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyClientGuardValidationResult {
  const guard = normalizeMessengerSafetyClientGuard(input.guardKey ?? input.runtimeAction ?? input.action, input.platform);
  const fallbackRuntimeAction = guard?.runtimeAction ?? readString(input.runtimeAction) ?? readString(input.action) ?? "chat.send_message";
  const missingIds = guard ? guard.requiredIds.filter((key) => !readMessengerSafetyClientGuardInputId(input, key)) : [];
  const runtimeCheck = checkMessengerSafetyRuntimeBridge({
    ...input,
    runtimeAction: fallbackRuntimeAction,
    action: guard?.enforcementAction ?? input.action,
  }, req, store);
  const rawContentPresent = readBoolean(input.rawContentPresent, false);
  const ready = Boolean(guard?.enabled) && missingIds.length === 0 && !rawContentPresent && runtimeCheck.ok;
  return {
    ok: true,
    guardFound: Boolean(guard),
    ready,
    guard,
    missingIds,
    runtimeCheck,
    validationAt: new Date().toISOString(),
    guardVersion: "messenger-safety-client-guards-v1",
    rawContentHidden: true,
    requiredClientBehavior: [
      "call_client_guard_before_action_commit",
      "do_not_send_raw_message_text_media_files_or_decrypted_content",
      "show_only_generic_blocked_or_pending_review_message_to_user",
      "respect_runtime_bridge_decision_before_socket_emit_or_database_write",
      missingIds.length ? "provide_missing_required_ids_before_live_integration" : "required_ids_present",
      rawContentPresent ? "raw_content_detected_guard_not_ready" : "ids_only_payload_ok",
    ],
  };
}

function normalizeMessengerSafetyGuardEventSource(value: unknown): AdminMessengerSafetyGuardEventSource {
  if (value === "enforcement_check" || value === "runtime_bridge_check" || value === "client_guard_validate" || value === "socket_gateway_guard" || value === "manual_probe") return value;
  return "manual_probe";
}

function normalizeMessengerSafetyGuardEvent(value: unknown): AdminMessengerSafetyGuardEvent | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  if (!id) return null;
  const checkedAt = readString(source.checkedAt) ?? new Date().toISOString();
  const previousTraceHash = typeof source.previousTraceHash === "string" ? source.previousTraceHash : null;
  const draft = {
    id,
    source: normalizeMessengerSafetyGuardEventSource(source.source),
    platform: readString(source.platform),
    guardKey: readString(source.guardKey),
    runtimeAction: readString(source.runtimeAction),
    enforcementAction: readString(source.enforcementAction),
    decision: source.decision === "deny" || source.decision === "hold_for_review" ? source.decision : "allow" as AdminMessengerSafetyEnforcementDecision,
    messengerInstruction: readString(source.messengerInstruction),
    allowed: readBoolean(source.allowed, source.decision === "allow"),
    ready: typeof source.ready === "boolean" ? source.ready : undefined,
    guardFound: typeof source.guardFound === "boolean" ? source.guardFound : undefined,
    missingIds: readStringArray(source.missingIds),
    actorUserId: readString(source.actorUserId),
    userId: readString(source.userId),
    peerUserId: readString(source.peerUserId),
    chatId: readString(source.chatId),
    conversationId: readString(source.conversationId),
    messageId: readString(source.messageId),
    clientMessageId: readString(source.clientMessageId),
    groupId: readString(source.groupId),
    channelId: readString(source.channelId),
    botId: readString(source.botId),
    targetType: readString(source.targetType),
    targetId: readString(source.targetId),
    requestId: readString(source.requestId),
    runtimeSource: readString(source.runtimeSource),
    matchedRuleIds: readStringArray(source.matchedRuleIds),
    matchedRestrictionIds: readStringArray(source.matchedRestrictionIds),
    rawContentPresent: readBoolean(source.rawContentPresent, false),
    rawContentHidden: true as const,
    userNotNotified: true as const,
    previousTraceHash,
    traceVersion: "sha256-guard-event-v1" as const,
    metadata: source.metadata && typeof source.metadata === "object" ? source.metadata as Record<string, unknown> : undefined,
    checkedBy: readString(source.checkedBy) ?? "system",
    checkedAt,
  };
  return { ...draft, traceHash: readString(source.traceHash) ?? sha256Text(draft) };
}

function buildMessengerSafetyGuardEvent(input: Partial<AdminMessengerSafetyGuardEvent>, previousTraceHash: string | null, by: string): AdminMessengerSafetyGuardEvent {
  const now = new Date().toISOString();
  const matchedRuleIds = readStringArray(input.matchedRuleIds);
  const matchedRestrictionIds = readStringArray(input.matchedRestrictionIds);
  const decision: AdminMessengerSafetyEnforcementDecision = input.decision === "deny" || input.decision === "hold_for_review" ? input.decision : "allow";
  const draft = {
    id: createAdminLocalId("msg_guard_evt"),
    source: normalizeMessengerSafetyGuardEventSource(input.source),
    platform: input.platform,
    guardKey: input.guardKey,
    runtimeAction: input.runtimeAction,
    enforcementAction: input.enforcementAction,
    decision,
    messengerInstruction: input.messengerInstruction,
    allowed: decision === "allow" && input.allowed !== false,
    ready: input.ready,
    guardFound: input.guardFound,
    missingIds: readStringArray(input.missingIds),
    actorUserId: input.actorUserId,
    userId: input.userId,
    peerUserId: input.peerUserId,
    chatId: input.chatId,
    conversationId: input.conversationId,
    messageId: input.messageId,
    clientMessageId: input.clientMessageId,
    groupId: input.groupId,
    channelId: input.channelId,
    botId: input.botId,
    targetType: input.targetType,
    targetId: input.targetId,
    requestId: input.requestId,
    runtimeSource: input.runtimeSource,
    matchedRuleIds,
    matchedRestrictionIds,
    rawContentPresent: Boolean(input.rawContentPresent),
    rawContentHidden: true as const,
    userNotNotified: true as const,
    previousTraceHash,
    traceVersion: "sha256-guard-event-v1" as const,
    metadata: input.metadata,
    checkedBy: by,
    checkedAt: now,
  };
  return { ...draft, traceHash: sha256Text(draft) };
}

function appendMessengerSafetyGuardEvent(state: AdminMessengerSafetyControlState, input: Partial<AdminMessengerSafetyGuardEvent>, by: string): { state: AdminMessengerSafetyControlState; event: AdminMessengerSafetyGuardEvent } {
  const previousTraceHash = state.guardEventLog[0]?.traceHash ?? null;
  const event = buildMessengerSafetyGuardEvent(input, previousTraceHash, by);
  return { state: { ...state, guardEventLog: [event, ...state.guardEventLog].slice(0, 1000) }, event };
}

function verifyMessengerSafetyGuardEventLogIntegrity(events: AdminMessengerSafetyGuardEvent[]): AdminMessengerSafetyGuardEventSnapshot["integrity"] {
  for (let index = 0; index < events.length; index += 1) {
    const event = events[index];
    const nextOlder = events[index + 1];
    if ((event.previousTraceHash ?? null) !== (nextOlder?.traceHash ?? null)) {
      return { total: events.length, chainVersion: "sha256-guard-event-v1", anchorHash: events[0]?.traceHash ?? null, brokenAtId: event.id, ok: false };
    }
  }
  return { total: events.length, chainVersion: "sha256-guard-event-v1", anchorHash: events[0]?.traceHash ?? null, ok: true };
}

function buildMessengerSafetyGuardEventPolicy(): string[] {
  return [
    "guard_event_log_records_every_enforcement_runtime_bridge_and_client_guard_decision",
    "guard_events_store_ids_hashes_decisions_missing_ids_and_rule_links_without_raw_content",
    "guard_event_log_is_hash_chained_for_security_service_traceability",
    "raw_content_present_forces_hold_or_not_ready_and_is_recorded_without_storing_content",
    "guard_event_export_requires_root_owner_and_audit_export_permission",
  ];
}

function buildMessengerSafetyGuardEventSnapshot(req: AdminRequest | null, limit = 100): AdminMessengerSafetyGuardEventSnapshot {
  const state = readMessengerSafetyControlState();
  const events = state.guardEventLog.slice(0, Math.max(1, Math.min(limit, 500)));
  const unique = (values: Array<string | undefined>) => new Set(values.filter(Boolean)).size;
  return {
    ok: true,
    eventLogVersion: "messenger-safety-guard-event-log-v1",
    generatedAt: new Date().toISOString(),
    generatedBy: req?.admin?.id ?? "system",
    summary: {
      totalEvents: state.guardEventLog.length,
      denyEvents: state.guardEventLog.filter((item) => item.decision === "deny").length,
      holdEvents: state.guardEventLog.filter((item) => item.decision === "hold_for_review").length,
      allowEvents: state.guardEventLog.filter((item) => item.decision === "allow").length,
      rawContentHeldEvents: state.guardEventLog.filter((item) => item.rawContentPresent).length,
      clientGuardNotReadyEvents: state.guardEventLog.filter((item) => item.source === "client_guard_validate" && item.ready === false).length,
      uniqueUsers: unique(state.guardEventLog.flatMap((item) => [item.actorUserId, item.userId, item.peerUserId])),
      uniqueChats: unique(state.guardEventLog.map((item) => item.chatId ?? item.conversationId)),
      uniqueMessages: unique(state.guardEventLog.map((item) => item.messageId ?? item.clientMessageId)),
      chainAnchorHash: state.guardEventLog[0]?.traceHash ?? null,
    },
    events,
    integrity: verifyMessengerSafetyGuardEventLogIntegrity(state.guardEventLog),
    policy: buildMessengerSafetyGuardEventPolicy(),
  };
}

function buildMessengerSafetyIntegrityMonitorPolicy(): string[] {
  return [
    "integrity_monitor_checks_evidence_vault_guard_events_restrictions_cases_authority_and_audit_chain",
    "broken_hash_chain_or_missing_required_links_must_be_treated_as_critical_before_external_export",
    "legal_hold_evidence_should_be_sealed_by_root_owner_before_authority_package_delivery",
    "active_restrictions_must_have_owner_approval_and_enforcement_reference",
    "integrity_monitor_exports_only_ids_hashes_links_findings_and_audit_anchors_without_raw_content",
  ];
}

function pushMessengerSafetyIntegrityFinding(findings: AdminMessengerSafetyIntegrityFinding[], input: Omit<AdminMessengerSafetyIntegrityFinding, "id" | "status" | "detectedAt">): void {
  const stable = `${input.scope}:${input.severity}:${input.targetType ?? "scope"}:${input.targetId ?? input.title}:${input.description}`;
  findings.push({
    ...input,
    id: `msg_safety_integrity_${sha256Text(stable).slice(0, 18)}`,
    status: "open",
    detectedAt: new Date().toISOString(),
  });
}

function findMissingMessengerSafetyLinks(ids: string[] | undefined, existing: Set<string>): string[] {
  return (ids ?? []).filter((id) => !existing.has(id));
}

function buildMessengerSafetyIntegrityMonitorSnapshot(req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyIntegrityMonitorSnapshot {
  const state = readMessengerSafetyControlState();
  const now = new Date().toISOString();
  const by = req?.admin?.id ?? "system";
  const reports = new Set(state.reports.map((item) => item.id));
  const cases = new Set(state.caseReviews.map((item) => item.id));
  const evidence = new Set(state.evidenceVault.map((item) => item.id));
  const aiSignals = new Set(state.aiSignals.map((item) => item.id));
  const authorityRequests = new Set(state.authorityRequests.map((item) => item.id));
  const restrictions = state.restrictions.map(refreshMessengerSafetyRestriction);
  const restrictionIds = new Set(restrictions.map((item) => item.id));
  const vaultIntegrity = verifyMessengerEvidenceVaultIntegrity(state.evidenceVault);
  const guardIntegrity = verifyMessengerSafetyGuardEventLogIntegrity(state.guardEventLog);
  const auditIntegrity = store.verifyAuditIntegrity();
  const findings: AdminMessengerSafetyIntegrityFinding[] = [];

  if (vaultIntegrity.brokenLinks > 0) {
    pushMessengerSafetyIntegrityFinding(findings, {
      scope: "evidence_vault",
      severity: "critical",
      title: "evidence_vault_chain_broken",
      description: `Evidence vault chain has ${vaultIntegrity.brokenLinks} broken link(s).`,
      targetType: "messenger_safety_evidence_vault",
      targetId: vaultIntegrity.anchorHash ?? "vault",
      remediation: "Stop external export, preserve current file, and require Root Owner/admin review of vault chain before disclosure.",
    });
  }

  if (!guardIntegrity.ok) {
    pushMessengerSafetyIntegrityFinding(findings, {
      scope: "guard_event_log",
      severity: "critical",
      title: "guard_event_chain_broken",
      description: `Guard event hash chain failed at ${guardIntegrity.brokenAtId ?? "unknown"}.`,
      targetType: "messenger_safety_guard_event_log",
      targetId: guardIntegrity.brokenAtId ?? guardIntegrity.anchorHash ?? "guard_events",
      remediation: "Stop relying on guard event export until security/admin review confirms the event log file and audit trail.",
    });
  }

  if (!auditIntegrity.ok) {
    pushMessengerSafetyIntegrityFinding(findings, {
      scope: "audit_log",
      severity: "critical",
      title: "audit_chain_broken",
      description: `Admin audit integrity failed: ${String(auditIntegrity.reason ?? "integrity_failed")}.`,
      targetType: "admin_audit",
      targetId: auditIntegrity.anchorHash ?? "audit",
      remediation: "Root Owner must review audit store before any authority package or compliance export is delivered.",
    });
  }

  for (const item of state.evidenceVault) {
    if (item.legalHold && !item.sealed) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "evidence_vault",
        severity: "warning",
        title: "legal_hold_evidence_not_sealed",
        description: "Evidence is under legal hold but not sealed by Root Owner yet.",
        targetType: "messenger_safety_evidence",
        targetId: item.id,
        linkedReportIds: item.reportId ? [item.reportId] : [],
        linkedEvidenceIds: [item.id],
        remediation: "Seal the evidence with Root Owner note before external export or authority package delivery.",
      });
    }
    if (item.reportId && !reports.has(item.reportId)) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "evidence_vault",
        severity: "warning",
        title: "evidence_report_link_missing",
        description: "Vault evidence references a report ID that is not present in the safety report store.",
        targetType: "messenger_safety_evidence",
        targetId: item.id,
        linkedReportIds: [item.reportId],
        linkedEvidenceIds: [item.id],
        remediation: "Relink evidence to an existing report/case or preserve it as manual/system evidence with a clear note.",
      });
    }
    if (item.aiSignalId && !aiSignals.has(item.aiSignalId)) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "evidence_vault",
        severity: "warning",
        title: "evidence_ai_signal_link_missing",
        description: "Vault evidence references an AI signal ID that is not present in the AI signal store.",
        targetType: "messenger_safety_evidence",
        targetId: item.id,
        linkedEvidenceIds: [item.id],
        remediation: "Relink evidence to the correct AI signal or keep the reference as external hash evidence.",
      });
    }
  }

  for (const item of restrictions) {
    if (item.status === "active" && !item.enforcementRef) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "restrictions",
        severity: "critical",
        title: "active_restriction_without_enforcement_ref",
        description: "Active safety restriction has no enforcement reference for runtime guard checks.",
        targetType: item.targetType,
        targetId: item.targetId,
        linkedRestrictionIds: [item.id],
        linkedReportIds: item.linkedReportIds,
        linkedCaseIds: item.linkedCaseIds,
        linkedEvidenceIds: item.linkedEvidenceIds,
        remediation: "Re-approve or refresh restriction status so enforcementRef is created before runtime use.",
      });
    }
    if (item.status === "active" && item.ownerApprovalRequired && !item.ownerApprovedBy) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "restrictions",
        severity: "critical",
        title: "active_restriction_without_owner_approval",
        description: "Active safety restriction requires Root Owner approval but has no owner approval marker.",
        targetType: item.targetType,
        targetId: item.targetId,
        linkedRestrictionIds: [item.id],
        linkedReportIds: item.linkedReportIds,
        linkedCaseIds: item.linkedCaseIds,
        linkedEvidenceIds: item.linkedEvidenceIds,
        remediation: "Move restriction back to pending_owner_decision or approve through Root Owner flow.",
      });
    }
    const missingEvidence = findMissingMessengerSafetyLinks(item.linkedEvidenceIds, evidence);
    if (missingEvidence.length) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "restrictions",
        severity: "warning",
        title: "restriction_missing_evidence_links",
        description: `Restriction references missing evidence ID(s): ${missingEvidence.join(", ")}.`,
        targetType: item.targetType,
        targetId: item.targetId,
        linkedRestrictionIds: [item.id],
        linkedEvidenceIds: missingEvidence,
        remediation: "Relink restriction to existing vault evidence or preserve a new evidence reference.",
      });
    }
    const missingReports = findMissingMessengerSafetyLinks(item.linkedReportIds, reports);
    const missingCases = findMissingMessengerSafetyLinks(item.linkedCaseIds, cases);
    if (missingReports.length || missingCases.length) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "restrictions",
        severity: "warning",
        title: "restriction_missing_report_or_case_links",
        description: `Restriction references missing report/case links: ${[...missingReports, ...missingCases].join(", ")}.`,
        targetType: item.targetType,
        targetId: item.targetId,
        linkedRestrictionIds: [item.id],
        linkedReportIds: missingReports,
        linkedCaseIds: missingCases,
        remediation: "Relink restriction to an existing safety report or case review before external package export.",
      });
    }
  }

  for (const item of state.caseReviews) {
    const missingEvidence = findMissingMessengerSafetyLinks(item.linkedEvidenceIds, evidence);
    const missingReports = findMissingMessengerSafetyLinks(item.linkedReportIds, reports);
    const missingSignals = findMissingMessengerSafetyLinks(item.linkedAiSignalIds, aiSignals);
    const missingAuthority = findMissingMessengerSafetyLinks(item.linkedAuthorityRequestIds, authorityRequests);
    const missingAll = [...missingEvidence, ...missingReports, ...missingSignals, ...missingAuthority];
    if (missingAll.length) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "case_reviews",
        severity: "warning",
        title: "case_review_missing_links",
        description: `Case review references missing linked records: ${missingAll.join(", ")}.`,
        targetType: item.targetType ?? "messenger_safety_case",
        targetId: item.targetId ?? item.id,
        linkedCaseIds: [item.id],
        linkedReportIds: missingReports,
        linkedEvidenceIds: missingEvidence,
        linkedAuthorityRequestIds: missingAuthority,
        remediation: "Fix case links before closing case or preparing authority package.",
      });
    }
  }

  for (const item of state.authorityRequests.map((request) => refreshMessengerAuthorityRequest(request, auditIntegrity.anchorHash))) {
    if ((item.status === "approved" || item.status === "completed") && !item.approvedBy) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "authority_requests",
        severity: "critical",
        title: "authority_request_without_owner_approval",
        description: "Authority request is approved/completed without Root Owner approval marker.",
        targetType: "messenger_authority_request",
        targetId: item.id,
        linkedAuthorityRequestIds: [item.id],
        linkedReportIds: item.linkedReportIds ?? [],
        linkedCaseIds: item.linkedCaseIds ?? [],
        linkedEvidenceIds: item.linkedEvidenceIds ?? [],
        remediation: "Do not export/deliver package until owner approval is present and audited.",
      });
    }
    const missingEvidence = findMissingMessengerSafetyLinks(item.linkedEvidenceIds, evidence);
    const missingReports = findMissingMessengerSafetyLinks(item.linkedReportIds, reports);
    const missingCases = findMissingMessengerSafetyLinks(item.linkedCaseIds, cases);
    if (missingEvidence.length || missingReports.length || missingCases.length) {
      pushMessengerSafetyIntegrityFinding(findings, {
        scope: "authority_requests",
        severity: "warning",
        title: "authority_request_missing_package_links",
        description: `Authority request references missing package links: ${[...missingEvidence, ...missingReports, ...missingCases].join(", ")}.`,
        targetType: "messenger_authority_request",
        targetId: item.id,
        linkedAuthorityRequestIds: [item.id],
        linkedReportIds: missingReports,
        linkedCaseIds: missingCases,
        linkedEvidenceIds: missingEvidence,
        remediation: "Fix authority request links before export and delivery.",
      });
    }
  }

  const activeRestrictions = restrictions.filter((item) => item.status === "active");
  const activeRestrictionsWithoutEnforcementRef = activeRestrictions.filter((item) => !item.enforcementRef).length;
  const unsealedLegalHoldEvidence = state.evidenceVault.filter((item) => item.legalHold && !item.sealed).length;
  const missingEvidenceLinks = findings.filter((item) => item.title.includes("missing_evidence") || item.title.includes("missing_package_links") || item.title.includes("case_review_missing_links")).length;
  const authorityRequestsWithoutOwnerApproval = findings.filter((item) => item.title === "authority_request_without_owner_approval").length;
  const orphanCaseLinks = findings.filter((item) => item.scope === "case_reviews").length;
  const criticalFindings = findings.filter((item) => item.severity === "critical").length;
  const warningFindings = findings.filter((item) => item.severity === "warning").length;
  const status: "ok" | "warning" | "critical" = criticalFindings ? "critical" : warningFindings ? "warning" : "ok";
  const checks: AdminMessengerSafetyIntegrityMonitorSnapshot["checks"] = [
    { key: "evidence_vault_chain", scope: "evidence_vault", status: vaultIntegrity.brokenLinks ? "critical" : "ok", message: vaultIntegrity.brokenLinks ? `${vaultIntegrity.brokenLinks} broken vault link(s)` : "Evidence vault chain is valid." },
    { key: "guard_event_chain", scope: "guard_event_log", status: guardIntegrity.ok ? "ok" : "critical", message: guardIntegrity.ok ? "Guard event chain is valid." : `Guard event chain failed at ${guardIntegrity.brokenAtId ?? "unknown"}.` },
    { key: "audit_chain", scope: "audit_log", status: auditIntegrity.ok ? "ok" : "critical", message: auditIntegrity.ok ? "Admin audit chain is valid." : `Audit integrity failed: ${String(auditIntegrity.reason ?? "integrity_failed")}.` },
    { key: "active_restrictions", scope: "restrictions", status: activeRestrictionsWithoutEnforcementRef ? "critical" : "ok", message: activeRestrictionsWithoutEnforcementRef ? `${activeRestrictionsWithoutEnforcementRef} active restriction(s) without enforcementRef.` : "Active restrictions are enforceable." },
    { key: "legal_hold_seal", scope: "evidence_vault", status: unsealedLegalHoldEvidence ? "warning" : "ok", message: unsealedLegalHoldEvidence ? `${unsealedLegalHoldEvidence} legal-hold evidence item(s) are not sealed.` : "Legal-hold evidence is sealed or empty." },
  ];
  const baseSnapshot = {
    ok: true as const,
    monitorVersion: "messenger-safety-integrity-monitor-v1" as const,
    generatedAt: now,
    generatedBy: by,
    summary: {
      status,
      totalFindings: findings.length,
      criticalFindings,
      warningFindings,
      vaultBrokenLinks: vaultIntegrity.brokenLinks,
      guardEventChainOk: guardIntegrity.ok,
      auditChainOk: auditIntegrity.ok,
      activeRestrictions: activeRestrictions.length,
      activeRestrictionsWithoutEnforcementRef,
      unsealedLegalHoldEvidence,
      missingEvidenceLinks,
      authorityRequestsWithoutOwnerApproval,
      orphanCaseLinks,
      chainAnchorHash: guardIntegrity.anchorHash ?? vaultIntegrity.anchorHash ?? auditIntegrity.anchorHash ?? null,
    },
    checks,
    findings: findings.slice(0, 500),
    anchors: {
      evidenceVaultAnchorHash: vaultIntegrity.anchorHash ?? null,
      guardEventAnchorHash: guardIntegrity.anchorHash ?? null,
      auditAnchorHash: auditIntegrity.anchorHash ?? null,
      monitorHash: "pending",
    },
    policy: buildMessengerSafetyIntegrityMonitorPolicy(),
  };
  return { ...baseSnapshot, anchors: { ...baseSnapshot.anchors, monitorHash: sha256Text({ ...baseSnapshot, anchors: { ...baseSnapshot.anchors, monitorHash: undefined } }) } };
}


function normalizeMessengerSafetyEscalationStatus(value: unknown, fallback: AdminMessengerSafetyEscalationStatus = "open"): AdminMessengerSafetyEscalationStatus {
  const allowed: AdminMessengerSafetyEscalationStatus[] = ["open", "acknowledged", "compliance_review", "owner_review", "authority_pending", "actioned", "closed", "rejected"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerSafetyEscalationStatus) ? value as AdminMessengerSafetyEscalationStatus : fallback;
}

function normalizeMessengerSafetyEscalationSource(value: unknown): AdminMessengerSafetyEscalationSource {
  const allowed: AdminMessengerSafetyEscalationSource[] = ["critical_report", "critical_case", "integrity_finding", "authority_due", "pending_restriction", "guard_deny_spike", "manual"];
  return typeof value === "string" && allowed.includes(value as AdminMessengerSafetyEscalationSource) ? value as AdminMessengerSafetyEscalationSource : "manual";
}

function normalizeMessengerSafetyEscalationPriority(value: unknown, fallback: "normal" | "urgent" | "critical" = "urgent"): "normal" | "urgent" | "critical" {
  return value === "critical" || value === "urgent" || value === "normal" ? value : fallback;
}

function addMinutesIso(baseIso: string, minutes: number): string {
  const baseMs = Number.isFinite(Date.parse(baseIso)) ? Date.parse(baseIso) : Date.now();
  return new Date(baseMs + Math.max(1, minutes) * 60_000).toISOString();
}

function isMessengerSafetyEscalationTerminal(status: AdminMessengerSafetyEscalationStatus): boolean {
  return status === "closed" || status === "rejected";
}

function messengerSafetyEscalationSlaMinutes(priority: "normal" | "urgent" | "critical", source: AdminMessengerSafetyEscalationSource): number {
  if (source === "authority_due") return priority === "critical" ? 30 : priority === "urgent" ? 120 : 1440;
  if (source === "integrity_finding") return priority === "critical" ? 60 : 360;
  if (source === "critical_report" || source === "critical_case") return priority === "critical" ? 120 : 360;
  if (source === "pending_restriction") return 180;
  if (source === "guard_deny_spike") return 240;
  return priority === "critical" ? 120 : priority === "urgent" ? 360 : 1440;
}

function createMessengerSafetyEscalationId(source: AdminMessengerSafetyEscalationSource, sourceKey: string): string {
  return `msg_sla_${sha256Text({ source, sourceKey }).slice(0, 20)}`;
}

function refreshMessengerSafetyEscalation(item: AdminMessengerSafetyEscalationItem): AdminMessengerSafetyEscalationItem {
  const overdue = !isMessengerSafetyEscalationTerminal(item.status) && Number.isFinite(Date.parse(item.dueAt)) && Date.parse(item.dueAt) <= Date.now();
  return { ...item, overdue, rawContentHidden: true, userNotNotified: true };
}

function normalizeMessengerSafetyEscalationItem(value: unknown): AdminMessengerSafetyEscalationItem | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const sourceKind = normalizeMessengerSafetyEscalationSource(source.source);
  const sourceKey = readString(source.sourceKey) ?? readString(source.id);
  if (!sourceKey) return null;
  const now = new Date().toISOString();
  const priority = normalizeMessengerSafetyEscalationPriority(source.priority);
  const slaMinutes = Number.isFinite(Number(source.slaMinutes)) ? Math.max(1, Math.floor(Number(source.slaMinutes))) : messengerSafetyEscalationSlaMinutes(priority, sourceKind);
  const createdAt = readString(source.createdAt) ?? now;
  const item: AdminMessengerSafetyEscalationItem = {
    id: readString(source.id) ?? createMessengerSafetyEscalationId(sourceKind, sourceKey),
    source: sourceKind,
    sourceKey,
    title: readString(source.title) ?? "messenger_safety_escalation",
    reason: readString(source.reason) ?? sourceKind,
    status: normalizeMessengerSafetyEscalationStatus(source.status),
    priority,
    severity: source.severity === "critical" ? "critical" : "high",
    category: readString(source.category) ? normalizeMessengerSafetyCategory(source.category) : undefined,
    targetType: readString(source.targetType),
    targetId: readString(source.targetId),
    relatedUserId: readString(source.relatedUserId),
    relatedChatId: readString(source.relatedChatId),
    relatedMessageId: readString(source.relatedMessageId),
    linkedReportIds: readStringArray(source.linkedReportIds),
    linkedCaseIds: readStringArray(source.linkedCaseIds),
    linkedAiSignalIds: readStringArray(source.linkedAiSignalIds),
    linkedEvidenceIds: readStringArray(source.linkedEvidenceIds),
    linkedRestrictionIds: readStringArray(source.linkedRestrictionIds),
    linkedAuthorityRequestIds: readStringArray(source.linkedAuthorityRequestIds),
    linkedIntegrityFindingIds: readStringArray(source.linkedIntegrityFindingIds),
    slaMinutes,
    dueAt: readString(source.dueAt) ?? addMinutesIso(createdAt, slaMinutes),
    overdue: readBoolean(source.overdue, false),
    ownerRequired: readBoolean(source.ownerRequired, true),
    complianceRequired: readBoolean(source.complianceRequired, true),
    authorityCooperationRequired: readBoolean(source.authorityCooperationRequired, false),
    rawContentHidden: true,
    userNotNotified: true,
    assignedTo: readString(source.assignedTo),
    decisionNote: readString(source.decisionNote),
    timeline: Array.isArray(source.timeline) ? source.timeline.filter((item): item is { event: string; by: string; at: string; note?: string; metadata?: Record<string, unknown> } => Boolean(item && typeof item === "object" && typeof (item as Record<string, unknown>).event === "string" && typeof (item as Record<string, unknown>).by === "string" && typeof (item as Record<string, unknown>).at === "string")) : [],
    createdBy: readString(source.createdBy) ?? "system",
    createdAt,
    updatedBy: readString(source.updatedBy) ?? readString(source.createdBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? createdAt,
  };
  return refreshMessengerSafetyEscalation(item);
}

function buildMessengerSafetyEscalationPolicy(): string[] {
  return [
    "critical_reports_cases_integrity_findings_authority_due_items_and_pending_restrictions_must_enter_sla_queue",
    "critical_authority_and_integrity_escalations_require_root_owner_decision_before_closure",
    "compliance_staff_can_review_but_owner_keeps_final_external_disclosure_control",
    "escalation_center_tracks_deadline_due_at_overdue_status_and_timeline_without_raw_content",
    "no_user_notification_is_sent_for_internal_safety_compliance_escalations",
  ];
}

function createMessengerSafetyEscalation(input: {
  source: AdminMessengerSafetyEscalationSource;
  sourceKey: string;
  title: string;
  reason: string;
  priority?: "normal" | "urgent" | "critical";
  severity?: "high" | "critical";
  category?: AdminMessengerSafetyCategory;
  targetType?: string;
  targetId?: string;
  relatedUserId?: string;
  relatedChatId?: string;
  relatedMessageId?: string;
  linkedReportIds?: string[];
  linkedCaseIds?: string[];
  linkedAiSignalIds?: string[];
  linkedEvidenceIds?: string[];
  linkedRestrictionIds?: string[];
  linkedAuthorityRequestIds?: string[];
  linkedIntegrityFindingIds?: string[];
  dueAt?: string;
  ownerRequired?: boolean;
  complianceRequired?: boolean;
  authorityCooperationRequired?: boolean;
}, by = "system"): AdminMessengerSafetyEscalationItem {
  const now = new Date().toISOString();
  const priority = input.priority ?? (input.severity === "critical" ? "critical" : "urgent");
  const slaMinutes = messengerSafetyEscalationSlaMinutes(priority, input.source);
  const item: AdminMessengerSafetyEscalationItem = {
    id: createMessengerSafetyEscalationId(input.source, input.sourceKey),
    source: input.source,
    sourceKey: input.sourceKey,
    title: input.title,
    reason: input.reason,
    status: "open",
    priority,
    severity: input.severity ?? "high",
    category: input.category,
    targetType: input.targetType,
    targetId: input.targetId,
    relatedUserId: input.relatedUserId,
    relatedChatId: input.relatedChatId,
    relatedMessageId: input.relatedMessageId,
    linkedReportIds: input.linkedReportIds ?? [],
    linkedCaseIds: input.linkedCaseIds ?? [],
    linkedAiSignalIds: input.linkedAiSignalIds ?? [],
    linkedEvidenceIds: input.linkedEvidenceIds ?? [],
    linkedRestrictionIds: input.linkedRestrictionIds ?? [],
    linkedAuthorityRequestIds: input.linkedAuthorityRequestIds ?? [],
    linkedIntegrityFindingIds: input.linkedIntegrityFindingIds ?? [],
    slaMinutes,
    dueAt: input.dueAt ?? addMinutesIso(now, slaMinutes),
    overdue: false,
    ownerRequired: input.ownerRequired ?? true,
    complianceRequired: input.complianceRequired ?? true,
    authorityCooperationRequired: input.authorityCooperationRequired ?? false,
    rawContentHidden: true,
    userNotNotified: true,
    timeline: [{ event: "escalation_auto_created", by, at: now, metadata: { source: input.source, sourceKey: input.sourceKey } }],
    createdBy: by,
    createdAt: now,
    updatedBy: by,
    updatedAt: now,
  };
  return refreshMessengerSafetyEscalation(item);
}

function buildMessengerSafetyAutoEscalations(state: AdminMessengerSafetyControlState, req: AdminRequest | null, store: AdminFileStore): AdminMessengerSafetyEscalationItem[] {
  const escalations: AdminMessengerSafetyEscalationItem[] = [];
  const terminalReportStatuses: AdminMessengerSafetyReportStatus[] = ["resolved", "rejected"];
  for (const report of state.reports) {
    if (report.severity === "critical" && !terminalReportStatuses.includes(report.status)) {
      escalations.push(createMessengerSafetyEscalation({
        source: "critical_report",
        sourceKey: report.id,
        title: report.title,
        reason: report.description,
        priority: report.category === "fraud_or_scam" || report.category === "kyc_bypass_or_identity_fraud" ? "urgent" : "critical",
        severity: "critical",
        category: report.category,
        targetType: report.targetType,
        targetId: report.targetId,
        relatedUserId: report.relatedUserId,
        relatedChatId: report.relatedChatId,
        relatedMessageId: report.relatedMessageId,
        linkedReportIds: [report.id],
        linkedAiSignalIds: report.aiSignalId ? [report.aiSignalId] : [],
        linkedEvidenceIds: report.vaultEvidenceIds ?? [],
        authorityCooperationRequired: ["terrorism_or_attack_planning", "assassination_or_serious_violence", "human_trafficking", "narcotics_or_psychotropic_trafficking", "money_laundering_or_aml", "child_exploitation"].includes(report.category),
      }, req?.admin?.id ?? "system"));
    }
  }

  for (const safetyCase of state.caseReviews) {
    if (safetyCase.severity === "critical" && safetyCase.status !== "closed" && safetyCase.status !== "rejected") {
      escalations.push(createMessengerSafetyEscalation({
        source: "critical_case",
        sourceKey: safetyCase.id,
        title: safetyCase.title,
        reason: safetyCase.decision?.note ?? safetyCase.status,
        priority: safetyCase.priority === "critical" ? "critical" : "urgent",
        severity: "critical",
        category: safetyCase.category,
        targetType: safetyCase.targetType,
        targetId: safetyCase.targetId,
        relatedUserId: safetyCase.relatedUserId,
        relatedChatId: safetyCase.relatedChatId,
        relatedMessageId: safetyCase.relatedMessageId,
        linkedReportIds: safetyCase.linkedReportIds,
        linkedAiSignalIds: safetyCase.linkedAiSignalIds,
        linkedEvidenceIds: safetyCase.linkedEvidenceIds,
        linkedAuthorityRequestIds: safetyCase.linkedAuthorityRequestIds,
        ownerRequired: true,
        complianceRequired: true,
        authorityCooperationRequired: safetyCase.status === "authority_review" || safetyCase.linkedAuthorityRequestIds.length > 0,
      }, req?.admin?.id ?? "system"));
    }
  }

  for (const request of state.authorityRequests.map((item) => refreshMessengerAuthorityRequest(item, store.verifyAuditIntegrity().anchorHash ?? null))) {
    const dueSoonOrOverdue = request.dueAt && Number.isFinite(Date.parse(request.dueAt)) && Date.parse(request.dueAt) <= Date.now() + 24 * 60 * 60_000;
    if ((request.priority === "critical" || request.priority === "urgent" || dueSoonOrOverdue) && request.status !== "completed" && request.status !== "rejected") {
      escalations.push(createMessengerSafetyEscalation({
        source: "authority_due",
        sourceKey: request.id,
        title: request.authorityName,
        reason: request.requestReference ?? request.requestedScope,
        priority: request.priority,
        severity: request.priority === "critical" ? "critical" : "high",
        targetType: "authority_request",
        targetId: request.id,
        linkedReportIds: request.linkedReportIds ?? [],
        linkedCaseIds: request.linkedCaseIds ?? [],
        linkedEvidenceIds: request.linkedEvidenceIds ?? [],
        linkedAuthorityRequestIds: [request.id],
        dueAt: request.dueAt,
        ownerRequired: true,
        complianceRequired: true,
        authorityCooperationRequired: true,
      }, req?.admin?.id ?? "system"));
    }
  }

  for (const restriction of state.restrictions.map(refreshMessengerSafetyRestriction)) {
    if (restriction.status === "pending_owner_decision") {
      escalations.push(createMessengerSafetyEscalation({
        source: "pending_restriction",
        sourceKey: restriction.id,
        title: restriction.reason,
        reason: restriction.legalBasis,
        priority: restriction.severity === "critical" ? "critical" : "urgent",
        severity: restriction.severity,
        category: restriction.category,
        targetType: restriction.targetType,
        targetId: restriction.targetId,
        relatedUserId: restriction.relatedUserId,
        relatedChatId: restriction.relatedChatId,
        relatedMessageId: restriction.relatedMessageId,
        linkedReportIds: restriction.linkedReportIds,
        linkedCaseIds: restriction.linkedCaseIds,
        linkedAiSignalIds: restriction.linkedAiSignalIds,
        linkedEvidenceIds: restriction.linkedEvidenceIds,
        linkedRestrictionIds: [restriction.id],
        ownerRequired: true,
        complianceRequired: true,
      }, req?.admin?.id ?? "system"));
    }
  }

  const integrity = buildMessengerSafetyIntegrityMonitorSnapshot(req, store);
  for (const finding of integrity.findings.filter((item) => item.severity === "critical" || item.severity === "warning")) {
    escalations.push(createMessengerSafetyEscalation({
      source: "integrity_finding",
      sourceKey: finding.id,
      title: finding.title,
      reason: finding.description,
      priority: finding.severity === "critical" ? "critical" : "urgent",
      severity: finding.severity === "critical" ? "critical" : "high",
      targetType: finding.targetType ?? finding.scope,
      targetId: finding.targetId,
      linkedReportIds: finding.linkedReportIds ?? [],
      linkedCaseIds: finding.linkedCaseIds ?? [],
      linkedEvidenceIds: finding.linkedEvidenceIds ?? [],
      linkedRestrictionIds: finding.linkedRestrictionIds ?? [],
      linkedAuthorityRequestIds: finding.linkedAuthorityRequestIds ?? [],
      linkedIntegrityFindingIds: [finding.id],
      ownerRequired: finding.severity === "critical",
      complianceRequired: true,
    }, req?.admin?.id ?? "system"));
  }

  const lastHour = Date.now() - 60 * 60_000;
  const deniedRecent = state.guardEventLog.filter((item) => item.decision === "deny" && Number.isFinite(Date.parse(item.checkedAt)) && Date.parse(item.checkedAt) >= lastHour);
  if (deniedRecent.length >= 10) {
    escalations.push(createMessengerSafetyEscalation({
      source: "guard_deny_spike",
      sourceKey: `last_hour_${deniedRecent.length}`,
      title: "guard_deny_spike",
      reason: `${deniedRecent.length} deny decisions in the last hour`,
      priority: "urgent",
      severity: "high",
      targetType: "guard_event_log",
      targetId: state.guardEventLog[0]?.id,
      linkedRestrictionIds: Array.from(new Set(deniedRecent.flatMap((item) => item.matchedRestrictionIds))).slice(0, 50),
      complianceRequired: true,
      ownerRequired: false,
    }, req?.admin?.id ?? "system"));
  }

  return escalations;
}

function mergeMessengerSafetyEscalations(autoEscalations: AdminMessengerSafetyEscalationItem[], storedEscalations: AdminMessengerSafetyEscalationItem[]): AdminMessengerSafetyEscalationItem[] {
  const storedBySourceKey = new Map(storedEscalations.map((item) => [`${item.source}:${item.sourceKey}`, item]));
  const merged = autoEscalations.map((autoItem) => {
    const stored = storedBySourceKey.get(`${autoItem.source}:${autoItem.sourceKey}`);
    if (!stored) return autoItem;
    return refreshMessengerSafetyEscalation({ ...autoItem, ...stored, linkedReportIds: Array.from(new Set([...autoItem.linkedReportIds, ...stored.linkedReportIds])), linkedCaseIds: Array.from(new Set([...autoItem.linkedCaseIds, ...stored.linkedCaseIds])), linkedEvidenceIds: Array.from(new Set([...autoItem.linkedEvidenceIds, ...stored.linkedEvidenceIds])), linkedRestrictionIds: Array.from(new Set([...autoItem.linkedRestrictionIds, ...stored.linkedRestrictionIds])), linkedAuthorityRequestIds: Array.from(new Set([...autoItem.linkedAuthorityRequestIds, ...stored.linkedAuthorityRequestIds])), linkedIntegrityFindingIds: Array.from(new Set([...autoItem.linkedIntegrityFindingIds, ...stored.linkedIntegrityFindingIds])) });
  });
  const autoKeys = new Set(autoEscalations.map((item) => `${item.source}:${item.sourceKey}`));
  for (const stored of storedEscalations) {
    if (!autoKeys.has(`${stored.source}:${stored.sourceKey}`)) merged.push(refreshMessengerSafetyEscalation(stored));
  }
  return merged.sort((a, b) => {
    const priorityRank = (item: AdminMessengerSafetyEscalationItem) => item.overdue ? 0 : item.priority === "critical" ? 1 : item.priority === "urgent" ? 2 : 3;
    const rank = priorityRank(a) - priorityRank(b);
    if (rank !== 0) return rank;
    return Date.parse(a.dueAt) - Date.parse(b.dueAt);
  });
}

function buildMessengerSafetyEscalationSnapshot(req: AdminRequest | null, store: AdminFileStore, limit = 100): AdminMessengerSafetyEscalationSnapshot {
  const state = readMessengerSafetyControlState();
  const autoEscalations = buildMessengerSafetyAutoEscalations(state, req, store);
  const escalations = mergeMessengerSafetyEscalations(autoEscalations, state.escalations.map(refreshMessengerSafetyEscalation));
  const active = escalations.filter((item) => !isMessengerSafetyEscalationTerminal(item.status));
  const nextDueAt = active.filter((item) => Number.isFinite(Date.parse(item.dueAt))).sort((a, b) => Date.parse(a.dueAt) - Date.parse(b.dueAt))[0]?.dueAt ?? null;
  return {
    ok: true,
    escalationVersion: "messenger-safety-escalation-sla-v1",
    generatedAt: new Date().toISOString(),
    generatedBy: req?.admin?.id ?? "system",
    summary: {
      totalEscalations: escalations.length,
      openEscalations: active.length,
      criticalEscalations: active.filter((item) => item.priority === "critical" || item.severity === "critical").length,
      overdueEscalations: active.filter((item) => item.overdue).length,
      ownerReviewRequired: active.filter((item) => item.ownerRequired && (item.status === "open" || item.status === "owner_review" || item.status === "acknowledged")).length,
      complianceReviewRequired: active.filter((item) => item.complianceRequired && (item.status === "open" || item.status === "compliance_review" || item.status === "acknowledged")).length,
      authorityPending: active.filter((item) => item.authorityCooperationRequired || item.status === "authority_pending").length,
      actionedEscalations: escalations.filter((item) => item.status === "actioned").length,
      closedEscalations: escalations.filter((item) => item.status === "closed" || item.status === "rejected").length,
      nextDueAt,
    },
    escalations: escalations.slice(0, Math.max(1, Math.min(limit, 500))),
    policy: buildMessengerSafetyEscalationPolicy(),
  };
}

function updateMessengerSafetyEscalationStatus(state: AdminMessengerSafetyControlState, id: string, status: AdminMessengerSafetyEscalationStatus, by: string, note?: string, assignedTo?: string): { state: AdminMessengerSafetyControlState; escalation?: AdminMessengerSafetyEscalationItem } {
  const snapshot = buildMessengerSafetyEscalationSnapshot({ admin: { id: by, role: "owner", permissions: [], tokenSource: "staff-session", rootOwner: true } } as unknown as AdminRequest, { verifyAuditIntegrity: () => ({ ok: true, algorithm: "sha256", integrityVersion: "sha256-v1", totalEntries: 0, protectedEntries: 0, legacyEntries: 0, verifiedEntries: 0, anchorHash: null, generatedAt: new Date().toISOString() }) } as unknown as AdminFileStore, 500);
  const existing = snapshot.escalations.find((item) => item.id === id);
  if (!existing) return { state };
  const now = new Date().toISOString();
  const updated = refreshMessengerSafetyEscalation({
    ...existing,
    status,
    assignedTo: readString(assignedTo) ?? existing.assignedTo,
    decisionNote: note ?? existing.decisionNote,
    timeline: [{ event: `escalation_status:${status}`, by, at: now, note }, ...existing.timeline],
    updatedBy: by,
    updatedAt: now,
  });
  const others = state.escalations.filter((item) => item.id !== id && `${item.source}:${item.sourceKey}` !== `${updated.source}:${updated.sourceKey}`);
  return { state: { ...state, escalations: [updated, ...others].slice(0, 1000), updatedAt: now }, escalation: updated };
}

