type AdminWalletMerchantCredentialKind = "api_key" | "webhook_secret";
type AdminWalletMerchantCredentialMode = "test" | "live";
type AdminWalletMerchantCredentialStatus = "active" | "rotated" | "revoked";

type AdminWalletMerchantCredentialRecord = {
  id: string;
  merchantId: string;
  kind: AdminWalletMerchantCredentialKind;
  mode: AdminWalletMerchantCredentialMode;
  label: string;
  prefix: string;
  keyHash: string;
  status: AdminWalletMerchantCredentialStatus;
  scopes: string[];
  callbackUrl?: string;
  ipAllowlist: string[];
  createdBy: string;
  createdAt: string;
  updatedBy: string;
  updatedAt: string;
  rotatedBy?: string;
  rotatedAt?: string;
  revokedBy?: string;
  revokedAt?: string;
};

type AdminWalletMerchantCredentialPublic = Omit<AdminWalletMerchantCredentialRecord, "keyHash"> & { masked: string };

type AdminWalletMerchantApiCenter = {
  ok: true;
  generatedAt: string;
  liveLaunchReady: boolean;
  writeEnabled: boolean;
  summary: {
    merchants: number;
    activeMerchants: number;
    apiKeys: number;
    activeApiKeys: number;
    webhookSecrets: number;
    activeWebhookSecrets: number;
    revokedCredentials: number;
    highRiskMerchants: number;
    kybApproved: number;
    qrPayEnabled: number;
  };
  credentials: AdminWalletMerchantCredentialPublic[];
  controls: Array<{ key: string; status: "ok" | "warning" | "blocked"; title: string; detail: string }>;
  rules: string[];
};

type AdminWalletMerchantCredentialActionResult = {
  credential: AdminWalletMerchantCredentialPublic;
  secretOnce?: string;
  warning: string;
};

const ADMIN_WALLET_MERCHANT_CREDENTIALS_PATH = process.env.ADMIN_WALLET_MERCHANT_CREDENTIALS_PATH || path.join(process.cwd(), "data", "admin-merchant-credentials.json");

function adminWalletMerchantCredentialsRead(): AdminWalletMerchantCredentialRecord[] {
  try {
    if (!fs.existsSync(ADMIN_WALLET_MERCHANT_CREDENTIALS_PATH)) return [];
    const parsed = JSON.parse(fs.readFileSync(ADMIN_WALLET_MERCHANT_CREDENTIALS_PATH, "utf8")) as unknown;
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((item) => adminWalletRecord(item))
      .filter((item) => adminWalletString(item.id, "") && adminWalletString(item.merchantId, ""))
      .map((item) => ({
        id: adminWalletString(item.id),
        merchantId: adminWalletString(item.merchantId),
        kind: item.kind === "webhook_secret" ? "webhook_secret" : "api_key",
        mode: item.mode === "live" ? "live" : "test",
        label: adminWalletString(item.label, item.kind === "webhook_secret" ? "Merchant webhook secret" : "Merchant API key"),
        prefix: adminWalletString(item.prefix, "sabi_secret"),
        keyHash: adminWalletString(item.keyHash, "missing_hash"),
        status: item.status === "rotated" || item.status === "revoked" ? item.status : "active",
        scopes: readStringArray(item.scopes),
        callbackUrl: readString(item.callbackUrl),
        ipAllowlist: readStringArray(item.ipAllowlist),
        createdBy: adminWalletString(item.createdBy, "system"),
        createdAt: adminWalletString(item.createdAt, new Date(0).toISOString()),
        updatedBy: adminWalletString(item.updatedBy, adminWalletString(item.createdBy, "system")),
        updatedAt: adminWalletString(item.updatedAt, adminWalletString(item.createdAt, new Date(0).toISOString())),
        rotatedBy: readString(item.rotatedBy),
        rotatedAt: readString(item.rotatedAt),
        revokedBy: readString(item.revokedBy),
        revokedAt: readString(item.revokedAt),
      }));
  } catch (error) {
    console.warn("[sabi-admin:wallet-merchant-credentials-read-error]", error);
    return [];
  }
}

function adminWalletMerchantCredentialsWrite(records: AdminWalletMerchantCredentialRecord[]): void {
  fs.mkdirSync(path.dirname(ADMIN_WALLET_MERCHANT_CREDENTIALS_PATH), { recursive: true });
  fs.writeFileSync(ADMIN_WALLET_MERCHANT_CREDENTIALS_PATH, JSON.stringify(records, null, 2));
}

function adminWalletMerchantSecretHash(value: string): string {
  return crypto.createHash("sha256").update(value).digest("hex");
}

function adminWalletMerchantGenerateSecret(kind: AdminWalletMerchantCredentialKind, mode: AdminWalletMerchantCredentialMode): { secret: string; prefix: string; keyHash: string } {
  const raw = crypto.randomBytes(32).toString("hex");
  const secret = kind === "webhook_secret" ? `sabi_whsec_${mode}_${raw}` : `sabi_mk_${mode}_${raw}`;
  return { secret, prefix: secret.slice(0, 18), keyHash: adminWalletMerchantSecretHash(secret) };
}

function adminWalletMerchantCredentialPublic(record: AdminWalletMerchantCredentialRecord): AdminWalletMerchantCredentialPublic {
  const { keyHash: _keyHash, ...safe } = record;
  return { ...safe, masked: `${record.prefix}••••••••` };
}

function adminWalletMerchantCredentialScopeList(value: unknown, fallback: string[]): string[] {
  const allowed = new Set(["payments:read", "payments:create", "refunds:create", "settlements:read", "webhooks:send", "qr:pay", "merchant:read"]);
  const raw = readStringArray(value).filter((item) => allowed.has(item));
  return raw.length ? raw : fallback;
}

function buildAdminWalletMerchantApiCenter(store: AdminFileStore): AdminWalletMerchantApiCenter {
  const merchants = store.listMerchants();
  const credentials = adminWalletMerchantCredentialsRead();
  const activeCredentials = credentials.filter((item) => item.status === "active");
  const apiKeys = credentials.filter((item) => item.kind === "api_key");
  const webhookSecrets = credentials.filter((item) => item.kind === "webhook_secret");
  const activeApiKeys = apiKeys.filter((item) => item.status === "active");
  const activeWebhookSecrets = webhookSecrets.filter((item) => item.status === "active");
  const activeMerchants = merchants.filter((item) => item.status === "active");
  const kybApproved = merchants.filter((item) => item.kybStatus === "approved");
  const qrPayEnabled = merchants.filter((item) => item.allowQrPay);
  const merchantWithKey = new Set(activeApiKeys.map((item) => item.merchantId));
  const merchantWithWebhook = new Set(activeWebhookSecrets.map((item) => item.merchantId));
  const controls: AdminWalletMerchantApiCenter["controls"] = [
    { key: "merchant_keys", status: activeMerchants.length > 0 && activeMerchants.every((item) => merchantWithKey.has(item.id)) ? "ok" : activeMerchants.length > 0 ? "warning" : "blocked", title: "Merchant API key coverage", detail: "Every live merchant must have at least one active server-generated API key before external integration." },
    { key: "webhook_secrets", status: activeMerchants.length > 0 && activeMerchants.every((item) => merchantWithWebhook.has(item.id)) ? "ok" : activeMerchants.length > 0 ? "warning" : "blocked", title: "Webhook secret coverage", detail: "Webhook signature verification requires a dedicated secret per merchant/callback route." },
    { key: "kyb_gate", status: activeMerchants.length > 0 && activeMerchants.every((item) => item.kybStatus === "approved") ? "ok" : "warning", title: "KYB gate", detail: "Live API keys should be issued only after KYB/AML review and risk approval." },
    { key: "qr_pay_gate", status: qrPayEnabled.length > 0 ? "ok" : "warning", title: "Merchant QR/Pay", detail: "Merchant API keys must be tied to QR/Pay, settlement, ledger and audit routes." },
    { key: "secret_storage", status: "ok", title: "Secret storage", detail: "Admin stores only SHA-256 hash and masked prefix; plaintext key is returned once at generation/rotation." },
  ];
  const blockers = controls.filter((item) => item.status === "blocked").length;
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    liveLaunchReady: blockers === 0 && activeMerchants.length > 0 && activeMerchants.every((item) => merchantWithKey.has(item.id) && merchantWithWebhook.has(item.id) && item.kybStatus === "approved"),
    writeEnabled: isAdminWriteEnabled(),
    summary: {
      merchants: merchants.length,
      activeMerchants: activeMerchants.length,
      apiKeys: apiKeys.length,
      activeApiKeys: activeApiKeys.length,
      webhookSecrets: webhookSecrets.length,
      activeWebhookSecrets: activeWebhookSecrets.length,
      revokedCredentials: credentials.filter((item) => item.status === "revoked").length,
      highRiskMerchants: merchants.filter((item) => item.riskLevel === "high" || item.riskLevel === "critical").length,
      kybApproved: kybApproved.length,
      qrPayEnabled: qrPayEnabled.length,
    },
    credentials: credentials.map(adminWalletMerchantCredentialPublic),
    controls,
    rules: [
      "Merchant API keys must be generated server-side and returned as plaintext only once.",
      "Admin storage keeps only key hash, masked prefix, merchantId, scopes, callback URL, IP allowlist, status and audit references.",
      "Generate, rotate and revoke actions require root owner, merchant write permission, admin write mode and emergency-lock clearance.",
      "Webhook signatures are mandatory for Merchant QR/Pay, settlement, refund and dispute callbacks.",
      "Live merchant API access requires KYB/AML/risk approval; provider_not_configured must not be faked as ready.",
    ],
  };
}

function createAdminWalletMerchantCredential(input: {
  store: AdminFileStore;
  merchantId: string;
  kind: AdminWalletMerchantCredentialKind;
  mode: AdminWalletMerchantCredentialMode;
  label?: string;
  scopes?: string[];
  callbackUrl?: string;
  ipAllowlist?: string[];
  actorId: string;
}): AdminWalletMerchantCredentialActionResult | null {
  if (!input.store.getMerchant(input.merchantId)) return null;
  const now = new Date().toISOString();
  const generated = adminWalletMerchantGenerateSecret(input.kind, input.mode);
  const credential: AdminWalletMerchantCredentialRecord = {
    id: `${input.kind === "webhook_secret" ? "mwh" : "mak"}_${crypto.randomUUID()}`,
    merchantId: input.merchantId,
    kind: input.kind,
    mode: input.mode,
    label: input.label || (input.kind === "webhook_secret" ? "Merchant webhook secret" : "Merchant API key"),
    prefix: generated.prefix,
    keyHash: generated.keyHash,
    status: "active",
    scopes: input.scopes?.length ? input.scopes : input.kind === "webhook_secret" ? ["webhooks:send"] : ["payments:read", "payments:create", "settlements:read", "qr:pay"],
    callbackUrl: input.callbackUrl,
    ipAllowlist: input.ipAllowlist ?? [],
    createdBy: input.actorId,
    createdAt: now,
    updatedBy: input.actorId,
    updatedAt: now,
  };
  const credentials = adminWalletMerchantCredentialsRead();
  credentials.unshift(credential);
  adminWalletMerchantCredentialsWrite(credentials);
  return { credential: adminWalletMerchantCredentialPublic(credential), secretOnce: generated.secret, warning: "Store this secret now. It will not be shown again." };
}

function rotateAdminWalletMerchantCredential(input: { id: string; actorId: string }): AdminWalletMerchantCredentialActionResult | null {
  const credentials = adminWalletMerchantCredentialsRead();
  const index = credentials.findIndex((item) => item.id === input.id);
  if (index < 0) return null;
  const current = credentials[index];
  const now = new Date().toISOString();
  const generated = adminWalletMerchantGenerateSecret(current.kind, current.mode);
  const updated: AdminWalletMerchantCredentialRecord = { ...current, prefix: generated.prefix, keyHash: generated.keyHash, status: "active", rotatedBy: input.actorId, rotatedAt: now, updatedBy: input.actorId, updatedAt: now };
  credentials[index] = updated;
  adminWalletMerchantCredentialsWrite(credentials);
  return { credential: adminWalletMerchantCredentialPublic(updated), secretOnce: generated.secret, warning: "Store this rotated secret now. It will not be shown again." };
}

function revokeAdminWalletMerchantCredential(input: { id: string; actorId: string }): AdminWalletMerchantCredentialPublic | null {
  const credentials = adminWalletMerchantCredentialsRead();
  const index = credentials.findIndex((item) => item.id === input.id);
  if (index < 0) return null;
  const now = new Date().toISOString();
  const updated: AdminWalletMerchantCredentialRecord = { ...credentials[index], status: "revoked", revokedBy: input.actorId, revokedAt: now, updatedBy: input.actorId, updatedAt: now };
  credentials[index] = updated;
  adminWalletMerchantCredentialsWrite(credentials);
  return adminWalletMerchantCredentialPublic(updated);
}

