type AdminMessengerFinalReadinessManualStatus = "pending" | "verified" | "blocked" | "waived";
type AdminMessengerFinalReadinessSeverity = "info" | "warning" | "critical";
type AdminMessengerFinalReadinessStatus = "ready" | "warning" | "blocked" | "not_configured";

type AdminMessengerFinalReadinessStoredItem = {
  key: string;
  manualStatus: AdminMessengerFinalReadinessManualStatus;
  note?: string;
  verifiedBy?: string;
  verifiedAt?: string;
  blockedBy?: string;
  blockedAt?: string;
  waivedBy?: string;
  waivedAt?: string;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerFinalReadinessSettings = {
  requireOwnerFinalApproval: boolean;
  requireTwoDeviceRealtimeVerification: boolean;
  requireNoCriticalSafetyBacklog: boolean;
  requireDirectoryPromotionReady: boolean;
  requireGreetingsSafeMode: boolean;
  requireNotificationsReady: boolean;
  requirePresenceReady: boolean;
  rawPrivateContentStorageAllowed: false;
  walletTouched: false;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerFinalReadinessState = {
  settings: AdminMessengerFinalReadinessSettings;
  items: AdminMessengerFinalReadinessStoredItem[];
  updatedAt: string;
};

type AdminMessengerFinalReadinessItem = {
  key: string;
  category: string;
  title: string;
  detail: string;
  severity: AdminMessengerFinalReadinessSeverity;
  status: AdminMessengerFinalReadinessStatus;
  source: string;
  required: boolean;
  manualStatus: AdminMessengerFinalReadinessManualStatus;
  ownerRequired: boolean;
  lastVerifiedBy?: string;
  lastVerifiedAt?: string;
  note?: string;
  evidenceHash: string;
  traceHash: string;
};

type AdminMessengerFinalReadinessSnapshot = {
  ok: true;
  centerVersion: string;
  generatedAt: string;
  generatedBy: string;
  rawContentIncluded: false;
  settings: AdminMessengerFinalReadinessSettings;
  summary: {
    totalItems: number;
    requiredItems: number;
    readyItems: number;
    warningItems: number;
    blockedItems: number;
    notConfiguredItems: number;
    manuallyVerifiedItems: number;
    manuallyBlockedItems: number;
    waivedItems: number;
    launchReady: boolean;
    readinessScorePct: number;
    ownerFinalApprovalRequired: boolean;
    healthStatus: AdminMessengerFinalReadinessStatus;
  };
  items: AdminMessengerFinalReadinessItem[];
  categories: Array<{ key: string; title: string; total: number; ready: number; blocked: number; warning: number; notConfigured: number; progressPct: number }>;
  blockers: AdminMessengerFinalReadinessItem[];
  warnings: AdminMessengerFinalReadinessItem[];
  charts: {
    readinessByCategory: Array<{ label: string; value: number; ready: number; blocked: number; warning: number; notConfigured: number; progressPct: number }>;
    sourceCoverage: Array<{ label: string; value: number; ready: number; blocked: number }>;
    finalGateLanes: Array<{ key: string; status: string; title: string; detail: string; progressPct: number }>;
  };
  rules: string[];
  nextRequiredSteps: string[];
  sourceQuality: { dashboardConnected: boolean; safetyConnected: boolean; presenceConnected: boolean; notificationsConnected: boolean; directoryConnected: boolean; growthConnected: boolean; contentQualityConnected: boolean; rawContentIncluded: false; walletTouched: false };
  traceHash: string;
};

const ADMIN_MESSENGER_FINAL_READINESS_FILE = path.join(process.cwd(), ".data", "admin", "messenger-final-readiness.json");

function createMessengerFinalReadinessTraceHash(value: unknown): string {
  return crypto.createHash("sha256").update(JSON.stringify(value)).digest("hex");
}

function defaultMessengerFinalReadinessSettings(): AdminMessengerFinalReadinessSettings {
  const now = new Date().toISOString();
  return {
    requireOwnerFinalApproval: true,
    requireTwoDeviceRealtimeVerification: true,
    requireNoCriticalSafetyBacklog: true,
    requireDirectoryPromotionReady: true,
    requireGreetingsSafeMode: true,
    requireNotificationsReady: true,
    requirePresenceReady: true,
    rawPrivateContentStorageAllowed: false,
    walletTouched: false,
    updatedBy: "system",
    updatedAt: now,
  };
}

function normalizeMessengerFinalReadinessSettings(value: unknown): AdminMessengerFinalReadinessSettings {
  const defaults = defaultMessengerFinalReadinessSettings();
  const source = value && typeof value === "object" ? (value as Record<string, unknown>) : {};
  return {
    requireOwnerFinalApproval: readBoolean(source.requireOwnerFinalApproval, defaults.requireOwnerFinalApproval),
    requireTwoDeviceRealtimeVerification: readBoolean(source.requireTwoDeviceRealtimeVerification, defaults.requireTwoDeviceRealtimeVerification),
    requireNoCriticalSafetyBacklog: readBoolean(source.requireNoCriticalSafetyBacklog, defaults.requireNoCriticalSafetyBacklog),
    requireDirectoryPromotionReady: readBoolean(source.requireDirectoryPromotionReady, defaults.requireDirectoryPromotionReady),
    requireGreetingsSafeMode: readBoolean(source.requireGreetingsSafeMode, defaults.requireGreetingsSafeMode),
    requireNotificationsReady: readBoolean(source.requireNotificationsReady, defaults.requireNotificationsReady),
    requirePresenceReady: readBoolean(source.requirePresenceReady, defaults.requirePresenceReady),
    rawPrivateContentStorageAllowed: false,
    walletTouched: false,
    updatedBy: readString(source.updatedBy) ?? defaults.updatedBy,
    updatedAt: readString(source.updatedAt) ?? defaults.updatedAt,
  };
}

function normalizeMessengerFinalReadinessStoredItem(value: unknown): AdminMessengerFinalReadinessStoredItem | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const key = readString(source.key);
  if (!key) return null;
  const rawStatus = readString(source.manualStatus) ?? "pending";
  const manualStatus: AdminMessengerFinalReadinessManualStatus = rawStatus === "verified" || rawStatus === "blocked" || rawStatus === "waived" ? rawStatus : "pending";
  const now = new Date().toISOString();
  return {
    key,
    manualStatus,
    note: readString(source.note),
    verifiedBy: readString(source.verifiedBy),
    verifiedAt: readString(source.verifiedAt),
    blockedBy: readString(source.blockedBy),
    blockedAt: readString(source.blockedAt),
    waivedBy: readString(source.waivedBy),
    waivedAt: readString(source.waivedAt),
    updatedBy: readString(source.updatedBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? now,
  };
}

function defaultMessengerFinalReadinessState(): AdminMessengerFinalReadinessState {
  return { settings: defaultMessengerFinalReadinessSettings(), items: [], updatedAt: new Date().toISOString() };
}

function readMessengerFinalReadinessState(): AdminMessengerFinalReadinessState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_FINAL_READINESS_FILE)) return defaultMessengerFinalReadinessState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_FINAL_READINESS_FILE, "utf8")) as Partial<AdminMessengerFinalReadinessState>;
    return {
      settings: normalizeMessengerFinalReadinessSettings(parsed.settings),
      items: Array.isArray(parsed.items) ? parsed.items.map(normalizeMessengerFinalReadinessStoredItem).filter((item): item is AdminMessengerFinalReadinessStoredItem => Boolean(item)) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerFinalReadinessState();
  }
}

function writeMessengerFinalReadinessState(state: AdminMessengerFinalReadinessState): AdminMessengerFinalReadinessState {
  const next = { ...state, settings: normalizeMessengerFinalReadinessSettings(state.settings), updatedAt: new Date().toISOString() };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_FINAL_READINESS_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_FINAL_READINESS_FILE, JSON.stringify(next, null, 2));
  return next;
}

function finalReadinessStatusFrom(value: unknown): AdminMessengerFinalReadinessStatus {
  if (value === "ready" || value === "ok" || value === "passed") return "ready";
  if (value === "blocked" || value === "critical" || value === "failed") return "blocked";
  if (value === "not_configured" || value === "disabled") return "not_configured";
  return "warning";
}

function createMessengerFinalReadinessItem(input: {
  key: string;
  category: string;
  title: string;
  detail: string;
  severity?: AdminMessengerFinalReadinessSeverity;
  status: AdminMessengerFinalReadinessStatus;
  source: string;
  required?: boolean;
  ownerRequired?: boolean;
}, manual: Map<string, AdminMessengerFinalReadinessStoredItem>): AdminMessengerFinalReadinessItem {
  const saved = manual.get(input.key);
  const manualStatus = saved?.manualStatus ?? "pending";
  const effectiveStatus: AdminMessengerFinalReadinessStatus = manualStatus === "blocked" ? "blocked" : manualStatus === "waived" && input.status === "blocked" ? "warning" : input.status;
  const evidenceHash = createMessengerFinalReadinessTraceHash({ key: input.key, status: input.status, manualStatus, source: input.source, detail: input.detail });
  return {
    key: input.key,
    category: input.category,
    title: input.title,
    detail: input.detail,
    severity: input.severity ?? (effectiveStatus === "blocked" ? "critical" : effectiveStatus === "warning" || effectiveStatus === "not_configured" ? "warning" : "info"),
    status: effectiveStatus,
    source: input.source,
    required: input.required ?? true,
    manualStatus,
    ownerRequired: input.ownerRequired ?? false,
    lastVerifiedBy: saved?.verifiedBy,
    lastVerifiedAt: saved?.verifiedAt,
    note: saved?.note,
    evidenceHash,
    traceHash: createMessengerFinalReadinessTraceHash({ key: input.key, evidenceHash, updatedAt: saved?.updatedAt ?? "runtime", rawContentIncluded: false }),
  };
}

async function buildMessengerFinalReadinessSnapshot(options: AdminModuleOptions, req: AdminRequest, store: AdminFileStore, providerStore: AdminProviderConfigStore): Promise<AdminMessengerFinalReadinessSnapshot> {
  const generatedAt = new Date().toISOString();
  const state = readMessengerFinalReadinessState();
  const manual = new Map(state.items.map((item) => [item.key, item]));
  const center = buildMessengerAdminCenter(options, store, providerStore);
  const diagnostics = buildMessengerDiagnostics(options, store, providerStore);
  const proMonitoring = await buildMessengerProMonitoringDashboard(options, req, store, providerStore);
  const presence = await buildMessengerPresenceOperationsSnapshot(options, req, store);
  const notifications = await buildMessengerNotificationsMonitorSnapshot(options, req);
  const directoryPromotion = await buildMessengerDirectoryPromotionSnapshot(options);
  const approvalVisibility = await buildMessengerApprovalVisibilitySnapshot(options);
  const contentQuality = await buildMessengerContentQualitySnapshot(options, req, store, providerStore);
  const growthAnalytics = await buildMessengerGrowthAnalyticsSnapshot(options, req, store, providerStore);
  const growthPromotion = await buildMessengerGrowthPromotionGreetingSnapshot(options, req, store, providerStore);
  const safetyDashboard = buildMessengerSafetyDashboard();
  const policyTraining = buildMessengerSafetyPolicyTrainingSnapshot(req, store);
  const prelaunchGate = buildMessengerSafetyPrelaunchReadinessGateSnapshot(req, store);
  const items: AdminMessengerFinalReadinessItem[] = [];
  const diag = (key: string) => diagnostics.find((item) => item.key === key);
  const pushItem = (input: Parameters<typeof createMessengerFinalReadinessItem>[0]) => items.push(createMessengerFinalReadinessItem(input, manual));

  pushItem({ key: "core_admin_dashboard", category: "dashboard", title: "Admin / Messenger dashboard", detail: `Dashboard status ${center.readiness.status}; blockers ${center.readiness.blockers}; warnings ${center.readiness.warnings}.`, status: center.readiness.status === "ready" ? "ready" : center.readiness.status === "blocked" ? "blocked" : "warning", source: "messenger_dashboard", ownerRequired: true });
  pushItem({ key: "messenger_pro_monitoring", category: "dashboard", title: "Messenger PRO monitoring", detail: `Readiness score ${proMonitoring.summary.readinessScorePct}%; online ${proMonitoring.summary.onlineUsers}; active 24h ${proMonitoring.summary.active24hUsers}.`, status: finalReadinessStatusFrom(proMonitoring.summary.readinessStatus), source: "messenger_dashboard_pro" });
  pushItem({ key: "realtime_presence", category: "realtime", title: "Online / presence operations", detail: `Online ${presence.summary.onlineUsers}; anomalies ${presence.summary.suspiciousStates}; realtime health ${presence.summary.presenceReadinessPct}%.`, status: state.settings.requirePresenceReady ? finalReadinessStatusFrom(presence.summary.realtimeHealth) : "warning", source: "presence_operations", required: state.settings.requirePresenceReady });
  pushItem({ key: "two_device_realtime", category: "realtime", title: "Two-device realtime verification", detail: "Two real devices must verify send/receive, typing, read/delivered, online/last seen and reconnect behavior.", status: diag("messenger_realtime")?.status === "ok" ? "warning" : finalReadinessStatusFrom(diag("messenger_realtime")?.status), source: "manual_device_verification", required: state.settings.requireTwoDeviceRealtimeVerification, ownerRequired: true });
  pushItem({ key: "chat_send_receive", category: "chat", title: "Chat send / receive", detail: diag("messenger_chat")?.message ?? "Chat runtime must use kernel facade and real backend data.", status: finalReadinessStatusFrom(diag("messenger_chat")?.status), source: "messenger_diagnostics" });
  pushItem({ key: "media_pipeline", category: "chat", title: "Media / document / audio / video messages", detail: diag("messenger_media_pipeline")?.message ?? "Media upload and playback must be verified without fake storage or black screens.", status: finalReadinessStatusFrom(diag("messenger_media_pipeline")?.status), source: "messenger_diagnostics" });
  pushItem({ key: "calls_pipeline", category: "calls", title: "Audio / video calls", detail: diag("messenger_calls")?.message ?? "Calls must use the independent calls subsystem and pass two-device audio/video verification.", status: finalReadinessStatusFrom(diag("messenger_calls")?.status), source: "messenger_diagnostics", ownerRequired: true });
  pushItem({ key: "notifications_missed", category: "notifications", title: "Notifications / missed messages / missed calls", detail: `Notification readiness ${notifications.summary.notificationReadinessPct}%; unread ${notifications.summary.unreadMessages}; missed calls ${notifications.summary.missedCalls}; issues ${notifications.summary.issueBacklog}.`, status: state.settings.requireNotificationsReady ? finalReadinessStatusFrom(notifications.summary.healthStatus) : "warning", source: "notifications_monitor", required: state.settings.requireNotificationsReady });
  pushItem({ key: "directory_public_objects", category: "directory", title: "Public groups / channels / bots", detail: `Public entries ${directoryPromotion.summary.publicEntries}/${directoryPromotion.summary.totalEntries}; pending approval ${directoryPromotion.summary.pendingApproval}; conversion ${directoryPromotion.summary.conversionPct}%.`, status: state.settings.requireDirectoryPromotionReady ? finalReadinessStatusFrom(directoryPromotion.summary.status) : "warning", source: "directory_promotion", required: state.settings.requireDirectoryPromotionReady });
  pushItem({ key: "approval_visibility", category: "directory", title: "Approval / visibility governance", detail: `Governance score ${approvalVisibility.summary.governanceScore}%; owner review ${approvalVisibility.summary.ownerReviewRequired}; safety review ${approvalVisibility.summary.safetyReviewRequired}.`, status: approvalVisibility.summary.governanceScore >= 80 && approvalVisibility.summary.safetyReviewRequired === 0 ? "ready" : approvalVisibility.summary.safetyReviewRequired > 0 ? "blocked" : "warning", source: "approval_visibility" });
  pushItem({ key: "growth_promotion", category: "growth", title: "Growth / promotion / greetings", detail: `Promotion campaigns ${growthPromotion.summary.totalPromotions}; greeting queue ${growthPromotion.summary.greetingTasks}; automation status ${growthPromotion.summary.status}.`, status: growthPromotion.summary.status === "ready" ? "ready" : finalReadinessStatusFrom(growthPromotion.summary.status), source: "growth_promotion_greetings" });
  pushItem({ key: "greetings_safety", category: "growth", title: "Birthday / holiday greeting safe mode", detail: `Auto greetings daily limit ${growthPromotion.settings.maxAutoGreetingsPerDay}; cooldown ${growthPromotion.settings.cooldownDaysPerContact}h; AI generated text ${growthPromotion.settings.aiGreetingDraftsAllowed ? "enabled" : "disabled"}.`, status: state.settings.requireGreetingsSafeMode && growthPromotion.settings.aiGreetingDraftsAllowed ? "blocked" : "ready", source: "greetings_automation", required: state.settings.requireGreetingsSafeMode });
  pushItem({ key: "growth_analytics", category: "growth", title: "Growth analytics / retention / conversion", detail: `Retention proxy ${growthAnalytics.summary.retentionProxyPct}%; promotion conversion ${growthAnalytics.summary.promotionConversionPct}%; confidence ${growthAnalytics.summary.dataConfidencePct}%.`, status: finalReadinessStatusFrom(growthAnalytics.summary.growthHealth), source: "growth_analytics" });
  pushItem({ key: "content_quality_antispam", category: "safety", title: "Content quality / anti-spam", detail: `Open signals ${contentQuality.summary.openSignals}; review backlog ${contentQuality.summary.reviewBacklog}; quality score ${contentQuality.summary.qualityScore}%.`, status: finalReadinessStatusFrom(contentQuality.summary.healthStatus), source: "content_quality" });
  pushItem({ key: "safety_compliance", category: "safety", title: "Messenger safety / compliance", detail: `Open reports ${((safetyDashboard.summary.openCriticalReports ?? 0) + (safetyDashboard.summary.underReviewReports ?? 0))}; critical reports ${(safetyDashboard.summary.openCriticalReports ?? 0)}; active restrictions ${(safetyDashboard.summary.activeSafetyRestrictions ?? 0)}.`, status: state.settings.requireNoCriticalSafetyBacklog && (safetyDashboard.summary.openCriticalReports ?? 0) > 0 ? "blocked" : ((safetyDashboard.summary.openCriticalReports ?? 0) + (safetyDashboard.summary.underReviewReports ?? 0)) > 0 ? "warning" : "ready", source: "messenger_safety", required: state.settings.requireNoCriticalSafetyBacklog, ownerRequired: true });
  pushItem({ key: "policy_training", category: "safety", title: "Policy training acknowledgement", detail: `Required tasks ${policyTraining.summary.requiredTasks}; overdue ${policyTraining.summary.overdueTasks}; completed ${policyTraining.summary.completedTasks}.`, status: policyTraining.summary.overdueTasks > 0 ? "blocked" : policyTraining.summary.requiredTasks > policyTraining.summary.completedTasks ? "warning" : "ready", source: "policy_training" });
  pushItem({ key: "prelaunch_safety_gate", category: "launch", title: "Safety prelaunch readiness gate", detail: `Safety gate status ${prelaunchGate.summary.launchStatus}; blockers ${prelaunchGate.summary.blockingChecks}; warnings ${prelaunchGate.summary.warningChecks}.`, status: finalReadinessStatusFrom(prelaunchGate.summary.launchStatus), source: "safety_prelaunch_gate", ownerRequired: true });
  pushItem({ key: "owner_final_approval", category: "launch", title: "Owner final approval", detail: "Root Owner must manually verify Messenger MAX readiness before moving to any other module.", status: state.settings.requireOwnerFinalApproval ? (manual.get("owner_final_approval")?.manualStatus === "verified" ? "ready" : "blocked") : "warning", source: "owner_manual_approval", required: state.settings.requireOwnerFinalApproval, ownerRequired: true });

  const requiredItems = items.filter((item) => item.required);
  const blockedItems = requiredItems.filter((item) => item.status === "blocked");
  const notConfiguredItems = requiredItems.filter((item) => item.status === "not_configured");
  const warningItems = requiredItems.filter((item) => item.status === "warning");
  const readyItems = requiredItems.filter((item) => item.status === "ready");
  const readinessScorePct = requiredItems.length ? Math.max(0, Math.min(100, Math.round(((readyItems.length + warningItems.length * 0.45) / requiredItems.length) * 100))) : 100;
  const launchReady = blockedItems.length === 0 && notConfiguredItems.length === 0 && warningItems.length === 0 && (!state.settings.requireOwnerFinalApproval || manual.get("owner_final_approval")?.manualStatus === "verified");
  const categoryKeys = Array.from(new Set(items.map((item) => item.category)));
  const categories = categoryKeys.map((key) => {
    const bucket = items.filter((item) => item.category === key);
    const ready = bucket.filter((item) => item.status === "ready").length;
    const blocked = bucket.filter((item) => item.status === "blocked").length;
    const warning = bucket.filter((item) => item.status === "warning").length;
    const notConfigured = bucket.filter((item) => item.status === "not_configured").length;
    return { key, title: key.replace(/_/g, " "), total: bucket.length, ready, blocked, warning, notConfigured, progressPct: bucket.length ? Math.round((ready / bucket.length) * 100) : 100 };
  });
  const sourceKeys = Array.from(new Set(items.map((item) => item.source)));
  const sourceCoverage = sourceKeys.map((key) => {
    const bucket = items.filter((item) => item.source === key);
    return { label: key, value: bucket.length, ready: bucket.filter((item) => item.status === "ready").length, blocked: bucket.filter((item) => item.status === "blocked" || item.status === "not_configured").length };
  });
  const summary = {
    totalItems: items.length,
    requiredItems: requiredItems.length,
    readyItems: readyItems.length,
    warningItems: warningItems.length,
    blockedItems: blockedItems.length,
    notConfiguredItems: notConfiguredItems.length,
    manuallyVerifiedItems: items.filter((item) => item.manualStatus === "verified").length,
    manuallyBlockedItems: items.filter((item) => item.manualStatus === "blocked").length,
    waivedItems: items.filter((item) => item.manualStatus === "waived").length,
    launchReady,
    readinessScorePct,
    ownerFinalApprovalRequired: state.settings.requireOwnerFinalApproval,
    healthStatus: launchReady ? "ready" as const : blockedItems.length || notConfiguredItems.length ? "blocked" as const : "warning" as const,
  };
  const rules = [
    "messenger_must_be_finished_before_wallet_or_other_modules",
    "final_readiness_does_not_send_fake_runtime_events",
    "two_real_devices_must_verify_realtime_calls_notifications_and_profile_linked_data",
    "root_owner_final_approval_required_before_module_transition",
    "raw_private_messages_media_files_must_not_be_stored_in_admin_final_readiness",
    "wallet_and_other_modules_are_not_touched_by_messenger_final_readiness",
  ];
  return {
    ok: true,
    centerVersion: "ADMIN-113.46",
    generatedAt,
    generatedBy: req.admin?.id ?? "env-admin",
    rawContentIncluded: false,
    settings: state.settings,
    summary,
    items,
    categories,
    blockers: items.filter((item) => item.status === "blocked" || item.status === "not_configured"),
    warnings: items.filter((item) => item.status === "warning"),
    charts: {
      readinessByCategory: categories.map((item) => ({ label: item.key, value: item.total, ready: item.ready, blocked: item.blocked, warning: item.warning, notConfigured: item.notConfigured, progressPct: item.progressPct })),
      sourceCoverage,
      finalGateLanes: [
        { key: "runtime", status: finalReadinessStatusFrom(diag("messenger_realtime")?.status), title: "Runtime / realtime", detail: "Kernel facade, socket gateway, presence and chat runtime.", progressPct: categories.find((item) => item.key === "realtime")?.progressPct ?? 0 },
        { key: "public_surface", status: approvalVisibility.summary.governanceScore >= 80 ? "ready" : "warning", title: "Public surface", detail: "Groups, channels, bots, promotion and approval visibility.", progressPct: categories.find((item) => item.key === "directory")?.progressPct ?? 0 },
        { key: "safety", status: contentQuality.summary.healthStatus, title: "Safety / anti-spam", detail: "Reports, quality, training, policy and prelaunch safety gates.", progressPct: categories.find((item) => item.key === "safety")?.progressPct ?? 0 },
        { key: "owner", status: manual.get("owner_final_approval")?.manualStatus === "verified" ? "ready" : "blocked", title: "Owner final approval", detail: "Final owner verification is required before moving beyond Messenger.", progressPct: manual.get("owner_final_approval")?.manualStatus === "verified" ? 100 : 0 },
      ],
    },
    rules,
    nextRequiredSteps: launchReady ? ["run_mobile_backend_two_device_final_verification"] : [...blockedItems, ...notConfiguredItems, ...warningItems].slice(0, 8).map((item) => item.key),
    sourceQuality: {
      dashboardConnected: true,
      safetyConnected: true,
      presenceConnected: presence.source !== "not_configured",
      notificationsConnected: notifications.source !== "not_configured",
      directoryConnected: directoryPromotion.sourceQuality.entriesSyncedFromDirectory > 0 || directoryPromotion.summary.totalEntries > 0,
      growthConnected: growthAnalytics.sourceQuality.usersSampled > 0 || growthAnalytics.sourceQuality.messagesSampled > 0,
      contentQualityConnected: true,
      rawContentIncluded: false,
      walletTouched: false,
    },
    traceHash: createMessengerFinalReadinessTraceHash({ center: "messenger_final_readiness", summary, generatedAt, rules, rawContentIncluded: false, walletTouched: false }),
  };
}

function updateMessengerFinalReadinessItemStatus(key: string, status: AdminMessengerFinalReadinessManualStatus, by: string, note?: string): AdminMessengerFinalReadinessState {
  const state = readMessengerFinalReadinessState();
  const now = new Date().toISOString();
  const previous = state.items.find((item) => item.key === key);
  const nextItem: AdminMessengerFinalReadinessStoredItem = {
    key,
    manualStatus: status,
    note,
    verifiedBy: status === "verified" ? by : previous?.verifiedBy,
    verifiedAt: status === "verified" ? now : previous?.verifiedAt,
    blockedBy: status === "blocked" ? by : previous?.blockedBy,
    blockedAt: status === "blocked" ? now : previous?.blockedAt,
    waivedBy: status === "waived" ? by : previous?.waivedBy,
    waivedAt: status === "waived" ? now : previous?.waivedAt,
    updatedBy: by,
    updatedAt: now,
  };
  const items = [...state.items.filter((item) => item.key !== key), nextItem];
  return writeMessengerFinalReadinessState({ ...state, items });
}

const ADMIN_MESSENGER_NOTIFICATIONS_MONITOR_FILE = path.join(process.cwd(), ".data", "admin", "messenger-notifications-monitor.json");

function createMessengerNotificationsTraceHash(value: unknown): string {
  return crypto.createHash("sha256").update(JSON.stringify(value)).digest("hex");
}

function defaultMessengerNotificationsMonitorSettings(): AdminMessengerNotificationsMonitorSettings {
  const now = new Date().toISOString();
  return {
    monitorEnabled: true,
    pushDeliveryMonitorEnabled: true,
    unreadMessagesMonitorEnabled: true,
    missedCallsMonitorEnabled: true,
    missedMessagesMonitorEnabled: true,
    realtimeQueueMonitorEnabled: true,
    readReceiptsMonitorEnabled: true,
    requireMessengerRealtimeBridge: true,
    rawPrivateContentStorageAllowed: false,
    primaryIdentity: "unified_user_id",
    maxUnreadPerUserWarning: 50,
    maxDeliveryLagMinutes: 5,
    maxQueueDepthWarning: 100,
    missedCallAlertWindowHours: 24,
    updatedBy: "system",
    updatedAt: now,
  };
}

function normalizeMessengerNotificationsMonitorSettings(value: unknown): AdminMessengerNotificationsMonitorSettings {
  const source = value && typeof value === "object" ? value as Record<string, unknown> : {};
  const defaults = defaultMessengerNotificationsMonitorSettings();
  return {
    monitorEnabled: readBoolean(source.monitorEnabled, defaults.monitorEnabled),
    pushDeliveryMonitorEnabled: readBoolean(source.pushDeliveryMonitorEnabled, defaults.pushDeliveryMonitorEnabled),
    unreadMessagesMonitorEnabled: readBoolean(source.unreadMessagesMonitorEnabled, defaults.unreadMessagesMonitorEnabled),
    missedCallsMonitorEnabled: readBoolean(source.missedCallsMonitorEnabled, defaults.missedCallsMonitorEnabled),
    missedMessagesMonitorEnabled: readBoolean(source.missedMessagesMonitorEnabled, defaults.missedMessagesMonitorEnabled),
    realtimeQueueMonitorEnabled: readBoolean(source.realtimeQueueMonitorEnabled, defaults.realtimeQueueMonitorEnabled),
    readReceiptsMonitorEnabled: readBoolean(source.readReceiptsMonitorEnabled, defaults.readReceiptsMonitorEnabled),
    requireMessengerRealtimeBridge: readBoolean(source.requireMessengerRealtimeBridge, defaults.requireMessengerRealtimeBridge),
    rawPrivateContentStorageAllowed: false,
    primaryIdentity: "unified_user_id",
    maxUnreadPerUserWarning: Math.max(1, Math.min(10000, Math.floor(readNumber(source.maxUnreadPerUserWarning, defaults.maxUnreadPerUserWarning)))),
    maxDeliveryLagMinutes: Math.max(1, Math.min(1440, Math.floor(readNumber(source.maxDeliveryLagMinutes, defaults.maxDeliveryLagMinutes)))),
    maxQueueDepthWarning: Math.max(1, Math.min(100000, Math.floor(readNumber(source.maxQueueDepthWarning, defaults.maxQueueDepthWarning)))),
    missedCallAlertWindowHours: Math.max(1, Math.min(168, Math.floor(readNumber(source.missedCallAlertWindowHours, defaults.missedCallAlertWindowHours)))),
    updatedBy: readString(source.updatedBy) ?? defaults.updatedBy,
    updatedAt: readString(source.updatedAt) ?? defaults.updatedAt,
  };
}

function defaultMessengerNotificationsMonitorState(): AdminMessengerNotificationsMonitorState {
  return { settings: defaultMessengerNotificationsMonitorSettings(), issues: [], updatedAt: new Date().toISOString() };
}

function normalizeMessengerNotificationsKnownIssue(value: unknown): AdminMessengerNotificationsKnownIssue | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  if (!id) return null;
  const status: AdminMessengerNotificationIssueStatus = source.status === "acknowledged" || source.status === "resolved" ? source.status : "open";
  return { id, status, note: readString(source.note), updatedBy: readString(source.updatedBy) ?? "system", updatedAt: readString(source.updatedAt) ?? new Date().toISOString() };
}

function readMessengerNotificationsMonitorState(): AdminMessengerNotificationsMonitorState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_NOTIFICATIONS_MONITOR_FILE)) return defaultMessengerNotificationsMonitorState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_NOTIFICATIONS_MONITOR_FILE, "utf8")) as Partial<AdminMessengerNotificationsMonitorState>;
    return {
      settings: normalizeMessengerNotificationsMonitorSettings(parsed.settings),
      issues: Array.isArray(parsed.issues) ? parsed.issues.map(normalizeMessengerNotificationsKnownIssue).filter((item): item is AdminMessengerNotificationsKnownIssue => Boolean(item)) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerNotificationsMonitorState();
  }
}

function writeMessengerNotificationsMonitorState(state: AdminMessengerNotificationsMonitorState): AdminMessengerNotificationsMonitorState {
  const next = { ...state, settings: normalizeMessengerNotificationsMonitorSettings(state.settings), updatedAt: new Date().toISOString() };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_NOTIFICATIONS_MONITOR_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_NOTIFICATIONS_MONITOR_FILE, JSON.stringify(next, null, 2));
  return next;
}

function normalizeMessengerDeliveryStatus(raw: string | undefined, fallback: string): AdminMessengerNotificationDeliveryItem["status"] {
  const value = (raw ?? "").trim().toLowerCase();
  if (["queued", "pending", "scheduled", "waiting"].includes(value)) return "queued";
  if (["sent", "delivered", "ok", "success"].includes(value)) return "delivered";
  if (["failed", "error", "rejected", "undelivered"].includes(value)) return "failed";
  if (["read", "seen", "opened"].includes(value)) return "read";
  if (["unread", "new"].includes(value)) return "unread";
  if (["missed", "no_answer", "not_answered"].includes(value)) return "missed";
  return fallback;
}

function minutesBetweenDates(start?: string, end?: string): number | null {
  if (!start || !end) return null;
  const a = new Date(start).getTime();
  const b = new Date(end).getTime();
  if (!Number.isFinite(a) || !Number.isFinite(b)) return null;
  return Math.max(0, Math.round((b - a) / 60000));
}

function buildMessengerNotificationDeliveryItem(row: unknown, kind: AdminMessengerNotificationDeliveryItem["kind"], source: string): AdminMessengerNotificationDeliveryItem | null {
  if (!row || typeof row !== "object") return null;
  const record = row as Record<string, unknown>;
  const id = recordString(record, ["id", "uuid", "eventId", "notificationId", "messageId", "callId"]);
  if (!id) return null;
  const targetUserId = recordString(record, ["targetUserId", "userId", "receiverUserId", "recipientUserId", "toUserId", "ownerUserId"]);
  const chatId = recordString(record, ["chatId", "conversationId", "roomId", "threadId"]);
  const messageId = recordString(record, ["messageId", "clientMessageId", "id"]);
  const callId = recordString(record, ["callId", "sessionId", "id"]);
  const createdAt = dateStringFromRecord(record, ["createdAt", "queuedAt", "sentAt", "startedAt", "timestamp"]);
  const deliveredAt = dateStringFromRecord(record, ["deliveredAt", "sentAt", "receivedAt", "completedAt"]);
  const readAt = dateStringFromRecord(record, ["readAt", "seenAt", "openedAt"]);
  const rawStatus = recordString(record, ["deliveryStatus", "status", "state", "readStatus"]);
  const fallback = kind === "message" && !readAt ? "unread" : kind === "call" ? "missed" : "unknown";
  const channel = recordString(record, ["channel", "transport", "provider", "type"]);
  return {
    id,
    kind,
    targetUserId,
    chatId,
    messageId: kind === "message" || kind === "read_receipt" ? messageId : undefined,
    callId: kind === "call" ? callId : undefined,
    channel: channel ?? (kind === "call" ? "call" : kind === "message" ? "in_app" : "unknown"),
    status: normalizeMessengerDeliveryStatus(rawStatus, fallback),
    createdAt,
    deliveredAt,
    readAt,
    lagMinutes: minutesBetweenDates(createdAt, deliveredAt ?? readAt),
    source,
    traceHash: createMessengerNotificationsTraceHash({ id, kind, targetUserId, chatId, messageId, callId, createdAt, status: rawStatus }),
    rawContentIncluded: false,
  };
}

function createMessengerNotificationsIssue(input: {
  kind: AdminMessengerNotificationIssueKind;
  severity: AdminMessengerNotificationIssueSeverity;
  title: string;
  detail: string;
  targetType: AdminMessengerNotificationsMonitorIssue["targetType"];
  targetId: string;
  count: number;
  detectedAt: string;
}, known: Map<string, AdminMessengerNotificationsKnownIssue>): AdminMessengerNotificationsMonitorIssue {
  const id = `notif_issue_${createMessengerNotificationsTraceHash({ kind: input.kind, targetType: input.targetType, targetId: input.targetId }).slice(0, 18)}`;
  const stored = known.get(id);
  return {
    id,
    kind: input.kind,
    severity: input.severity,
    status: stored?.status ?? "open",
    title: input.title,
    detail: input.detail,
    targetType: input.targetType,
    targetId: input.targetId,
    count: input.count,
    traceHash: createMessengerNotificationsTraceHash({ ...input, id }),
    detectedAt: input.detectedAt,
    acknowledgedBy: stored?.status === "acknowledged" ? stored.updatedBy : undefined,
    acknowledgedAt: stored?.status === "acknowledged" ? stored.updatedAt : undefined,
    resolvedBy: stored?.status === "resolved" ? stored.updatedBy : undefined,
    resolvedAt: stored?.status === "resolved" ? stored.updatedAt : undefined,
    note: stored?.note,
    rawContentIncluded: false,
  };
}

async function buildMessengerNotificationsMonitorSnapshot(options: AdminModuleOptions, req: AdminRequest): Promise<AdminMessengerNotificationsMonitorSnapshot> {
  const state = readMessengerNotificationsMonitorState();
  const settings = state.settings;
  const runtime = runtimeRecord(options);
  const notificationRows = await listDelegateRows(options, ["messengerNotification", "messengerNotifications", "notification", "notifications", "pushNotification", "pushNotifications"], 800);
  const messageRows = await listDelegateRows(options, ["messengerMessage", "messengerMessages", "message", "messages", "chatMessage", "chatMessages"], 800);
  const callRows = await listDelegateRows(options, ["messengerCall", "messengerCalls", "call", "calls", "voiceCall", "videoCall", "premiumCall", "callSession"], 500);
  const readReceiptRows = await listDelegateRows(options, ["messengerReadReceipt", "messengerReadReceipts", "readReceipt", "readReceipts", "messageReceipt", "messageReceipts"], 500);
  const notificationEvents = notificationRows.map((row) => buildMessengerNotificationDeliveryItem(row, "push", "database")).filter((item): item is AdminMessengerNotificationDeliveryItem => Boolean(item));
  const messageEvents = messageRows.map((row) => buildMessengerNotificationDeliveryItem(row, "message", "database")).filter((item): item is AdminMessengerNotificationDeliveryItem => Boolean(item));
  const callEvents = callRows.map((row) => buildMessengerNotificationDeliveryItem(row, "call", "database")).filter((item): item is AdminMessengerNotificationDeliveryItem => Boolean(item));
  const receiptEvents = readReceiptRows.map((row) => buildMessengerNotificationDeliveryItem(row, "read_receipt", "database")).filter((item): item is AdminMessengerNotificationDeliveryItem => Boolean(item));
  const runtimeQueued = numberFromRuntime(runtime, ["messengerNotificationQueueDepth", "notificationQueueDepth", "pushQueueDepth", "realtimeQueueDepth"]);
  const runtimeFailed = numberFromRuntime(runtime, ["messengerFailedNotifications", "failedNotifications", "pushFailed"]);
  const runtimeDelivered = numberFromRuntime(runtime, ["messengerDeliveredNotifications", "deliveredNotifications", "pushDelivered"]);
  const runtimeUnread = numberFromRuntime(runtime, ["messengerUnreadMessages", "unreadMessages", "unreadMessageCount"]);
  const runtimeMissedCalls = numberFromRuntime(runtime, ["messengerMissedCalls", "missedCalls", "missedCallCount"]);
  const runtimeReadReceipts = numberFromRuntime(runtime, ["messengerReadReceipts", "readReceipts", "readReceiptCount"]);
  const events = [...notificationEvents, ...messageEvents, ...callEvents, ...receiptEvents].slice(0, 260);
  const source: AdminMessengerNotificationsMonitorSnapshot["source"] = events.length ? "database" : [runtimeQueued, runtimeFailed, runtimeDelivered, runtimeUnread, runtimeMissedCalls, runtimeReadReceipts].some((value) => value !== null) ? "runtime" : "not_configured";
  const queuedNotifications = notificationEvents.filter((item) => item.status === "queued").length + (events.length ? 0 : (runtimeQueued ?? 0));
  const deliveredNotifications = notificationEvents.filter((item) => item.status === "delivered" || item.status === "read").length + (events.length ? 0 : (runtimeDelivered ?? 0));
  const failedNotifications = notificationEvents.filter((item) => item.status === "failed").length + (events.length ? 0 : (runtimeFailed ?? 0));
  const unreadMessages = settings.unreadMessagesMonitorEnabled ? messageEvents.filter((item) => item.status === "unread" || (!item.readAt && item.status !== "read")).length + (messageEvents.length ? 0 : (runtimeUnread ?? 0)) : 0;
  const missedMessages = settings.missedMessagesMonitorEnabled ? messageEvents.filter((item) => item.status === "failed" || item.status === "queued").length : 0;
  const missedCalls = settings.missedCallsMonitorEnabled ? callEvents.filter((item) => item.status === "missed" || item.status === "failed" || item.status === "unknown").length + (callEvents.length ? 0 : (runtimeMissedCalls ?? 0)) : 0;
  const readReceipts = settings.readReceiptsMonitorEnabled ? receiptEvents.length + (receiptEvents.length ? 0 : (runtimeReadReceipts ?? 0)) : 0;
  const realtimeQueueDepth = settings.realtimeQueueMonitorEnabled ? (runtimeQueued ?? queuedNotifications) : 0;
  const unreadByUser = new Map<string, number>();
  messageEvents.forEach((item) => {
    if ((item.status === "unread" || (!item.readAt && item.status !== "read")) && item.targetUserId) unreadByUser.set(item.targetUserId, (unreadByUser.get(item.targetUserId) ?? 0) + 1);
  });
  const known = new Map(state.issues.map((item) => [item.id, item]));
  const detectedAt = new Date().toISOString();
  const issues: AdminMessengerNotificationsMonitorIssue[] = [];
  if (settings.pushDeliveryMonitorEnabled && failedNotifications > 0) issues.push(createMessengerNotificationsIssue({ kind: "delivery_failure", severity: failedNotifications > 10 ? "critical" : failedNotifications > 3 ? "high" : "medium", title: "Notification delivery failures", detail: `${failedNotifications} Messenger notification delivery events are failed.`, targetType: "provider", targetId: "push_delivery", count: failedNotifications, detectedAt }, known));
  if (settings.realtimeQueueMonitorEnabled && realtimeQueueDepth > settings.maxQueueDepthWarning) issues.push(createMessengerNotificationsIssue({ kind: "queue_backlog", severity: realtimeQueueDepth > settings.maxQueueDepthWarning * 3 ? "critical" : "high", title: "Realtime notification queue backlog", detail: `Queue depth ${realtimeQueueDepth} is above ${settings.maxQueueDepthWarning}.`, targetType: "queue", targetId: "messenger_realtime_queue", count: realtimeQueueDepth, detectedAt }, known));
  unreadByUser.forEach((count, userId) => {
    if (count > settings.maxUnreadPerUserWarning) issues.push(createMessengerNotificationsIssue({ kind: "high_unread", severity: count > settings.maxUnreadPerUserWarning * 3 ? "high" : "medium", title: "High unread messages for user", detail: `User has ${count} unread Messenger messages.`, targetType: "user", targetId: userId, count, detectedAt }, known));
  });
  if (missedCalls > 0) issues.push(createMessengerNotificationsIssue({ kind: "missed_call_spike", severity: missedCalls > 20 ? "high" : "medium", title: "Missed calls require review", detail: `${missedCalls} missed call events in current sample/runtime window.`, targetType: "call", targetId: "missed_calls_window", count: missedCalls, detectedAt }, known));
  const realtimeBridgeReady = readRuntimeFlag(runtime, ["messengerRealtimeReady", "messengerRealtimeEnabled", "messengerSocketReady", "messengerPresenceReady"], null) === true;
  const pushProviderReady = readRuntimeFlag(runtime, ["pushProviderReady", "messengerPushReady", "notificationsProviderReady", "expoPushReady"], null) === true;
  if (settings.requireMessengerRealtimeBridge && !realtimeBridgeReady) issues.push(createMessengerNotificationsIssue({ kind: "realtime_bridge_not_ready", severity: source === "not_configured" ? "high" : "medium", title: "Messenger realtime bridge is not confirmed ready", detail: "Runtime did not confirm Messenger realtime/presence bridge readiness for notifications.", targetType: "runtime", targetId: "messenger_realtime_bridge", count: 1, detectedAt }, known));
  if (settings.pushDeliveryMonitorEnabled && !pushProviderReady) issues.push(createMessengerNotificationsIssue({ kind: "push_provider_not_configured", severity: source === "not_configured" ? "high" : "medium", title: "Push provider readiness not confirmed", detail: "Push/notification provider must be real or clearly provider_not_configured before launch.", targetType: "provider", targetId: "push_provider", count: 1, detectedAt }, known));
  if (settings.readReceiptsMonitorEnabled && messageEvents.length > 0 && readReceipts === 0) issues.push(createMessengerNotificationsIssue({ kind: "read_receipt_gap", severity: "medium", title: "Read receipt gap", detail: "Messages are sampled but read receipts are not visible to Admin monitor.", targetType: "system", targetId: "read_receipts", count: messageEvents.length, detectedAt }, known));
  const unresolvedIssues = issues.filter((item) => item.status !== "resolved");
  const deliveryTotal = queuedNotifications + deliveredNotifications + failedNotifications;
  const deliveryHealthPct = deliveryTotal > 0 ? percentOf(deliveredNotifications, deliveryTotal) : (source === "not_configured" ? 0 : 100);
  const readyChecks = [source !== "not_configured", deliveryHealthPct >= 90, unresolvedIssues.length === 0, realtimeBridgeReady || !settings.requireMessengerRealtimeBridge, pushProviderReady || !settings.pushDeliveryMonitorEnabled, readReceipts > 0 || messageEvents.length === 0].filter(Boolean).length;
  const notificationReadinessPct = percentOf(readyChecks, 6);
  const healthStatus: AdminMessengerNotificationsMonitorSnapshot["summary"]["healthStatus"] = source === "not_configured" ? "not_configured" : unresolvedIssues.some((item) => item.severity === "critical") ? "blocked" : unresolvedIssues.length > 0 || notificationReadinessPct < 80 ? "warning" : "ready";
  const issueCounts = new Map<string, number>();
  issues.forEach((item) => issueCounts.set(item.kind, (issueCounts.get(item.kind) ?? 0) + 1));
  const last7 = Array.from({ length: 7 }).map((_, index) => {
    const date = new Date(Date.now() - (6 - index) * 86400000);
    const day = date.toISOString().slice(0, 10);
    const value = callEvents.filter((item) => (item.createdAt ?? "").slice(0, 10) === day && item.status === "missed").length;
    return { label: day.slice(5), value };
  });
  return {
    ok: true,
    centerVersion: "messenger-notifications-monitor-v1",
    generatedAt: detectedAt,
    generatedBy: req.admin?.id ?? "env-admin",
    rawContentIncluded: false,
    source,
    settings,
    summary: {
      totalDeliveryEvents: events.length,
      queuedNotifications,
      deliveredNotifications,
      failedNotifications,
      unreadMessages,
      unreadUsers: unreadByUser.size || (unreadMessages > 0 ? 1 : 0),
      missedMessages,
      missedCalls,
      readReceipts,
      realtimeQueueDepth,
      pushProviderReady,
      realtimeBridgeReady,
      issueBacklog: unresolvedIssues.length,
      acknowledgedIssues: issues.filter((item) => item.status === "acknowledged").length,
      resolvedIssues: issues.filter((item) => item.status === "resolved").length,
      deliveryHealthPct,
      notificationReadinessPct,
      healthStatus,
    },
    deliveryEvents: events,
    issues: issues.sort((a, b) => b.detectedAt.localeCompare(a.detectedAt)).slice(0, 120),
    charts: {
      deliveryFunnel: chartFromCounts([
        { label: "queued", value: queuedNotifications },
        { label: "delivered", value: deliveredNotifications },
        { label: "failed", value: failedNotifications },
        { label: "unread", value: unreadMessages },
        { label: "read_receipts", value: readReceipts },
      ]),
      issueMix: Array.from(issueCounts.entries()).map(([label, value]) => ({ label, value })).sort((a, b) => b.value - a.value),
      unreadTopUsers: Array.from(unreadByUser.entries()).sort((a, b) => b[1] - a[1]).slice(0, 12).map(([label, value]) => ({ label, value })),
      missedCallTrend: last7,
      healthLanes: [
        { key: "delivery", status: deliveryHealthPct >= 90 ? "ready" : deliveryTotal > 0 ? "warning" : "not_configured", title: "Delivery health", detail: `${deliveryHealthPct}% delivered/read in current sample.`, value: deliveryHealthPct, target: 90, progressPct: Math.min(100, deliveryHealthPct) },
        { key: "queue", status: realtimeQueueDepth > settings.maxQueueDepthWarning ? "warning" : "ready", title: "Realtime queue", detail: `Queue depth ${realtimeQueueDepth}; warning limit ${settings.maxQueueDepthWarning}.`, value: realtimeQueueDepth, target: settings.maxQueueDepthWarning, progressPct: Math.min(100, percentOf(realtimeQueueDepth, settings.maxQueueDepthWarning)) },
        { key: "unread", status: unreadMessages > 0 ? "warning" : "ready", title: "Unread / missed messages", detail: `${unreadMessages} unread and ${missedMessages} missed message delivery signals.`, value: unreadMessages + missedMessages, target: settings.maxUnreadPerUserWarning, progressPct: Math.min(100, percentOf(unreadMessages + missedMessages, settings.maxUnreadPerUserWarning)) },
        { key: "missed_calls", status: missedCalls > 0 ? "warning" : "ready", title: "Missed calls", detail: `${missedCalls} missed call signals in monitored window.`, value: missedCalls, target: 20, progressPct: Math.min(100, percentOf(missedCalls, 20)) },
      ],
    },
    rules: [
      "messenger_notifications_monitor_does_not_touch_wallet_or_other_modules",
      "messenger_notifications_monitor_stores_metadata_ids_hashes_statuses_and_timestamps_only",
      "raw_private_message_text_media_and_files_must_not_be_saved_in_admin_notifications_monitor",
      "missed_messages_calls_unread_and_delivery_failures_are_operational_signals_not_user_guilt_decisions",
      "actual_delivery_must_use_real_messenger_runtime_push_and_realtime_providers_no_fake_send",
    ],
    nextRequiredSteps: [
      "connect_monitor_to_real_messenger_notification_delivery_queue",
      "verify_unread_missed_call_badges_on_two_real_devices",
      "verify_push_provider_and_realtime_socket_delivery_health_before_launch",
    ],
    sourceQuality: { notificationRows: notificationRows.length, messageRows: messageRows.length, callRows: callRows.length, readReceiptRows: readReceiptRows.length, runtimeCountersAvailable: [runtimeQueued, runtimeFailed, runtimeDelivered, runtimeUnread, runtimeMissedCalls, runtimeReadReceipts].some((value) => value !== null), rawContentIncluded: false, walletTouched: false },
    traceHash: createMessengerNotificationsTraceHash({ center: "notifications_monitor", source, settings, summary: { queuedNotifications, deliveredNotifications, failedNotifications, unreadMessages, missedCalls, readReceipts, realtimeQueueDepth }, generatedAt: detectedAt }),
  };
}

function updateMessengerNotificationsIssueStatus(id: string, status: AdminMessengerNotificationIssueStatus, by: string, note?: string): AdminMessengerNotificationsMonitorState {
  const state = readMessengerNotificationsMonitorState();
  const now = new Date().toISOString();
  const item: AdminMessengerNotificationsKnownIssue = { id, status, note, updatedBy: by, updatedAt: now };
  const exists = state.issues.some((entry) => entry.id === id);
  const issues = exists ? state.issues.map((entry) => entry.id === id ? item : entry) : [item, ...state.issues];
  return writeMessengerNotificationsMonitorState({ ...state, issues });
}

function messengerFeatureFlags(store?: AdminFileStore) {
  const control = readMessengerControlState();
  const overrides = new Map(control.featureFlags.map((flag) => [flag.key, flag]));
  const base = [
    { key: "messenger_core", enabled: envFlag("SABI_MESSENGER_ENABLED", true), ownerControlled: true, riskLevel: "medium" as const, description: "Core Sabi Messenger chat shell and routing." },
    { key: "messenger_realtime_presence", enabled: envFlag("SABI_MESSENGER_REALTIME_ENABLED", true), ownerControlled: true, riskLevel: "high" as const, description: "Realtime presence, typing, delivered and read receipts." },
    { key: "messenger_calls", enabled: envFlag("SABI_CALLS_ENABLED", true), ownerControlled: true, riskLevel: "high" as const, description: "Independent premium audio/video call runtime readiness." },
    { key: "messenger_media", enabled: envFlag("SABI_MESSENGER_MEDIA_ENABLED", true), ownerControlled: true, riskLevel: "medium" as const, description: "Media, documents, audio messages and video messages." },
    { key: "messenger_public_directory", enabled: envFlag("SABI_MESSENGER_PUBLIC_DIRECTORY_ENABLED", true), ownerControlled: true, riskLevel: "medium" as const, description: "Global search/listing for public groups, channels and bots." },
    { key: "messenger_paid_features", enabled: envFlag("SABI_MESSENGER_PREMIUM_ENABLED", false), ownerControlled: true, riskLevel: "high" as const, description: "Paid AI translation, premium stickers and future monetized features." },
  ];

  return base.map((flag) => {
    const override = overrides.get(flag.key);
    return {
      ...flag,
      enabled: override ? override.enabled : flag.enabled,
      source: override ? "admin" as const : "env_or_default" as const,
      updatedBy: override?.updatedBy,
      updatedAt: override?.updatedAt,
      note: override?.note,
    };
  });
}

function computeMessengerCheckStatus(pass: boolean | null, configured = true): AdminMessengerStatus {
  if (!configured) return "not_configured";
  if (pass === true) return "ok";
  if (pass === false) return "blocked";
  return "warning";
}

function hasRuntimeOk(runtime: Record<string, unknown>, keys: string[]): boolean {
  return readRuntimeFlag(runtime, keys) === true;
}

function buildMessengerDiagnostics(options: AdminModuleOptions, store: AdminFileStore, providerStore: AdminProviderConfigStore) {
  const runtime = runtimeRecord(options);
  const providers = getAdminProviderStatuses(providerStore.list());
  const aiProviders = providers.filter((item) => item.kind === "ai");
  const pushProviders = providers.filter((item) => item.kind === "push");
  const storageProviders = providers.filter((item) => item.kind === "storage" || item.key.includes("storage"));
  const recentMessengerAudit = store.listAudit(100).filter((entry) => String(entry.action).includes("messenger"));
  const riskSignals = store.listRiskSignals(100).filter((signal) => signal.source === "messenger" || String(signal.targetType) === "messenger" || signal.category.includes("messenger"));
  const activeLocks = store.listEmergencyLocks(100).filter((lock) => lock.status === "active" && (lock.scope === "all" || lock.scope === "system" || lock.scope === "ai"));
  const directoryControl = readMessengerDirectoryControlState();
  const activeDirectoryRestrictions = directoryControl.restrictions.filter((item) => item.status === "active");

  const messengerApiReady = hasRuntimeOk(runtime, ["messengerApiMounted"]) && hasRuntimeOk(runtime, ["callsApiMounted"]);
  const messengerRealtimeRuntimeReady = readRuntimeFlag(runtime, ["messengerRealtimeReady", "realtimeReady", "socketReady"]);
  const callsRuntimeReady = readRuntimeFlag(runtime, ["callsReady", "sabiCallsReady", "premiumCallsReady"]);
  const mediaRuntimeReady = readRuntimeFlag(runtime, ["messengerMediaReady", "mediaReady", "uploadsReady"]);
  const directoryRuntimeReady = readRuntimeFlag(runtime, ["messengerDirectoryReady", "publicDirectoryReady"]);
  const notificationsRuntimeReady = readRuntimeFlag(runtime, ["messengerNotificationsReady", "notificationFoundationReady", "pushReady"]);

  return [
    {
      key: "messenger_api_mount",
      title: "Messenger API",
      status: messengerApiReady ? "ok" as const : "warning" as const,
      severity: messengerApiReady ? "info" as const : "warning" as const,
      message: messengerApiReady
        ? "Messenger and independent calls backend routes are mounted and visible to Admin runtime."
        : "Admin can monitor Messenger, but final launch readiness still requires live backend route verification.",
      metadata: { expectedRoutes: ["/api/v2/messenger", "/api/v2/calls"], runtimeKeys: Object.keys(runtime).slice(0, 40), runtimeApiMounted: messengerApiReady },
    },
    {
      key: "messenger_realtime",
      title: "Realtime / presence",
      status: computeMessengerCheckStatus(messengerRealtimeRuntimeReady),
      severity: messengerRealtimeRuntimeReady === true ? "info" as const : "critical" as const,
      message: messengerRealtimeRuntimeReady === true
        ? "Messenger realtime transport is attached through kernel; two-device mobile verification remains the final manual launch proof."
        : "Presence, typing, delivered/read and cross-device realtime must pass two-device verification.",
      metadata: { required: ["presence", "typing", "delivered", "read", "two_device_test"], runtimeVerified: messengerRealtimeRuntimeReady === true },
    },
    {
      key: "messenger_calls",
      title: "Calls",
      status: computeMessengerCheckStatus(callsRuntimeReady),
      severity: callsRuntimeReady === true ? "info" as const : "critical" as const,
      message: callsRuntimeReady === true
        ? "Independent Sabi Calls runtime is mounted and owns calls separately from legacy Messenger calls."
        : "Audio/video calls must be verified from independent calls subsystem, not legacy Messenger calls.",
      metadata: { required: ["incoming_overlay", "accept_decline", "ringback", "audio_route", "video_stream", "hangup_sync"], runtimeVerified: callsRuntimeReady === true },
    },
    {
      key: "messenger_media_pipeline",
      title: "Media pipeline",
      status: computeMessengerCheckStatus(mediaRuntimeReady),
      severity: mediaRuntimeReady === true ? "info" as const : "warning" as const,
      message: mediaRuntimeReady === true
        ? "Messenger media/upload route is mounted; black-screen playback must still be checked on real mobile devices."
        : "Documents, photo/video, audio messages and video bubbles must not produce black screens or fake uploads.",
      metadata: { storageProviders: storageProviders.map((item) => ({ key: item.key, status: item.status, missingFields: item.missingFields })), runtimeVerified: mediaRuntimeReady === true },
    },
    {
      key: "messenger_groups_channels_bots",
      title: "Groups / channels / bots",
      status: computeMessengerCheckStatus(directoryRuntimeReady),
      severity: directoryRuntimeReady === true ? "info" as const : "warning" as const,
      message: directoryRuntimeReady === true
        ? "Groups, channels and bots directory runtime is enabled for Profile/Admin ownership and Messenger search/listing."
        : "Groups, channels and bots should be created from Profile/Admin ownership and surfaced in Messenger search/listing.",
      metadata: { publicByDefault: directoryControl.settings.publicByDefault, businessAccountHiddenForNow: directoryControl.settings.businessAccountHidden, botsPremiumOnly: directoryControl.settings.botsPremiumOnly, activeRestrictions: activeDirectoryRestrictions.length, runtimeVerified: directoryRuntimeReady === true },
    },
    {
      key: "messenger_ai_translation",
      title: "AI translation",
      status: aiProviders.some((item) => item.status === "ready") ? "ok" as const : "not_configured" as const,
      severity: "warning" as const,
      message: "Paid AI translation requires real provider configuration. Fake translation must stay disabled.",
      metadata: { providers: aiProviders.map((item) => ({ key: item.key, status: item.status, missingFields: item.missingFields })) },
    },
    {
      key: "messenger_push_notifications",
      title: "Notifications",
      status: pushProviders.some((item) => item.status === "ready") || notificationsRuntimeReady === true ? "ok" as const : "warning" as const,
      severity: pushProviders.some((item) => item.status === "ready") || notificationsRuntimeReady === true ? "info" as const : "warning" as const,
      message: pushProviders.some((item) => item.status === "ready")
        ? "Push provider is configured for Messenger notifications."
        : notificationsRuntimeReady === true
          ? "Notification foundation is connected; external push provider can stay provider-not-configured until real keys are added."
          : "Unread messages, missed calls and critical Messenger alerts should be connected to notification foundation.",
      metadata: { providers: pushProviders.map((item) => ({ key: item.key, status: item.status, missingFields: item.missingFields })), runtimeVerified: notificationsRuntimeReady === true },
    },
    {
      key: "messenger_risk_signals",
      title: "Risk signals",
      status: riskSignals.some((item) => item.severity === "critical" && item.status !== "resolved") ? "blocked" as const : riskSignals.length ? "warning" as const : "ok" as const,
      severity: "medium" as const,
      message: "Messenger moderation and safety signals should be visible in Admin before publication.",
      metadata: { signals: riskSignals.length, activeLocks: activeLocks.map((lock) => ({ id: lock.id, scope: lock.scope, title: lock.title })) },
    },
    {
      key: "messenger_premium_controls",
      title: "Messenger premium controls",
      status: readMessengerModerationControlState().premiumSettings.coinPaymentsRequired ? "ok" as const : "warning" as const,
      severity: readMessengerModerationControlState().premiumSettings.coinPaymentsRequired ? "info" as const : "warning" as const,
      message: readMessengerModerationControlState().premiumSettings.coinPaymentsRequired ? "Premium Messenger paid features require COIN routing." : "Premium Messenger controls should require COIN routing before launch.",
      metadata: { premiumSettings: readMessengerModerationControlState().premiumSettings },
    },
    {
      key: "messenger_moderation_queue",
      title: "Messenger moderation queue",
      status: buildMessengerModerationDashboard().summary.criticalReports > 0 ? "blocked" as const : buildMessengerModerationDashboard().summary.openReports > 0 ? "warning" as const : "ok" as const,
      severity: buildMessengerModerationDashboard().summary.criticalReports > 0 ? "critical" as const : buildMessengerModerationDashboard().summary.openReports > 0 ? "warning" as const : "info" as const,
      message: buildMessengerModerationDashboard().summary.criticalReports > 0 ? "Critical Messenger reports require owner/security review." : buildMessengerModerationDashboard().summary.openReports > 0 ? "Open Messenger reports require admin review." : "Messenger moderation queue is clear.",
      metadata: buildMessengerModerationDashboard().summary,
    },
    {
      key: "messenger_admin_audit",
      title: "Admin audit",
      status: "ok" as const,
      severity: "info" as const,
      message: "Messenger admin center actions are recorded in immutable audit.",
      metadata: { recentMessengerAudit: recentMessengerAudit.length },
    },
  ];
}


function buildMessengerAdmin100DiagnosticsFromSnapshot(snapshot: Record<string, unknown>): Array<{ key: string; title: string; status: AdminMessengerStatus; severity: string; message: string; metadata?: Record<string, unknown> }> {
  const sectionsRaw = snapshot["sections"];
  const sections = sectionsRaw && typeof sectionsRaw === "object" ? sectionsRaw as Record<string, unknown> : {};
  const failuresRaw = snapshot["failures"];
  const failures = Array.isArray(failuresRaw) ? failuresRaw.filter((item): item is Record<string, unknown> => Boolean(item) && typeof item === "object") : [];
  const status = failures.length ? "warning" as const : "ok" as const;
  const sectionKeys = Object.keys(sections);
  const generatedAt = typeof snapshot["generatedAt"] === "string" ? snapshot["generatedAt"] : new Date().toISOString();
  const elapsedMs = typeof snapshot["elapsedMs"] === "number" ? snapshot["elapsedMs"] : undefined;
  const normalizedKey = (value: unknown) => String(value || "unknown").replace(/[^a-zA-Z0-9_:-]+/g, "_").slice(0, 80);

  const checks: Array<{ key: string; title: string; status: AdminMessengerStatus; severity: string; message: string; metadata?: Record<string, unknown> }> = [{
    key: "admin_100_runtime_snapshot",
    title: "Admin Messenger 100 runtime snapshot",
    status,
    severity: failures.length ? "warning" as const : "info" as const,
    message: failures.length
      ? `Admin Messenger 100 snapshot is connected but ${failures.length} section(s) are degraded. This is now visible as readiness data, not a fake success.`
      : "Admin Messenger 100 snapshot is connected and all registered sections responded.",
    metadata: {
      status: snapshot["status"],
      sections: sectionKeys.length,
      failures: failures.length,
      elapsedMs,
      generatedAt,
      adminControlled: true,
      rawContentIncluded: false,
    },
  }];

  for (const failure of failures.slice(0, 60)) {
    const label = failure["label"] ?? failure["path"] ?? "section";
    const httpStatus = typeof failure["status"] === "number" ? failure["status"] : 0;
    checks.push({
      key: `admin_100_section_${normalizedKey(label)}`,
      title: `Admin Messenger section: ${String(label)}`,
      status: httpStatus >= 500 ? "warning" as const : "blocked" as const,
      severity: httpStatus >= 500 ? "warning" as const : "critical" as const,
      message: `Section responded as degraded instead of blocking Admin UI: ${String(failure["error"] ?? "unknown_error")}`,
      metadata: {
        ...failure,
        adminControlled: true,
        rawContentIncluded: false,
      },
    });
  }

  return checks;
}

function buildMessengerAdminDiagnosticsReadinessReport(diagnostics: Array<{ status: string; severity: string; key: string }>, admin100Snapshot: Record<string, unknown>, center: ReturnType<typeof buildMessengerAdminCenter>) {
  const sectionsRaw = admin100Snapshot["sections"];
  const failuresRaw = admin100Snapshot["failures"];
  const sections = sectionsRaw && typeof sectionsRaw === "object" ? sectionsRaw as Record<string, unknown> : {};
  const failures = Array.isArray(failuresRaw) ? failuresRaw.filter((item): item is Record<string, unknown> => Boolean(item) && typeof item === "object") : [];
  const blocked = diagnostics.filter((item) => item.status === "blocked" || item.status === "not_configured").length;
  const warnings = diagnostics.filter((item) => item.status === "warning").length;
  const passed = diagnostics.filter((item) => item.status === "ok").length;
  const status = blocked > 0 ? "blocked" : warnings > 0 || failures.length > 0 ? "warning" : "ready";

  return {
    ok: true,
    status,
    launchReady: status === "ready" && center.readiness.ready,
    summary: {
      checks: diagnostics.length,
      passed,
      warnings,
      blockers: blocked,
      sections: Object.keys(sections).length,
      degradedSections: failures.length,
      centerStatus: center.readiness.status,
      centerReady: center.readiness.ready,
    },
    failures: failures.map((item) => ({
      label: item["label"],
      path: item["path"],
      status: item["status"],
      error: item["error"],
    })),
    generatedAt: new Date().toISOString(),
    adminControlled: true,
    rawContentIncluded: false,
  };
}


function buildMessengerAdmin100FinalGate(diagnostics: Array<{ status: string; severity: string; key: string; title?: string; message?: string }>, admin100Snapshot: Record<string, unknown>, center: ReturnType<typeof buildMessengerAdminCenter>, prelaunchGate: AdminMessengerSafetyPrelaunchReadinessGateSnapshot, launchCommand: AdminMessengerSafetyLaunchCommandSnapshot, directoryReviewQueue: { count?: number; entries?: unknown[]; items?: unknown[] }) {
  const sectionsRaw = admin100Snapshot["sections"];
  const sections = sectionsRaw && typeof sectionsRaw === "object" ? sectionsRaw as Record<string, unknown> : {};
  const failuresRaw = admin100Snapshot["failures"];
  const failures = Array.isArray(failuresRaw) ? failuresRaw.filter((item): item is Record<string, unknown> => Boolean(item) && typeof item === "object") : [];
  const blockedDiagnostics = diagnostics.filter((item) => item.status === "blocked" || item.status === "not_configured");
  const warningDiagnostics = diagnostics.filter((item) => item.status === "warning");
  const passedDiagnostics = diagnostics.filter((item) => item.status === "ok");
  const prelaunchBlocked = Boolean(prelaunchGate.summary.launchBlocked || prelaunchGate.summary.blockingChecks > 0);
  const launchBlocked = !Boolean(launchCommand.summary.canLaunch);
  const queueCount = typeof directoryReviewQueue.count === "number"
    ? directoryReviewQueue.count
    : Array.isArray(directoryReviewQueue.entries)
      ? directoryReviewQueue.entries.length
      : Array.isArray(directoryReviewQueue.items)
        ? directoryReviewQueue.items.length
        : 0;

  const blockers: Array<Record<string, unknown>> = [];
  const warnings: Array<Record<string, unknown>> = [];

  for (const item of blockedDiagnostics) {
    blockers.push({
      key: item.key,
      title: item.title ?? item.key,
      source: "diagnostics",
      status: item.status,
      severity: item.severity,
      message: item.message ?? "diagnostic_blocker",
    });
  }

  for (const failure of failures.slice(0, 80)) {
    const httpStatus = typeof failure["status"] === "number" ? failure["status"] : 0;
    const target = httpStatus >= 500 ? warnings : blockers;
    target.push({
      key: `section_${String(failure["label"] ?? failure["path"] ?? "unknown")}`,
      title: String(failure["label"] ?? failure["path"] ?? "Admin Messenger section"),
      source: "admin_100_snapshot",
      status: httpStatus >= 500 ? "degraded" : "blocked",
      httpStatus,
      message: String(failure["error"] ?? "section_degraded"),
      path: failure["path"],
    });
  }

  if (prelaunchBlocked) {
    for (const item of prelaunchGate.blockers.slice(0, 80)) {
      blockers.push({
        key: item.key,
        title: item.title,
        source: "prelaunch_gate",
        status: item.status,
        message: item.reason,
        ownerOnly: item.ownerOnly,
        requiredBeforeLaunch: item.requiredBeforeLaunch,
      });
    }
  }

  if (launchBlocked) {
    for (const item of launchCommand.blockedItems.slice(0, 80)) {
      blockers.push({
        key: item.key,
        title: item.title,
        source: "launch_command",
        status: item.status,
        message: item.reason,
        ownerOnly: item.ownerOnly,
        requiredBeforePublication: item.requiredBeforePublication,
      });
    }
  }

  for (const item of warningDiagnostics.slice(0, 80)) {
    warnings.push({
      key: item.key,
      title: item.title ?? item.key,
      source: "diagnostics",
      status: item.status,
      severity: item.severity,
      message: item.message ?? "diagnostic_warning",
    });
  }

  for (const item of prelaunchGate.warnings.slice(0, 80)) {
    warnings.push({
      key: item.key,
      title: item.title,
      source: "prelaunch_gate",
      status: item.status,
      message: item.reason,
      ownerOnly: item.ownerOnly,
      requiredBeforeLaunch: item.requiredBeforeLaunch,
    });
  }

  for (const item of launchCommand.ownerRequiredItems.slice(0, 80)) {
    warnings.push({
      key: item.key,
      title: item.title,
      source: "launch_command_owner_required",
      status: item.status,
      message: item.reason,
      ownerOnly: item.ownerOnly,
      requiredBeforePublication: item.requiredBeforePublication,
    });
  }

  if (queueCount > 0) {
    warnings.push({
      key: "directory_review_queue_not_empty",
      title: "directory_review_queue_not_empty",
      source: "directory_review_queue",
      status: "warning",
      message: "directory_review_queue_has_items_for_admin_review",
      count: queueCount,
    });
  }

  const totalChecks = diagnostics.length + prelaunchGate.checks.length + launchCommand.commandItems.length + Math.max(Object.keys(sections).length, 1);
  const blockedCount = blockers.length;
  const warningCount = warnings.length;
  const passedCount = passedDiagnostics.length + prelaunchGate.summary.passedChecks + launchCommand.readyItems.length;
  const readinessScorePct = Math.max(0, Math.min(100, Math.round((passedCount / Math.max(totalChecks, 1)) * 100)));
  const status = blockedCount > 0 ? "blocked" : warningCount > 0 ? "warning" : "ready";
  const launchReady = status === "ready" && center.readiness.ready && !prelaunchBlocked && !launchBlocked && failures.length === 0;

  return {
    ok: true,
    status,
    launchReady,
    command: launchReady ? "launch_allowed" : "launch_blocked",
    summary: {
      readinessScorePct,
      totalChecks,
      passedChecks: passedCount,
      warningChecks: warningCount,
      blockingChecks: blockedCount,
      diagnostics: diagnostics.length,
      admin100Sections: Object.keys(sections).length,
      degradedSections: failures.length,
      directoryReviewItems: queueCount,
      centerStatus: center.readiness.status,
      centerReady: center.readiness.ready,
      prelaunchStatus: prelaunchGate.summary.launchStatus,
      prelaunchBlocked,
      launchCommandStatus: launchCommand.summary.commandStatus,
      launchCommandCanLaunch: launchCommand.summary.canLaunch,
    },
    blockers,
    warnings,
    generatedAt: new Date().toISOString(),
    adminControlled: true,
    rawContentIncluded: false,
  };
}

function buildMessengerAdmin100FinalGateDiagnostics(finalGate: ReturnType<typeof buildMessengerAdmin100FinalGate>): Array<{ key: string; title: string; status: AdminMessengerStatus; severity: string; message: string; metadata?: Record<string, unknown> }> {
  return [
    {
      key: "admin_100_final_gate",
      title: "Admin Messenger 100 final gate",
      status: finalGate.status === "ready" ? "ok" as const : finalGate.status === "warning" ? "warning" as const : "blocked" as const,
      severity: finalGate.status === "ready" ? "info" : finalGate.status === "warning" ? "warning" : "critical",
      message: finalGate.launchReady
        ? "Admin Messenger final gate is ready for owner launch decision."
        : "Admin Messenger final gate is not launch-ready. Review blockers and warnings before publication.",
      metadata: finalGate.summary,
    },
    {
      key: "admin_100_launch_command_gate",
      title: "Admin Messenger launch command gate",
      status: finalGate.launchReady ? "ok" as const : "blocked" as const,
      severity: finalGate.launchReady ? "info" : "critical",
      message: finalGate.launchReady ? "Launch command can proceed." : "Launch command is blocked until Admin Messenger blockers are resolved.",
      metadata: {
        command: finalGate.command,
        blockers: finalGate.blockers.length,
        warnings: finalGate.warnings.length,
        launchReady: finalGate.launchReady,
        adminControlled: true,
        rawContentIncluded: false,
      },
    },
  ];
}

function buildMessengerAdminCenter(options: AdminModuleOptions, store: AdminFileStore, providerStore: AdminProviderConfigStore) {
  const diagnostics = buildMessengerDiagnostics(options, store, providerStore);
  const control = readMessengerControlState();
  const flags = messengerFeatureFlags(store);
  const autoBlockers = diagnostics.filter((item) => item.status === "blocked" || item.status === "not_configured");
  const manualBlockers = control.launchBlockers.filter((item) => item.status === "active");
  const warnings = diagnostics.filter((item) => item.status === "warning");
  const blockers = [
    ...autoBlockers.map((item) => ({ key: item.key, title: item.title, status: item.status, message: item.message, severity: item.severity, source: "diagnostic" as const })),
    ...manualBlockers.map((item) => ({ key: item.key, title: item.title, status: "blocked" as const, message: item.message, severity: item.severity, source: "manual" as const, id: item.id })),
  ];
  const ready = blockers.length === 0 && warnings.length === 0;

  return {
    generatedAt: new Date().toISOString(),
    readiness: {
      status: ready ? "ready" as const : blockers.length ? "blocked" as const : "warning" as const,
      ready,
      blockers: blockers.length,
      warnings: warnings.length,
      checks: diagnostics.length,
      passed: diagnostics.filter((item) => item.status === "ok").length,
    },
    sections: [
      { key: "chat", status: computeMessengerCheckStatus(readRuntimeFlag(runtimeRecord(options), ["messengerChatReady", "chatReady"])), title: "Chats", ownerControl: true },
      { key: "realtime", status: diagnostics.find((item) => item.key === "messenger_realtime")?.status ?? "warning", title: "Realtime", ownerControl: true },
      { key: "calls", status: diagnostics.find((item) => item.key === "messenger_calls")?.status ?? "warning", title: "Calls", ownerControl: true },
      { key: "media", status: diagnostics.find((item) => item.key === "messenger_media_pipeline")?.status ?? "warning", title: "Media", ownerControl: true },
      { key: "groups_channels_bots", status: diagnostics.find((item) => item.key === "messenger_groups_channels_bots")?.status ?? "warning", title: "Groups / Channels / Bots", ownerControl: true },
      { key: "ai_translation", status: diagnostics.find((item) => item.key === "messenger_ai_translation")?.status ?? "not_configured", title: "AI translation", ownerControl: true },
      { key: "notifications", status: diagnostics.find((item) => item.key === "messenger_push_notifications")?.status ?? "warning", title: "Notifications", ownerControl: true },
      { key: "moderation", status: diagnostics.find((item) => item.key === "messenger_risk_signals")?.status ?? "ok", title: "Moderation", ownerControl: true },
      { key: "premium_controls", status: diagnostics.find((item) => item.key === "messenger_premium_controls")?.status ?? "warning", title: "Premium controls", ownerControl: true },
      { key: "moderation_queue", status: diagnostics.find((item) => item.key === "messenger_moderation_queue")?.status ?? "ok", title: "Moderation queue", ownerControl: true },
    ],
    diagnostics,
    featureFlags: flags,
    control: {
      featureFlags: control.featureFlags,
      launchBlockers: control.launchBlockers,
      updatedAt: control.updatedAt,
    },
    launchBlockers: blockers.map((item) => ({ ...item })),
    adminRules: [
      "admin_controls_messenger_without_owning_business_logic",
      "messenger_runtime_stays_in_kernel_and_backend_services",
      "no_direct_socket_usage_from_admin_ui",
      "calls_must_use_independent_calls_subsystem_not_legacy_messenger_calls",
      "ai_translation_requires_real_provider_or_provider_not_configured",
      "all_messenger_admin_actions_are_audited",
      "messenger_premium_and_moderation_are_controlled_from_admin",
    ],
  };
}


type AdminMessengerMaxPrelaunchGateManualStatus = "pending" | "verified" | "blocked" | "waived";
type AdminMessengerMaxPrelaunchStatus = "ready" | "warning" | "blocked" | "not_configured";

type AdminMessengerMaxPrelaunchStoredGate = {
  key: string;
  manualStatus: AdminMessengerMaxPrelaunchGateManualStatus;
  note?: string;
  verifiedBy?: string;
  verifiedAt?: string;
  blockedBy?: string;
  blockedAt?: string;
  waivedBy?: string;
  waivedAt?: string;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerMaxPrelaunchSettings = {
  requireOwnerGoLiveApproval: boolean;
  requireNoBlockedFinalReadiness: boolean;
  requireTwoDeviceRealtimeProof: boolean;
  requirePublicDirectoryReady: boolean;
  requireGrowthPromotionReady: boolean;
  requireGreetingsSafeMode: boolean;
  requireNotificationsReady: boolean;
  requirePresenceReady: boolean;
  requireSafetyGateReady: boolean;
  requireMobileBackendVerificationPlan: boolean;
  rawPrivateContentStorageAllowed: false;
  walletTouched: false;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerMaxPrelaunchState = {
  settings: AdminMessengerMaxPrelaunchSettings;
  gates: AdminMessengerMaxPrelaunchStoredGate[];
  updatedAt: string;
};

type AdminMessengerMaxPrelaunchGate = {
  key: string;
  categoryKey: string;
  titleKey: string;
  detailKey: string;
  status: AdminMessengerMaxPrelaunchStatus;
  manualStatus: AdminMessengerMaxPrelaunchGateManualStatus;
  required: boolean;
  ownerRequired: boolean;
  scorePct: number;
  blockers: number;
  warnings: number;
  sourceKey: string;
  lastVerifiedBy?: string;
  lastVerifiedAt?: string;
  note?: string;
  evidenceHash: string;
  traceHash: string;
};

type AdminMessengerMaxPrelaunchSnapshot = {
  ok: true;
  centerVersion: "messenger-max-prelaunch-control-v1";
  generatedAt: string;
  generatedBy: string;
  rawContentIncluded: false;
  settings: AdminMessengerMaxPrelaunchSettings;
  summary: {
    totalGates: number;
    requiredGates: number;
    readyGates: number;
    warningGates: number;
    blockedGates: number;
    notConfiguredGates: number;
    manuallyVerifiedGates: number;
    manuallyBlockedGates: number;
    waivedGates: number;
    maxReadinessPct: number;
    goLiveAllowed: boolean;
    ownerGoLiveApprovalRequired: boolean;
    healthStatus: AdminMessengerMaxPrelaunchStatus;
    walletTouched: false;
  };
  gates: AdminMessengerMaxPrelaunchGate[];
  blockers: AdminMessengerMaxPrelaunchGate[];
  warnings: AdminMessengerMaxPrelaunchGate[];
  categories: Array<{ key: string; total: number; ready: number; blocked: number; warning: number; notConfigured: number; progressPct: number }>;
  charts: {
    readinessLanes: Array<{ key: string; status: AdminMessengerMaxPrelaunchStatus; scorePct: number; blockers: number; warnings: number }>;
    categoryProgress: Array<{ label: string; value: number; ready: number; blocked: number; warning: number; notConfigured: number; progressPct: number }>;
    operationalFocus: Array<{ label: string; value: number; status: AdminMessengerMaxPrelaunchStatus }>;
  };
  rules: string[];
  nextRequiredSteps: string[];
  sourceQuality: {
    finalReadinessConnected: boolean;
    dashboardConnected: boolean;
    presenceConnected: boolean;
    notificationsConnected: boolean;
    directoryConnected: boolean;
    growthConnected: boolean;
    contentQualityConnected: boolean;
    safetyGateConnected: boolean;
    rawContentIncluded: false;
    walletTouched: false;
  };
  traceHash: string;
};

const ADMIN_MESSENGER_MAX_PRELAUNCH_FILE = path.join(process.cwd(), ".data", "admin", "messenger-max-prelaunch.json");

function createMessengerMaxPrelaunchTraceHash(value: unknown): string {
  return crypto.createHash("sha256").update(JSON.stringify(value)).digest("hex");
}

function defaultMessengerMaxPrelaunchSettings(): AdminMessengerMaxPrelaunchSettings {
  const now = new Date().toISOString();
  return {
    requireOwnerGoLiveApproval: true,
    requireNoBlockedFinalReadiness: true,
    requireTwoDeviceRealtimeProof: true,
    requirePublicDirectoryReady: true,
    requireGrowthPromotionReady: true,
    requireGreetingsSafeMode: true,
    requireNotificationsReady: true,
    requirePresenceReady: true,
    requireSafetyGateReady: true,
    requireMobileBackendVerificationPlan: true,
    rawPrivateContentStorageAllowed: false,
    walletTouched: false,
    updatedBy: "system",
    updatedAt: now,
  };
}

function normalizeMessengerMaxPrelaunchSettings(value: unknown): AdminMessengerMaxPrelaunchSettings {
  const defaults = defaultMessengerMaxPrelaunchSettings();
  const source = value && typeof value === "object" ? (value as Record<string, unknown>) : {};
  return {
    requireOwnerGoLiveApproval: readBoolean(source.requireOwnerGoLiveApproval, defaults.requireOwnerGoLiveApproval),
    requireNoBlockedFinalReadiness: readBoolean(source.requireNoBlockedFinalReadiness, defaults.requireNoBlockedFinalReadiness),
    requireTwoDeviceRealtimeProof: readBoolean(source.requireTwoDeviceRealtimeProof, defaults.requireTwoDeviceRealtimeProof),
    requirePublicDirectoryReady: readBoolean(source.requirePublicDirectoryReady, defaults.requirePublicDirectoryReady),
    requireGrowthPromotionReady: readBoolean(source.requireGrowthPromotionReady, defaults.requireGrowthPromotionReady),
    requireGreetingsSafeMode: readBoolean(source.requireGreetingsSafeMode, defaults.requireGreetingsSafeMode),
    requireNotificationsReady: readBoolean(source.requireNotificationsReady, defaults.requireNotificationsReady),
    requirePresenceReady: readBoolean(source.requirePresenceReady, defaults.requirePresenceReady),
    requireSafetyGateReady: readBoolean(source.requireSafetyGateReady, defaults.requireSafetyGateReady),
    requireMobileBackendVerificationPlan: readBoolean(source.requireMobileBackendVerificationPlan, defaults.requireMobileBackendVerificationPlan),
    rawPrivateContentStorageAllowed: false,
    walletTouched: false,
    updatedBy: readString(source.updatedBy) ?? defaults.updatedBy,
    updatedAt: readString(source.updatedAt) ?? defaults.updatedAt,
  };
}

function normalizeMessengerMaxPrelaunchStoredGate(value: unknown): AdminMessengerMaxPrelaunchStoredGate | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const key = readString(source.key);
  if (!key) return null;
  const rawStatus = readString(source.manualStatus) ?? "pending";
  const manualStatus: AdminMessengerMaxPrelaunchGateManualStatus = rawStatus === "verified" || rawStatus === "blocked" || rawStatus === "waived" ? rawStatus : "pending";
  const now = new Date().toISOString();
  return {
    key,
    manualStatus,
    note: readString(source.note),
    verifiedBy: readString(source.verifiedBy),
    verifiedAt: readString(source.verifiedAt),
    blockedBy: readString(source.blockedBy),
    blockedAt: readString(source.blockedAt),
    waivedBy: readString(source.waivedBy),
    waivedAt: readString(source.waivedAt),
    updatedBy: readString(source.updatedBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? now,
  };
}

function defaultMessengerMaxPrelaunchState(): AdminMessengerMaxPrelaunchState {
  return { settings: defaultMessengerMaxPrelaunchSettings(), gates: [], updatedAt: new Date().toISOString() };
}

function readMessengerMaxPrelaunchState(): AdminMessengerMaxPrelaunchState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_MAX_PRELAUNCH_FILE)) return defaultMessengerMaxPrelaunchState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_MAX_PRELAUNCH_FILE, "utf8")) as Partial<AdminMessengerMaxPrelaunchState>;
    return {
      settings: normalizeMessengerMaxPrelaunchSettings(parsed.settings),
      gates: Array.isArray(parsed.gates) ? parsed.gates.map(normalizeMessengerMaxPrelaunchStoredGate).filter((item): item is AdminMessengerMaxPrelaunchStoredGate => Boolean(item)) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerMaxPrelaunchState();
  }
}

function writeMessengerMaxPrelaunchState(state: AdminMessengerMaxPrelaunchState): AdminMessengerMaxPrelaunchState {
  const next = { ...state, settings: normalizeMessengerMaxPrelaunchSettings(state.settings), updatedAt: new Date().toISOString() };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_MAX_PRELAUNCH_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_MAX_PRELAUNCH_FILE, JSON.stringify(next, null, 2));
  return next;
}

function maxPrelaunchStatusFrom(params: { blocked: boolean; warning: boolean; notConfigured?: boolean }): AdminMessengerMaxPrelaunchStatus {
  if (params.blocked) return "blocked";
  if (params.notConfigured) return "not_configured";
  if (params.warning) return "warning";
  return "ready";
}

function createMessengerMaxPrelaunchGate(input: {
  key: string;
  categoryKey: string;
  titleKey: string;
  detailKey: string;
  status: AdminMessengerMaxPrelaunchStatus;
  required?: boolean;
  ownerRequired?: boolean;
  scorePct: number;
  blockers?: number;
  warnings?: number;
  sourceKey: string;
}, manual: Map<string, AdminMessengerMaxPrelaunchStoredGate>): AdminMessengerMaxPrelaunchGate {
  const saved = manual.get(input.key);
  const manualStatus = saved?.manualStatus ?? "pending";
  const status: AdminMessengerMaxPrelaunchStatus = manualStatus === "blocked" ? "blocked" : manualStatus === "waived" && input.status === "blocked" ? "warning" : input.status;
  const evidenceHash = createMessengerMaxPrelaunchTraceHash({ key: input.key, status: input.status, manualStatus, sourceKey: input.sourceKey, scorePct: input.scorePct });
  return {
    key: input.key,
    categoryKey: input.categoryKey,
    titleKey: input.titleKey,
    detailKey: input.detailKey,
    status,
    manualStatus,
    required: input.required ?? true,
    ownerRequired: input.ownerRequired ?? false,
    scorePct: Math.max(0, Math.min(100, Math.round(input.scorePct))),
    blockers: input.blockers ?? 0,
    warnings: input.warnings ?? 0,
    sourceKey: input.sourceKey,
    lastVerifiedBy: saved?.verifiedBy,
    lastVerifiedAt: saved?.verifiedAt,
    note: saved?.note,
    evidenceHash,
    traceHash: createMessengerMaxPrelaunchTraceHash({ key: input.key, evidenceHash, updatedAt: saved?.updatedAt ?? "system" }),
  };
}

async function buildMessengerMaxPrelaunchSnapshot(options: AdminModuleOptions, req: AdminRequest, store: AdminFileStore, providerStore: AdminProviderConfigStore): Promise<AdminMessengerMaxPrelaunchSnapshot> {
  const state = readMessengerMaxPrelaunchState();
  const manual = new Map(state.gates.map((item) => [item.key, item]));
  const generatedAt = new Date().toISOString();
  const dashboard = await buildMessengerProMonitoringDashboard(options, req, store, providerStore);
  const finalReadiness = await buildMessengerFinalReadinessSnapshot(options, req, store, providerStore);
  const presence = await buildMessengerPresenceOperationsSnapshot(options, req, store);
  const notifications = await buildMessengerNotificationsMonitorSnapshot(options, req);
  const directory = await buildMessengerDirectoryPromotionSnapshot(options);
  const approval = await buildMessengerApprovalVisibilitySnapshot(options);
  const growth = await buildMessengerGrowthAnalyticsSnapshot(options, req, store, providerStore);
  const growthPromotion = await buildMessengerGrowthPromotionGreetingSnapshot(options, req, store, providerStore);
  const contentQuality = await buildMessengerContentQualitySnapshot(options, req, store, providerStore);
  const safetyGate = buildMessengerSafetyPrelaunchReadinessGateSnapshot(req, store);
  const launchCommand = buildMessengerSafetyLaunchCommandSnapshot(req, store);

  const gates: AdminMessengerMaxPrelaunchGate[] = [];
  const push = (item: Parameters<typeof createMessengerMaxPrelaunchGate>[0]) => gates.push(createMessengerMaxPrelaunchGate(item, manual));

  push({
    key: "overall_dashboard",
    categoryKey: "dashboard",
    titleKey: "messenger.max.gate.overallDashboard.title",
    detailKey: "messenger.max.gate.overallDashboard.detail",
    status: maxPrelaunchStatusFrom({ blocked: dashboard.summary.readinessStatus === "blocked", warning: dashboard.summary.readinessStatus === "warning" || dashboard.summary.readinessScorePct < 80, notConfigured: dashboard.summary.totalUsers <= 0 }),
    scorePct: dashboard.summary.readinessScorePct,
    blockers: dashboard.summary.launchBlockers,
    warnings: dashboard.summary.warnings,
    sourceKey: "overview",
  });

  push({
    key: "final_readiness",
    categoryKey: "readiness",
    titleKey: "messenger.max.gate.finalReadiness.title",
    detailKey: "messenger.max.gate.finalReadiness.detail",
    status: maxPrelaunchStatusFrom({ blocked: state.settings.requireNoBlockedFinalReadiness && finalReadiness.summary.blockedItems > 0, warning: finalReadiness.summary.warningItems > 0 || !finalReadiness.summary.launchReady, notConfigured: finalReadiness.summary.notConfiguredItems > 0 }),
    scorePct: finalReadiness.summary.readinessScorePct,
    blockers: finalReadiness.summary.blockedItems,
    warnings: finalReadiness.summary.warningItems + finalReadiness.summary.notConfiguredItems,
    sourceKey: "finalReadiness",
    ownerRequired: true,
  });

  push({
    key: "presence_realtime",
    categoryKey: "realtime",
    titleKey: "messenger.max.gate.presenceRealtime.title",
    detailKey: "messenger.max.gate.presenceRealtime.detail",
    status: maxPrelaunchStatusFrom({ blocked: state.settings.requirePresenceReady && presence.summary.realtimeHealth === "blocked", warning: presence.summary.realtimeHealth === "warning" || presence.summary.suspiciousStates > 0, notConfigured: presence.summary.realtimeHealth === "not_configured" }),
    scorePct: presence.summary.presenceReadinessPct,
    blockers: presence.anomalies.filter((item) => item.status !== "resolved" && item.severity === "critical").length,
    warnings: presence.summary.suspiciousStates,
    sourceKey: "presence",
  });

  push({
    key: "notifications_missed",
    categoryKey: "delivery",
    titleKey: "messenger.max.gate.notificationsMissed.title",
    detailKey: "messenger.max.gate.notificationsMissed.detail",
    status: maxPrelaunchStatusFrom({ blocked: state.settings.requireNotificationsReady && notifications.summary.healthStatus === "blocked", warning: notifications.summary.healthStatus === "warning" || notifications.summary.issueBacklog > 0, notConfigured: notifications.summary.healthStatus === "not_configured" }),
    scorePct: notifications.summary.notificationReadinessPct,
    blockers: notifications.issues.filter((item) => item.status !== "resolved" && item.severity === "critical").length,
    warnings: notifications.summary.issueBacklog,
    sourceKey: "notifications",
  });

  push({
    key: "public_directory",
    categoryKey: "directory",
    titleKey: "messenger.max.gate.publicDirectory.title",
    detailKey: "messenger.max.gate.publicDirectory.detail",
    status: maxPrelaunchStatusFrom({ blocked: false, warning: directory.summary.pendingApproval > 0 || directory.summary.lowQualityEntries > 0 || approval.summary.safetyReviewRequired > 0, notConfigured: !directory.summary.directoryDatabaseConnected }),
    scorePct: approval.summary.governanceScore,
    blockers: approval.summary.restrictedEntries,
    warnings: directory.summary.pendingApproval + directory.summary.lowQualityEntries + approval.summary.safetyReviewRequired,
    sourceKey: "directory",
  });

  push({
    key: "growth_promotion",
    categoryKey: "growth",
    titleKey: "messenger.max.gate.growthPromotion.title",
    detailKey: "messenger.max.gate.growthPromotion.detail",
    status: maxPrelaunchStatusFrom({ blocked: false, warning: state.settings.requireGrowthPromotionReady && (growth.summary.dataConfidencePct < 55 || growth.summary.promotionHealth === "not_configured"), notConfigured: growth.summary.dataConfidencePct < 40 }),
    scorePct: growth.summary.dataConfidencePct,
    blockers: 0,
    warnings: growth.summary.promotionHealth === "not_configured" ? 1 : 0,
    sourceKey: "growth",
  });

  push({
    key: "greetings_safety",
    categoryKey: "growth",
    titleKey: "messenger.max.gate.greetingsSafety.title",
    detailKey: "messenger.max.gate.greetingsSafety.detail",
    status: maxPrelaunchStatusFrom({ blocked: false, warning: state.settings.requireGreetingsSafeMode && growthPromotion.summary.pendingGreetingApprovals > 0, notConfigured: growthPromotion.greetingTemplates.length <= 0 }),
    scorePct: growthPromotion.summary.readinessScorePct,
    blockers: 0,
    warnings: growthPromotion.summary.pendingGreetingApprovals + 0 + 0,
    sourceKey: "greetings",
  });

  push({
    key: "content_antispam",
    categoryKey: "safety",
    titleKey: "messenger.max.gate.contentAntispam.title",
    detailKey: "messenger.max.gate.contentAntispam.detail",
    status: maxPrelaunchStatusFrom({ blocked: contentQuality.summary.highRiskSignals > 0, warning: contentQuality.summary.reviewBacklog > 0 || contentQuality.summary.spamGuardCoveragePct < 90, notConfigured: contentQuality.summary.spamGuardCoveragePct < 50 }),
    scorePct: contentQuality.summary.qualityScore,
    blockers: contentQuality.summary.highRiskSignals,
    warnings: contentQuality.summary.reviewBacklog,
    sourceKey: "contentQuality",
  });

  push({
    key: "safety_prelaunch_gate",
    categoryKey: "safety",
    titleKey: "messenger.max.gate.safetyPrelaunch.title",
    detailKey: "messenger.max.gate.safetyPrelaunch.detail",
    status: maxPrelaunchStatusFrom({ blocked: state.settings.requireSafetyGateReady && safetyGate.summary.launchBlocked, warning: safetyGate.summary.warningChecks > 0, notConfigured: safetyGate.summary.totalChecks <= 0 }),
    scorePct: percentOf(safetyGate.summary.passedChecks, Math.max(1, safetyGate.summary.totalChecks)),
    blockers: safetyGate.summary.blockingChecks,
    warnings: safetyGate.summary.warningChecks,
    sourceKey: "safetyGate",
    ownerRequired: true,
  });

  push({
    key: "mobile_backend_verification",
    categoryKey: "verification",
    titleKey: "messenger.max.gate.mobileBackend.title",
    detailKey: "messenger.max.gate.mobileBackend.detail",
    status: maxPrelaunchStatusFrom({ blocked: state.settings.requireMobileBackendVerificationPlan && launchCommand.summary.launchBlocked, warning: launchCommand.summary.ownerRequiredCommands > 0 || launchCommand.summary.totalCommands <= 0 }),
    scorePct: percentOf(launchCommand.summary.readyCommands, Math.max(1, launchCommand.summary.totalCommands)),
    blockers: launchCommand.summary.blockedCommands,
    warnings: launchCommand.summary.ownerRequiredCommands,
    sourceKey: "mobileBackend",
    ownerRequired: true,
  });

  const required = gates.filter((item) => item.required && item.manualStatus !== "waived");
  const readyGates = gates.filter((item) => item.status === "ready").length;
  const warningGates = gates.filter((item) => item.status === "warning").length;
  const blockedGates = gates.filter((item) => item.status === "blocked").length;
  const notConfiguredGates = gates.filter((item) => item.status === "not_configured").length;
  const manualVerified = gates.filter((item) => item.manualStatus === "verified").length;
  const maxReadinessPct = percentOf(gates.reduce((sum, item) => sum + item.scorePct, 0), Math.max(1, gates.length * 100));
  const ownerGoLiveApprovalRequired = state.settings.requireOwnerGoLiveApproval && manualVerified < required.length;
  const goLiveAllowed = blockedGates === 0 && notConfiguredGates === 0 && (!ownerGoLiveApprovalRequired) && maxReadinessPct >= 85;
  const healthStatus: AdminMessengerMaxPrelaunchStatus = goLiveAllowed ? "ready" : blockedGates > 0 ? "blocked" : notConfiguredGates > 0 ? "not_configured" : "warning";
  const categories = Array.from(new Set(gates.map((item) => item.categoryKey))).map((key) => {
    const rows = gates.filter((item) => item.categoryKey === key);
    return {
      key,
      total: rows.length,
      ready: rows.filter((item) => item.status === "ready").length,
      blocked: rows.filter((item) => item.status === "blocked").length,
      warning: rows.filter((item) => item.status === "warning").length,
      notConfigured: rows.filter((item) => item.status === "not_configured").length,
      progressPct: percentOf(rows.filter((item) => item.status === "ready").length, Math.max(1, rows.length)),
    };
  });
  return {
    ok: true,
    centerVersion: "messenger-max-prelaunch-control-v1",
    generatedAt,
    generatedBy: req.admin?.id ?? "env-admin",
    rawContentIncluded: false,
    settings: state.settings,
    summary: {
      totalGates: gates.length,
      requiredGates: required.length,
      readyGates,
      warningGates,
      blockedGates,
      notConfiguredGates,
      manuallyVerifiedGates: manualVerified,
      manuallyBlockedGates: gates.filter((item) => item.manualStatus === "blocked").length,
      waivedGates: gates.filter((item) => item.manualStatus === "waived").length,
      maxReadinessPct,
      goLiveAllowed,
      ownerGoLiveApprovalRequired,
      healthStatus,
      walletTouched: false,
    },
    gates,
    blockers: gates.filter((item) => item.status === "blocked" || item.status === "not_configured"),
    warnings: gates.filter((item) => item.status === "warning"),
    categories,
    charts: {
      readinessLanes: gates.map((item) => ({ key: item.key, status: item.status, scorePct: item.scorePct, blockers: item.blockers, warnings: item.warnings })),
      categoryProgress: categories.map((item) => ({ label: item.key, value: item.total, ready: item.ready, blocked: item.blocked, warning: item.warning, notConfigured: item.notConfigured, progressPct: item.progressPct })),
      operationalFocus: [
        { label: "blocked", value: blockedGates, status: blockedGates > 0 ? "blocked" : "ready" },
        { label: "not_configured", value: notConfiguredGates, status: notConfiguredGates > 0 ? "not_configured" : "ready" },
        { label: "warnings", value: warningGates, status: warningGates > 0 ? "warning" : "ready" },
        { label: "manual_verified", value: manualVerified, status: manualVerified >= required.length ? "ready" : "warning" },
      ],
    },
    rules: [
      "messenger_max_prelaunch_does_not_touch_wallet_or_other_modules",
      "messenger_max_prelaunch_uses_metadata_ids_hashes_statuses_and_operational_counts_only",
      "raw_private_messages_media_and_files_must_not_be_saved_in_admin_max_prelaunch",
      "root_owner_final_go_live_confirmation_is_required_before_leaving_messenger_phase",
      "next_major_modules_stay_locked_until_messenger_is_complete",
    ],
    nextRequiredSteps: goLiveAllowed ? ["run_two_device_mobile_backend_messenger_verification"] : ["resolve_blocked_or_not_configured_gates", "verify_required_gates_by_owner_or_responsible_admin", "run_two_device_mobile_backend_messenger_verification"],
    sourceQuality: {
      finalReadinessConnected: finalReadiness.ok === true,
      dashboardConnected: dashboard.ok === true,
      presenceConnected: presence.ok === true,
      notificationsConnected: notifications.ok === true,
      directoryConnected: directory.ok === true,
      growthConnected: growth.ok === true,
      contentQualityConnected: contentQuality.ok === true,
      safetyGateConnected: safetyGate.ok === true,
      rawContentIncluded: false,
      walletTouched: false,
    },
    traceHash: createMessengerMaxPrelaunchTraceHash({ generatedAt, gates: gates.map((item) => ({ key: item.key, status: item.status, manualStatus: item.manualStatus, scorePct: item.scorePct })), settings: state.settings }),
  };
}

function updateMessengerMaxPrelaunchGateStatus(key: string, status: AdminMessengerMaxPrelaunchGateManualStatus, by: string, note?: string): AdminMessengerMaxPrelaunchState {
  const state = readMessengerMaxPrelaunchState();
  const now = new Date().toISOString();
  const existing = state.gates.find((item) => item.key === key);
  const next: AdminMessengerMaxPrelaunchStoredGate = {
    ...(existing ?? { key, manualStatus: "pending" as const, updatedBy: by, updatedAt: now }),
    key,
    manualStatus: status,
    note: note ?? existing?.note,
    verifiedBy: status === "verified" ? by : existing?.verifiedBy,
    verifiedAt: status === "verified" ? now : existing?.verifiedAt,
    blockedBy: status === "blocked" ? by : existing?.blockedBy,
    blockedAt: status === "blocked" ? now : existing?.blockedAt,
    waivedBy: status === "waived" ? by : existing?.waivedBy,
    waivedAt: status === "waived" ? now : existing?.waivedAt,
    updatedBy: by,
    updatedAt: now,
  };
  const gates = state.gates.filter((item) => item.key !== key);
  if (status !== "pending" || note) gates.push(next);
  return writeMessengerMaxPrelaunchState({ ...state, gates });
}


type AdminMessengerRuntimeVerificationManualStatus = "pending" | "verified" | "blocked" | "waived";
type AdminMessengerRuntimeVerificationStatus = "ready" | "warning" | "blocked" | "not_configured";
type AdminMessengerRuntimeVerificationSessionStatus = "draft" | "running" | "passed" | "failed" | "cancelled";

type AdminMessengerRuntimeVerificationStoredItem = {
  key: string;
  manualStatus: AdminMessengerRuntimeVerificationManualStatus;
  note?: string;
  proofRef?: string;
  verifiedBy?: string;
  verifiedAt?: string;
  blockedBy?: string;
  blockedAt?: string;
  waivedBy?: string;
  waivedAt?: string;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerRuntimeVerificationSettings = {
  requireTwoPhysicalDevices: boolean;
  requireUnifiedUserIdProof: boolean;
  requireRealtimePresenceProof: boolean;
  requireChatSendReceiveProof: boolean;
  requireMediaPipelineProof: boolean;
  requireCallsProof: boolean;
  requireNotificationsProof: boolean;
  requirePublicDirectoryProof: boolean;
  requireSafetyAndAntiSpamProof: boolean;
  requireOwnerFinalRuntimeApproval: boolean;
  rawPrivateContentStorageAllowed: false;
  walletTouched: false;
  updatedBy: string;
  updatedAt: string;
};

type AdminMessengerRuntimeVerificationSession = {
  id: string;
  title: string;
  status: AdminMessengerRuntimeVerificationSessionStatus;
  deviceAUserId: string;
  deviceBUserId: string;
  deviceALabel?: string;
  deviceBLabel?: string;
  connectionMode: "lan" | "tunnel" | "production" | "local";
  startedAt: string;
  finishedAt?: string;
  createdBy: string;
  updatedBy: string;
  updatedAt: string;
  note?: string;
  proofHash: string;
  traceHash: string;
};

type AdminMessengerRuntimeVerificationState = {
  settings: AdminMessengerRuntimeVerificationSettings;
  items: AdminMessengerRuntimeVerificationStoredItem[];
  sessions: AdminMessengerRuntimeVerificationSession[];
  updatedAt: string;
};

type AdminMessengerRuntimeVerificationItem = {
  key: string;
  categoryKey: string;
  titleKey: string;
  detailKey: string;
  status: AdminMessengerRuntimeVerificationStatus;
  manualStatus: AdminMessengerRuntimeVerificationManualStatus;
  required: boolean;
  ownerRequired: boolean;
  scorePct: number;
  blockers: number;
  warnings: number;
  sourceKey: string;
  proofRef?: string;
  note?: string;
  lastVerifiedBy?: string;
  lastVerifiedAt?: string;
  evidenceHash: string;
  traceHash: string;
};

type AdminMessengerRuntimeVerificationSnapshot = {
  ok: true;
  centerVersion: "messenger-runtime-two-device-verification-v1";
  generatedAt: string;
  generatedBy: string;
  rawContentIncluded: false;
  settings: AdminMessengerRuntimeVerificationSettings;
  summary: {
    totalItems: number;
    requiredItems: number;
    readyItems: number;
    warningItems: number;
    blockedItems: number;
    notConfiguredItems: number;
    manuallyVerifiedItems: number;
    manuallyBlockedItems: number;
    waivedItems: number;
    activeSessions: number;
    passedSessions: number;
    failedSessions: number;
    runtimeReadinessPct: number;
    runtimeVerificationAllowed: boolean;
    ownerRuntimeApprovalRequired: boolean;
    healthStatus: AdminMessengerRuntimeVerificationStatus;
    walletTouched: false;
  };
  items: AdminMessengerRuntimeVerificationItem[];
  sessions: AdminMessengerRuntimeVerificationSession[];
  blockers: AdminMessengerRuntimeVerificationItem[];
  warnings: AdminMessengerRuntimeVerificationItem[];
  categories: Array<{ key: string; total: number; ready: number; blocked: number; warning: number; notConfigured: number; progressPct: number }>;
  charts: {
    verificationLanes: Array<{ key: string; status: AdminMessengerRuntimeVerificationStatus; scorePct: number; blockers: number; warnings: number }>;
    categoryProgress: Array<{ label: string; value: number; ready: number; blocked: number; warning: number; notConfigured: number; progressPct: number }>;
    sessionStatus: Array<{ label: string; value: number }>;
  };
  rules: string[];
  nextRequiredSteps: string[];
  sourceQuality: {
    maxPrelaunchConnected: boolean;
    finalReadinessConnected: boolean;
    presenceConnected: boolean;
    notificationsConnected: boolean;
    directoryConnected: boolean;
    contentQualityConnected: boolean;
    manualSessionProofAvailable: boolean;
    rawContentIncluded: false;
    walletTouched: false;
  };
  traceHash: string;
};

const ADMIN_MESSENGER_RUNTIME_VERIFICATION_FILE = path.join(process.cwd(), ".data", "admin", "messenger-runtime-verification.json");

function createMessengerRuntimeVerificationTraceHash(value: unknown): string {
  return crypto.createHash("sha256").update(JSON.stringify(value)).digest("hex");
}

function defaultMessengerRuntimeVerificationSettings(): AdminMessengerRuntimeVerificationSettings {
  const now = new Date().toISOString();
  return {
    requireTwoPhysicalDevices: true,
    requireUnifiedUserIdProof: true,
    requireRealtimePresenceProof: true,
    requireChatSendReceiveProof: true,
    requireMediaPipelineProof: true,
    requireCallsProof: true,
    requireNotificationsProof: true,
    requirePublicDirectoryProof: true,
    requireSafetyAndAntiSpamProof: true,
    requireOwnerFinalRuntimeApproval: true,
    rawPrivateContentStorageAllowed: false,
    walletTouched: false,
    updatedBy: "system",
    updatedAt: now,
  };
}

function normalizeMessengerRuntimeVerificationSettings(value: unknown): AdminMessengerRuntimeVerificationSettings {
  const defaults = defaultMessengerRuntimeVerificationSettings();
  const source = value && typeof value === "object" ? (value as Record<string, unknown>) : {};
  return {
    requireTwoPhysicalDevices: readBoolean(source.requireTwoPhysicalDevices, defaults.requireTwoPhysicalDevices),
    requireUnifiedUserIdProof: readBoolean(source.requireUnifiedUserIdProof, defaults.requireUnifiedUserIdProof),
    requireRealtimePresenceProof: readBoolean(source.requireRealtimePresenceProof, defaults.requireRealtimePresenceProof),
    requireChatSendReceiveProof: readBoolean(source.requireChatSendReceiveProof, defaults.requireChatSendReceiveProof),
    requireMediaPipelineProof: readBoolean(source.requireMediaPipelineProof, defaults.requireMediaPipelineProof),
    requireCallsProof: readBoolean(source.requireCallsProof, defaults.requireCallsProof),
    requireNotificationsProof: readBoolean(source.requireNotificationsProof, defaults.requireNotificationsProof),
    requirePublicDirectoryProof: readBoolean(source.requirePublicDirectoryProof, defaults.requirePublicDirectoryProof),
    requireSafetyAndAntiSpamProof: readBoolean(source.requireSafetyAndAntiSpamProof, defaults.requireSafetyAndAntiSpamProof),
    requireOwnerFinalRuntimeApproval: readBoolean(source.requireOwnerFinalRuntimeApproval, defaults.requireOwnerFinalRuntimeApproval),
    rawPrivateContentStorageAllowed: false,
    walletTouched: false,
    updatedBy: readString(source.updatedBy) ?? defaults.updatedBy,
    updatedAt: readString(source.updatedAt) ?? defaults.updatedAt,
  };
}

function normalizeMessengerRuntimeVerificationStoredItem(value: unknown): AdminMessengerRuntimeVerificationStoredItem | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const key = readString(source.key);
  if (!key) return null;
  const rawStatus = readString(source.manualStatus) ?? "pending";
  const manualStatus: AdminMessengerRuntimeVerificationManualStatus = rawStatus === "verified" || rawStatus === "blocked" || rawStatus === "waived" ? rawStatus : "pending";
  const now = new Date().toISOString();
  return {
    key,
    manualStatus,
    note: readString(source.note),
    proofRef: readString(source.proofRef),
    verifiedBy: readString(source.verifiedBy),
    verifiedAt: readString(source.verifiedAt),
    blockedBy: readString(source.blockedBy),
    blockedAt: readString(source.blockedAt),
    waivedBy: readString(source.waivedBy),
    waivedAt: readString(source.waivedAt),
    updatedBy: readString(source.updatedBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? now,
  };
}

function normalizeMessengerRuntimeVerificationSession(value: unknown): AdminMessengerRuntimeVerificationSession | null {
  if (!value || typeof value !== "object") return null;
  const source = value as Record<string, unknown>;
  const id = readString(source.id);
  const deviceAUserId = readString(source.deviceAUserId);
  const deviceBUserId = readString(source.deviceBUserId);
  if (!id || !deviceAUserId || !deviceBUserId) return null;
  const rawStatus = readString(source.status) ?? "draft";
  const status: AdminMessengerRuntimeVerificationSessionStatus = rawStatus === "running" || rawStatus === "passed" || rawStatus === "failed" || rawStatus === "cancelled" ? rawStatus : "draft";
  const rawMode = readString(source.connectionMode) ?? "lan";
  const connectionMode: AdminMessengerRuntimeVerificationSession["connectionMode"] = rawMode === "tunnel" || rawMode === "production" || rawMode === "local" ? rawMode : "lan";
  const now = new Date().toISOString();
  return {
    id,
    title: readString(source.title) ?? "runtime_verification_session",
    status,
    deviceAUserId,
    deviceBUserId,
    deviceALabel: readString(source.deviceALabel),
    deviceBLabel: readString(source.deviceBLabel),
    connectionMode,
    startedAt: readString(source.startedAt) ?? now,
    finishedAt: readString(source.finishedAt),
    createdBy: readString(source.createdBy) ?? "system",
    updatedBy: readString(source.updatedBy) ?? "system",
    updatedAt: readString(source.updatedAt) ?? now,
    note: readString(source.note),
    proofHash: readString(source.proofHash) ?? createMessengerRuntimeVerificationTraceHash({ id, deviceAUserId, deviceBUserId, connectionMode }),
    traceHash: readString(source.traceHash) ?? createMessengerRuntimeVerificationTraceHash({ id, status, now }),
  };
}

function defaultMessengerRuntimeVerificationState(): AdminMessengerRuntimeVerificationState {
  return { settings: defaultMessengerRuntimeVerificationSettings(), items: [], sessions: [], updatedAt: new Date().toISOString() };
}

function readMessengerRuntimeVerificationState(): AdminMessengerRuntimeVerificationState {
  try {
    if (!fs.existsSync(ADMIN_MESSENGER_RUNTIME_VERIFICATION_FILE)) return defaultMessengerRuntimeVerificationState();
    const parsed = JSON.parse(fs.readFileSync(ADMIN_MESSENGER_RUNTIME_VERIFICATION_FILE, "utf8")) as Partial<AdminMessengerRuntimeVerificationState>;
    return {
      settings: normalizeMessengerRuntimeVerificationSettings(parsed.settings),
      items: Array.isArray(parsed.items) ? parsed.items.map(normalizeMessengerRuntimeVerificationStoredItem).filter((item): item is AdminMessengerRuntimeVerificationStoredItem => Boolean(item)) : [],
      sessions: Array.isArray(parsed.sessions) ? parsed.sessions.map(normalizeMessengerRuntimeVerificationSession).filter((item): item is AdminMessengerRuntimeVerificationSession => Boolean(item)) : [],
      updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString(),
    };
  } catch {
    return defaultMessengerRuntimeVerificationState();
  }
}

function writeMessengerRuntimeVerificationState(state: AdminMessengerRuntimeVerificationState): AdminMessengerRuntimeVerificationState {
  const next = {
    ...state,
    settings: normalizeMessengerRuntimeVerificationSettings(state.settings),
    items: state.items.map(normalizeMessengerRuntimeVerificationStoredItem).filter((item): item is AdminMessengerRuntimeVerificationStoredItem => Boolean(item)),
    sessions: state.sessions.map(normalizeMessengerRuntimeVerificationSession).filter((item): item is AdminMessengerRuntimeVerificationSession => Boolean(item)),
    updatedAt: new Date().toISOString(),
  };
  fs.mkdirSync(path.dirname(ADMIN_MESSENGER_RUNTIME_VERIFICATION_FILE), { recursive: true });
  fs.writeFileSync(ADMIN_MESSENGER_RUNTIME_VERIFICATION_FILE, JSON.stringify(next, null, 2));
  return next;
}

function runtimeVerificationStatusFrom(params: { blocked: boolean; warning: boolean; notConfigured?: boolean }): AdminMessengerRuntimeVerificationStatus {
  if (params.blocked) return "blocked";
  if (params.notConfigured) return "not_configured";
  if (params.warning) return "warning";
  return "ready";
}

function createMessengerRuntimeVerificationItem(input: {
  key: string;
  categoryKey: string;
  titleKey: string;
  detailKey: string;
  status: AdminMessengerRuntimeVerificationStatus;
  required?: boolean;
  ownerRequired?: boolean;
  scorePct: number;
  blockers?: number;
  warnings?: number;
  sourceKey: string;
}, manual: Map<string, AdminMessengerRuntimeVerificationStoredItem>): AdminMessengerRuntimeVerificationItem {
  const saved = manual.get(input.key);
  const manualStatus = saved?.manualStatus ?? "pending";
  const status: AdminMessengerRuntimeVerificationStatus = manualStatus === "blocked" ? "blocked" : manualStatus === "verified" ? "ready" : manualStatus === "waived" && input.status === "blocked" ? "warning" : input.status;
  const evidenceHash = createMessengerRuntimeVerificationTraceHash({ key: input.key, status: input.status, manualStatus, sourceKey: input.sourceKey, scorePct: input.scorePct, proofRef: saved?.proofRef });
  return {
    key: input.key,
    categoryKey: input.categoryKey,
    titleKey: input.titleKey,
    detailKey: input.detailKey,
    status,
    manualStatus,
    required: input.required !== false,
    ownerRequired: Boolean(input.ownerRequired),
    scorePct: Math.max(0, Math.min(100, Math.round(input.scorePct))),
    blockers: input.blockers ?? (status === "blocked" || status === "not_configured" ? 1 : 0),
    warnings: input.warnings ?? (status === "warning" ? 1 : 0),
    sourceKey: input.sourceKey,
    proofRef: saved?.proofRef,
    note: saved?.note,
    lastVerifiedBy: saved?.verifiedBy,
    lastVerifiedAt: saved?.verifiedAt,
    evidenceHash,
    traceHash: createMessengerRuntimeVerificationTraceHash({ key: input.key, evidenceHash, updatedAt: saved?.updatedAt ?? "system" }),
  };
}

async function buildMessengerRuntimeVerificationSnapshot(options: AdminModuleOptions, req: AdminRequest, store: AdminFileStore, providerStore: AdminProviderConfigStore): Promise<AdminMessengerRuntimeVerificationSnapshot> {
  const state = readMessengerRuntimeVerificationState();
  const manual = new Map(state.items.map((item) => [item.key, item]));
  const generatedAt = new Date().toISOString();
  const maxPrelaunch = await buildMessengerMaxPrelaunchSnapshot(options, req, store, providerStore);
  const finalReadiness = await buildMessengerFinalReadinessSnapshot(options, req, store, providerStore);
  const presence = await buildMessengerPresenceOperationsSnapshot(options, req, store);
  const notifications = await buildMessengerNotificationsMonitorSnapshot(options, req);
  const directory = await buildMessengerDirectoryPromotionSnapshot(options);
  const growth = await buildMessengerGrowthPromotionGreetingSnapshot(options, req, store, providerStore);
  const contentQuality = await buildMessengerContentQualitySnapshot(options, req, store, providerStore);
  const sessions = state.sessions.slice().sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt))).slice(0, 100);
  const activeSessions = sessions.filter((item) => item.status === "running" || item.status === "draft").length;
  const passedSessions = sessions.filter((item) => item.status === "passed").length;
  const failedSessions = sessions.filter((item) => item.status === "failed").length;
  const hasSessionProof = sessions.some((item) => item.status === "passed" || item.status === "running");
  const items: AdminMessengerRuntimeVerificationItem[] = [];
  const push = (item: Parameters<typeof createMessengerRuntimeVerificationItem>[0]) => items.push(createMessengerRuntimeVerificationItem(item, manual));

  push({ key: "two_physical_devices", categoryKey: "runtime", titleKey: "messenger.runtime.item.twoDevices.title", detailKey: "messenger.runtime.item.twoDevices.detail", status: hasSessionProof ? "ready" : "not_configured", scorePct: hasSessionProof ? 100 : 0, sourceKey: "manual_test_session", ownerRequired: true });
  push({ key: "unified_user_id_pair", categoryKey: "identity", titleKey: "messenger.runtime.item.unifiedId.title", detailKey: "messenger.runtime.item.unifiedId.detail", status: state.settings.requireUnifiedUserIdProof && !hasSessionProof ? "not_configured" : "ready", scorePct: hasSessionProof ? 95 : 0, sourceKey: "identity_runtime_proof" });
  push({ key: "max_prelaunch_ready", categoryKey: "readiness", titleKey: "messenger.runtime.item.maxReady.title", detailKey: "messenger.runtime.item.maxReady.detail", status: maxPrelaunch.summary.goLiveAllowed ? "ready" : maxPrelaunch.summary.healthStatus === "blocked" ? "blocked" : "warning", scorePct: maxPrelaunch.summary.maxReadinessPct, blockers: maxPrelaunch.summary.blockedGates + maxPrelaunch.summary.notConfiguredGates, warnings: maxPrelaunch.summary.warningGates, sourceKey: "max_prelaunch" });
  push({ key: "final_readiness_ready", categoryKey: "readiness", titleKey: "messenger.runtime.item.finalReady.title", detailKey: "messenger.runtime.item.finalReady.detail", status: finalReadiness.summary.healthStatus, scorePct: finalReadiness.summary.readinessScorePct, blockers: finalReadiness.summary.blockedItems + finalReadiness.summary.notConfiguredItems, warnings: finalReadiness.summary.warningItems, sourceKey: "final_readiness" });
  push({ key: "presence_realtime", categoryKey: "realtime", titleKey: "messenger.runtime.item.presence.title", detailKey: "messenger.runtime.item.presence.detail", status: presence.summary.realtimeHealth, scorePct: presence.summary.presenceReadinessPct, blockers: presence.summary.suspiciousStates, warnings: presence.summary.staleSessions, sourceKey: "presence_operations" });
  push({ key: "chat_send_receive", categoryKey: "chat", titleKey: "messenger.runtime.item.chat.title", detailKey: "messenger.runtime.item.chat.detail", status: state.settings.requireChatSendReceiveProof && !hasSessionProof ? "not_configured" : runtimeVerificationStatusFrom({ blocked: false, warning: finalReadiness.items.some((item) => item.key === "chat_send_receive" && item.status !== "ready") }), scorePct: hasSessionProof ? 90 : 0, sourceKey: "manual_two_device_chat_proof" });
  push({ key: "typing_read_delivery", categoryKey: "chat", titleKey: "messenger.runtime.item.receipts.title", detailKey: "messenger.runtime.item.receipts.detail", status: hasSessionProof ? "ready" : "not_configured", scorePct: hasSessionProof ? 88 : 0, sourceKey: "manual_two_device_realtime_proof" });
  push({ key: "media_pipeline", categoryKey: "media", titleKey: "messenger.runtime.item.media.title", detailKey: "messenger.runtime.item.media.detail", status: state.settings.requireMediaPipelineProof && !hasSessionProof ? "not_configured" : runtimeVerificationStatusFrom({ blocked: false, warning: finalReadiness.items.some((item) => item.key === "media_pipeline" && item.status !== "ready") }), scorePct: hasSessionProof ? 85 : 0, sourceKey: "manual_media_pipeline_proof" });
  push({ key: "calls_runtime", categoryKey: "calls", titleKey: "messenger.runtime.item.calls.title", detailKey: "messenger.runtime.item.calls.detail", status: state.settings.requireCallsProof && !hasSessionProof ? "not_configured" : runtimeVerificationStatusFrom({ blocked: false, warning: finalReadiness.items.some((item) => item.key === "calls" && item.status !== "ready") }), scorePct: hasSessionProof ? 80 : 0, sourceKey: "independent_calls_runtime_proof" });
  push({ key: "notifications_missed", categoryKey: "notifications", titleKey: "messenger.runtime.item.notifications.title", detailKey: "messenger.runtime.item.notifications.detail", status: notifications.summary.healthStatus, scorePct: notifications.summary.notificationReadinessPct, blockers: notifications.summary.failedNotifications, warnings: notifications.summary.issueBacklog, sourceKey: "notifications_monitor" });
  push({ key: "public_directory", categoryKey: "directory", titleKey: "messenger.runtime.item.directory.title", detailKey: "messenger.runtime.item.directory.detail", status: runtimeVerificationStatusFrom({ blocked: directory.summary.status === "blocked", warning: directory.summary.status === "warning" || directory.summary.lowQualityEntries > 0, notConfigured: directory.summary.status === "not_configured" }), scorePct: percentOf(directory.summary.publicEntries, Math.max(1, directory.summary.totalEntries)), blockers: directory.summary.hiddenEntries, warnings: directory.summary.pendingApproval + directory.summary.lowQualityEntries, sourceKey: "public_directory" });
  push({ key: "growth_greetings", categoryKey: "growth", titleKey: "messenger.runtime.item.growth.title", detailKey: "messenger.runtime.item.growth.detail", status: runtimeVerificationStatusFrom({ blocked: growth.summary.readinessScorePct < 50, warning: growth.summary.readinessScorePct < 80 }), scorePct: growth.summary.readinessScorePct, blockers: 0, warnings: growth.summary.pendingPromotions + growth.summary.pendingGreetingApprovals, sourceKey: "growth_promotion_greetings" });
  push({ key: "quality_antispam", categoryKey: "safety", titleKey: "messenger.runtime.item.quality.title", detailKey: "messenger.runtime.item.quality.detail", status: runtimeVerificationStatusFrom({ blocked: contentQuality.summary.healthStatus === "needs_review" || contentQuality.summary.highRiskSignals > 0, warning: contentQuality.summary.healthStatus === "watch" || contentQuality.summary.reviewBacklog > 0 }), scorePct: contentQuality.summary.qualityScore, blockers: contentQuality.summary.highRiskSignals, warnings: contentQuality.summary.reviewBacklog + contentQuality.summary.openSignals, sourceKey: "content_quality_antispam" });
  push({ key: "owner_runtime_approval", categoryKey: "owner", titleKey: "messenger.runtime.item.owner.title", detailKey: "messenger.runtime.item.owner.detail", status: state.settings.requireOwnerFinalRuntimeApproval && (manual.get("owner_runtime_approval")?.manualStatus !== "verified") ? "blocked" : "ready", scorePct: manual.get("owner_runtime_approval")?.manualStatus === "verified" ? 100 : 0, sourceKey: "owner_manual_runtime_approval", ownerRequired: true });
  push({ key: "no_raw_private_content", categoryKey: "privacy", titleKey: "messenger.runtime.item.privacy.title", detailKey: "messenger.runtime.item.privacy.detail", status: "ready", scorePct: 100, blockers: 0, warnings: 0, sourceKey: "admin_privacy_policy" });

  const required = items.filter((item) => item.required);
  const readyItems = items.filter((item) => item.status === "ready").length;
  const warningItems = items.filter((item) => item.status === "warning").length;
  const blockedItems = items.filter((item) => item.status === "blocked").length;
  const notConfiguredItems = items.filter((item) => item.status === "not_configured").length;
  const manuallyVerifiedItems = items.filter((item) => item.manualStatus === "verified").length;
  const ownerRuntimeApprovalRequired = state.settings.requireOwnerFinalRuntimeApproval && manual.get("owner_runtime_approval")?.manualStatus !== "verified";
  const runtimeReadinessPct = percentOf(items.reduce((sum, item) => sum + item.scorePct, 0), Math.max(1, items.length * 100));
  const runtimeVerificationAllowed = blockedItems === 0 && notConfiguredItems === 0 && !ownerRuntimeApprovalRequired && runtimeReadinessPct >= 85;
  const healthStatus: AdminMessengerRuntimeVerificationStatus = runtimeVerificationAllowed ? "ready" : blockedItems > 0 ? "blocked" : notConfiguredItems > 0 ? "not_configured" : "warning";
  const categories = Array.from(new Set(items.map((item) => item.categoryKey))).map((key) => {
    const rows = items.filter((item) => item.categoryKey === key);
    return {
      key,
      total: rows.length,
      ready: rows.filter((item) => item.status === "ready").length,
      blocked: rows.filter((item) => item.status === "blocked").length,
      warning: rows.filter((item) => item.status === "warning").length,
      notConfigured: rows.filter((item) => item.status === "not_configured").length,
      progressPct: percentOf(rows.filter((item) => item.status === "ready").length, Math.max(1, rows.length)),
    };
  });
  return {
    ok: true,
    centerVersion: "messenger-runtime-two-device-verification-v1",
    generatedAt,
    generatedBy: req.admin?.id ?? "env-admin",
    rawContentIncluded: false,
    settings: state.settings,
    summary: {
      totalItems: items.length,
      requiredItems: required.length,
      readyItems,
      warningItems,
      blockedItems,
      notConfiguredItems,
      manuallyVerifiedItems,
      manuallyBlockedItems: items.filter((item) => item.manualStatus === "blocked").length,
      waivedItems: items.filter((item) => item.manualStatus === "waived").length,
      activeSessions,
      passedSessions,
      failedSessions,
      runtimeReadinessPct,
      runtimeVerificationAllowed,
      ownerRuntimeApprovalRequired,
      healthStatus,
      walletTouched: false,
    },
    items,
    sessions,
    blockers: items.filter((item) => item.status === "blocked" || item.status === "not_configured"),
    warnings: items.filter((item) => item.status === "warning"),
    categories,
    charts: {
      verificationLanes: items.map((item) => ({ key: item.key, status: item.status, scorePct: item.scorePct, blockers: item.blockers, warnings: item.warnings })),
      categoryProgress: categories.map((item) => ({ label: item.key, value: item.total, ready: item.ready, blocked: item.blocked, warning: item.warning, notConfigured: item.notConfigured, progressPct: item.progressPct })),
      sessionStatus: ["draft", "running", "passed", "failed", "cancelled"].map((label) => ({ label, value: sessions.filter((item) => item.status === label).length })),
    },
    rules: [
      "runtime_verification_runs_only_after_messenger_max_prelaunch_center",
      "two_device_test_must_use_real_phones_and_real_backend_runtime",
      "manual_proof_must_reference_ids_hashes_or_test_notes_not_raw_private_messages",
      "calls_test_must_use_independent_calls_subsystem_not_legacy_messenger_calls",
      "wallet_and_other_modules_remain_locked_until_messenger_runtime_verification_is_complete",
    ],
    nextRequiredSteps: runtimeVerificationAllowed ? ["start_real_two_device_messenger_mobile_backend_test"] : ["create_two_device_runtime_test_session", "verify_required_runtime_items", "resolve_runtime_blockers_before_other_modules"],
    sourceQuality: {
      maxPrelaunchConnected: maxPrelaunch.ok === true,
      finalReadinessConnected: finalReadiness.ok === true,
      presenceConnected: presence.ok === true,
      notificationsConnected: notifications.ok === true,
      directoryConnected: directory.ok === true,
      contentQualityConnected: contentQuality.ok === true,
      manualSessionProofAvailable: hasSessionProof,
      rawContentIncluded: false,
      walletTouched: false,
    },
    traceHash: createMessengerRuntimeVerificationTraceHash({ generatedAt, items: items.map((item) => ({ key: item.key, status: item.status, manualStatus: item.manualStatus, scorePct: item.scorePct })), sessions: sessions.map((item) => ({ id: item.id, status: item.status, proofHash: item.proofHash })) }),
  };
}

function updateMessengerRuntimeVerificationItemStatus(key: string, status: AdminMessengerRuntimeVerificationManualStatus, by: string, note?: string, proofRef?: string): AdminMessengerRuntimeVerificationState {
  const state = readMessengerRuntimeVerificationState();
  const now = new Date().toISOString();
  const existing = state.items.find((item) => item.key === key);
  const next: AdminMessengerRuntimeVerificationStoredItem = {
    ...(existing ?? { key, manualStatus: "pending" as const, updatedBy: by, updatedAt: now }),
    key,
    manualStatus: status,
    note: note ?? existing?.note,
    proofRef: proofRef ?? existing?.proofRef,
    verifiedBy: status === "verified" ? by : existing?.verifiedBy,
    verifiedAt: status === "verified" ? now : existing?.verifiedAt,
    blockedBy: status === "blocked" ? by : existing?.blockedBy,
    blockedAt: status === "blocked" ? now : existing?.blockedAt,
    waivedBy: status === "waived" ? by : existing?.waivedBy,
    waivedAt: status === "waived" ? now : existing?.waivedAt,
    updatedBy: by,
    updatedAt: now,
  };
  const items = state.items.filter((item) => item.key !== key);
  if (status !== "pending" || note || proofRef) items.push(next);
  return writeMessengerRuntimeVerificationState({ ...state, items });
}

function createMessengerRuntimeVerificationSession(body: Record<string, unknown>, by: string): AdminMessengerRuntimeVerificationState {
  const state = readMessengerRuntimeVerificationState();
  const now = new Date().toISOString();
  const deviceAUserId = readString(body.deviceAUserId) ?? "";
  const deviceBUserId = readString(body.deviceBUserId) ?? "";
  if (!deviceAUserId || !deviceBUserId) return state;
  const rawMode = readString(body.connectionMode) ?? "lan";
  const connectionMode: AdminMessengerRuntimeVerificationSession["connectionMode"] = rawMode === "tunnel" || rawMode === "production" || rawMode === "local" ? rawMode : "lan";
  const id = `msg_runtime_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
  const title = readString(body.title) ?? "runtime_verification_session";
  const session: AdminMessengerRuntimeVerificationSession = {
    id,
    title,
    status: "draft",
    deviceAUserId,
    deviceBUserId,
    deviceALabel: readString(body.deviceALabel),
    deviceBLabel: readString(body.deviceBLabel),
    connectionMode,
    startedAt: readString(body.startedAt) ?? now,
    createdBy: by,
    updatedBy: by,
    updatedAt: now,
    note: readString(body.note),
    proofHash: createMessengerRuntimeVerificationTraceHash({ id, title, deviceAUserId, deviceBUserId, connectionMode, createdBy: by, createdAt: now }),
    traceHash: createMessengerRuntimeVerificationTraceHash({ id, status: "draft", now }),
  };
  return writeMessengerRuntimeVerificationState({ ...state, sessions: [session, ...state.sessions].slice(0, 100) });
}

function updateMessengerRuntimeVerificationSessionStatus(id: string, status: AdminMessengerRuntimeVerificationSessionStatus, by: string, note?: string): AdminMessengerRuntimeVerificationState {
  const state = readMessengerRuntimeVerificationState();
  const now = new Date().toISOString();
  const sessions = state.sessions.map((item) => item.id === id ? {
    ...item,
    status,
    finishedAt: status === "passed" || status === "failed" || status === "cancelled" ? now : item.finishedAt,
    note: note ?? item.note,
    updatedBy: by,
    updatedAt: now,
    traceHash: createMessengerRuntimeVerificationTraceHash({ id, status, by, now, proofHash: item.proofHash }),
  } : item);
  return writeMessengerRuntimeVerificationState({ ...state, sessions });
}


