  router.post("/wallet/merchant-api-center/credentials", requireAdminPermission("merchant:write"), requireRootOwner, (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }

    const body = readBodyObject(req);
    const merchantId = readString(body.merchantId);
    if (!merchantId) {
      res.status(400).json({ ok: false, error: "merchant_id_required" });
      return;
    }

    if (!requireNoEmergencyLockForAction(store, req, res, ["merchant", "wallet"], "wallet.merchant_api.generate", "merchant", merchantId)) return;

    const kind: AdminWalletMerchantCredentialKind = body.kind === "webhook_secret" ? "webhook_secret" : "api_key";
    const mode: AdminWalletMerchantCredentialMode = body.mode === "live" ? "live" : "test";
    const result = createAdminWalletMerchantCredential({
      store,
      merchantId,
      kind,
      mode,
      label: readString(body.label),
      scopes: adminWalletMerchantCredentialScopeList(body.scopes, kind === "webhook_secret" ? ["webhooks:send"] : ["payments:read", "payments:create", "settlements:read", "qr:pay"]),
      callbackUrl: readString(body.callbackUrl),
      ipAllowlist: readStringArray(body.ipAllowlist),
      actorId: req.admin?.id ?? "env-admin",
    });
    if (!result) {
      res.status(404).json({ ok: false, error: "admin_merchant_not_found" });
      return;
    }
    audit(store, req, "admin.wallet.merchant_api.generate" as AdminAuditAction, "merchant", merchantId, { credentialId: result.credential.id, kind, mode, scopes: result.credential.scopes, secretReturnedOnce: Boolean(result.secretOnce) });
    res.json({ ok: true, result, merchantApiCenter: buildAdminWalletMerchantApiCenter(store) });
  });

