  router.use("/messenger", requireAdminPermission("messenger:read"), async (req: AdminRequest, res: Response, next: NextFunction) => {
    if (req.method !== "GET") {
      next();
      return;
    }

    const normalizedRuntimePath = decodeURIComponent(String(req.path || "")).replace(/\s+/g, "-");
    if (normalizedRuntimePath === "/admin-100/snapshot") {
      next();
      return;
    }

    const builder = adminMessengerRuntimeBuilders[`${req.method} ${req.path}`];
    if (!builder) {
      next();
      return;
    }

    const result = await runAdminMessengerRuntimeBuilder(`${req.method} /messenger${req.path}`, builder, req);
    if (res.headersSent) return;

    if (result.ok) {
      audit(store, req, "admin.messenger.fast_runtime.snapshot" as AdminAuditAction, "messenger_admin_runtime", req.path, { path: req.path, rawContentIncluded: false });
      res.json(result.payload);
      return;
    }

    audit(store, req, "admin.messenger.fast_runtime.degraded" as AdminAuditAction, "messenger_admin_runtime", req.path, { path: req.path, error: result.error, rawContentIncluded: false });
    res.status(result.status).json(result.payload);
  });




