  router.post("/messenger/directory/:kind/:id/review-action", requireAdminPermission("messenger:write"), async (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }

    const kindRaw = getParam(req, "kind");
    if (!isMessengerDirectoryKind(kindRaw)) {
      res.status(400).json({ ok: false, error: "messenger_directory_kind_invalid" });
      return;
    }

    const targetId = getParam(req, "id");
    const body = readBodyObject(req);
    const action = normalizeMessengerDirectoryReviewAction(body.action ?? req.query.action);
    if (!targetId) {
      res.status(400).json({ ok: false, error: "messenger_directory_target_id_required" });
      return;
    }
    if (!action) {
      res.status(400).json({ ok: false, error: "messenger_directory_review_action_required" });
      return;
    }

    const reason = readString(body.reason) ?? readString(body.reviewReason) ?? "admin_review";
    let control = readMessengerDirectoryControlState();
    const now = new Date().toISOString();
    let visibleInMobile = true;

    if (action === "approve" || action === "restore") {
      let released = false;
      control = writeMessengerDirectoryControlState({
        ...control,
        restrictions: control.restrictions.map((item) => {
          if (item.kind !== kindRaw || item.targetId !== targetId || item.status !== "active") return item;
          released = true;
          return {
            ...item,
            status: "released",
            releasedBy: req.admin?.id ?? "admin",
            releasedAt: now,
            releaseReason: reason,
          };
        }),
      });
      visibleInMobile = true;
      audit(store, req, `admin.messenger.directory.review.${action}` as AdminAuditAction, `messenger_${kindRaw}`, targetId, { released, reason, rawContentIncluded: false });
    } else {
      const existing = control.restrictions.find((item) => item.kind === kindRaw && item.targetId === targetId && item.status === "active");
      const restriction: AdminMessengerDirectoryRestriction = existing ?? {
        id: createAdminLocalId("msg_dir_review"),
        kind: kindRaw,
        targetId,
        reason: buildAdminMessengerDirectoryActionReason(action, reason),
        status: "active",
        createdBy: req.admin?.id ?? "admin",
        createdAt: now,
      };

      control = writeMessengerDirectoryControlState({
        ...control,
        restrictions: existing
          ? control.restrictions.map((item) => item.id === existing.id ? { ...item, reason: buildAdminMessengerDirectoryActionReason(action, reason) } : item)
          : [restriction, ...control.restrictions],
      });
      visibleInMobile = false;
      audit(store, req, `admin.messenger.directory.review.${action}` as AdminAuditAction, `messenger_${kindRaw}`, targetId, { reason, rawContentIncluded: false });
    }

    const queue = await buildAdminMessengerDirectoryReviewQueue(options, { limit: 100 });
    res.json({
      ok: true,
      kind: kindRaw,
      id: targetId,
      action,
      visibleInMobile,
      control,
      queue,
      adminControlled: true,
      rawContentIncluded: false,
      updatedAt: now,
    });
  });

