  router.post("/messenger/directory-promotion/entries/:id/status", requireAdminPermission("messenger:write"), async (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const status = normalizeDirectoryPromotionListingStatus(body.status, "pending_approval");
    const state = readMessengerDirectoryPromotionState();
    const now = new Date().toISOString();
    let updated: AdminMessengerDirectoryPromotionEntry | undefined;
    const entries = state.entries.map((entry) => {
      if (entry.id !== id) return entry;
      const next: AdminMessengerDirectoryPromotionEntry = {
        ...entry,
        listingStatus: status,
        approvalStatus: status === "approved" || status === "featured" || status === "boosted" || status === "recommended" ? "approved" : status === "rejected" ? "rejected" : entry.approvalStatus,
        visibility: status === "hidden" || status === "rejected" ? "hidden" : entry.visibility === "restricted" ? "restricted" : "public",
        note: readString(body.note) ?? entry.note,
        rejectionReason: status === "rejected" ? readString(body.note) ?? entry.rejectionReason : entry.rejectionReason,
        approvedBy: status === "approved" || status === "featured" || status === "boosted" || status === "recommended" ? req.admin?.id ?? "admin" : entry.approvedBy,
        approvedAt: status === "approved" || status === "featured" || status === "boosted" || status === "recommended" ? now : entry.approvedAt,
        rejectedBy: status === "rejected" ? req.admin?.id ?? "admin" : entry.rejectedBy,
        rejectedAt: status === "rejected" ? now : entry.rejectedAt,
        hiddenBy: status === "hidden" ? req.admin?.id ?? "admin" : entry.hiddenBy,
        hiddenAt: status === "hidden" ? now : entry.hiddenAt,
        pausedBy: status === "paused" ? req.admin?.id ?? "admin" : entry.pausedBy,
        pausedAt: status === "paused" ? now : entry.pausedAt,
        updatedBy: req.admin?.id ?? "admin",
        updatedAt: now,
      };
      updated = next;
      return next;
    });
    if (!updated) {
      res.status(404).json({ ok: false, error: "messenger_directory_promotion_entry_not_found" });
      return;
    }
    writeMessengerDirectoryPromotionState({ ...state, entries });
    const snapshot = await buildMessengerDirectoryPromotionSnapshot(options);
    audit(store, req, "admin.messenger.directory_promotion.entry.status", "messenger_directory_promotion_entry", id, { status, kind: updated.kind, targetId: updated.targetId, rawContentIncluded: false, traceHash: updated.traceHash });
    res.json({ ok: true, entry: updated, snapshot });
  });

  router.post("/messenger/directory-promotion/entries/:id/boost", requireAdminPermission("messenger:write"), async (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const state = readMessengerDirectoryPromotionState();
    const now = new Date().toISOString();
    let updated: AdminMessengerDirectoryPromotionEntry | undefined;
    const entries = state.entries.map((entry) => {
      if (entry.id !== id) return entry;
      const featuredRankRaw = readNumber(body.featuredRank, entry.featuredRank ?? 0);
      const next: AdminMessengerDirectoryPromotionEntry = {
        ...entry,
        listingStatus: readBoolean(body.recommended, entry.recommended) ? "recommended" : featuredRankRaw > 0 ? "featured" : (readNumber(body.searchBoostPct, entry.searchBoostPct) > 0 || readNumber(body.directoryBoostPct, entry.directoryBoostPct) > 0) ? "boosted" : entry.listingStatus,
        approvalStatus: "approved",
        visibility: entry.visibility === "restricted" ? "restricted" : "public",
        featuredRank: featuredRankRaw > 0 ? Math.floor(featuredRankRaw) : undefined,
        searchBoostPct: clampDirectoryPromotionScore(body.searchBoostPct, entry.searchBoostPct),
        directoryBoostPct: clampDirectoryPromotionScore(body.directoryBoostPct, entry.directoryBoostPct),
        recommended: readBoolean(body.recommended, entry.recommended),
        note: readString(body.note) ?? entry.note,
        boostedBy: req.admin?.id ?? "admin",
        boostedAt: now,
        approvedBy: entry.approvedBy ?? req.admin?.id ?? "admin",
        approvedAt: entry.approvedAt ?? now,
        updatedBy: req.admin?.id ?? "admin",
        updatedAt: now,
      };
      updated = next;
      return next;
    });
    if (!updated) {
      res.status(404).json({ ok: false, error: "messenger_directory_promotion_entry_not_found" });
      return;
    }
    writeMessengerDirectoryPromotionState({ ...state, entries });
    const snapshot = await buildMessengerDirectoryPromotionSnapshot(options);
    audit(store, req, "admin.messenger.directory_promotion.entry.boost", "messenger_directory_promotion_entry", id, { kind: updated.kind, targetId: updated.targetId, featuredRank: updated.featuredRank, searchBoostPct: updated.searchBoostPct, directoryBoostPct: updated.directoryBoostPct, recommended: updated.recommended, rawContentIncluded: false, traceHash: updated.traceHash });
    res.json({ ok: true, entry: updated, snapshot });
  });

