  router.patch("/messenger/feature-flags/:key", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    const key = getParam(req, "key");
    const allowed = new Set(messengerFeatureFlags(store).map((flag) => flag.key));
    if (!allowed.has(key)) {
      res.status(404).json({ ok: false, error: "messenger_feature_flag_not_found" });
      return;
    }

    const body = readBodyObject(req);
    const enabled = readMessengerFlagEnabled(body.enabled);
    if (enabled === null) {
      res.status(400).json({ ok: false, error: "messenger_feature_flag_enabled_required" });
      return;
    }

    const control = readMessengerControlState();
    const now = new Date().toISOString();
    const nextFlag: AdminMessengerStoredFeatureFlag = {
      key,
      enabled,
      updatedBy: req.admin?.id ?? "admin",
      updatedAt: now,
      note: readString(body.note),
    };
    const next = {
      ...control,
      featureFlags: [...control.featureFlags.filter((item) => item.key !== key), nextFlag],
    };
    const saved = writeMessengerControlState(next);
    audit(store, req, "admin.messenger.feature_flags.update", "messenger_feature_flag", key, { enabled, note: nextFlag.note });
    res.json({ ok: true, control: saved, featureFlags: messengerFeatureFlags(store), center: buildMessengerAdminCenter(options, store, providerStore) });
  });

