    const message = readString(body.message);
    const key = readString(body.key) ?? `manual_${Date.now().toString(36)}`;
    const severity = body.severity === "critical" ? "critical" : "warning";

    if (!title || !message) {
      res.status(400).json({ ok: false, error: "messenger_launch_blocker_title_and_message_required" });
      return;
    }

    const control = readMessengerControlState();
    const blocker: AdminMessengerStoredLaunchBlocker = {
      id: createAdminLocalId("msg_blocker"),
      key,
      title,
      message,
      severity,
      status: "active",
      createdBy: req.admin?.id ?? "admin",
      createdAt: new Date().toISOString(),
    };
    const saved = writeMessengerControlState({ ...control, launchBlockers: [blocker, ...control.launchBlockers] });
    audit(store, req, "admin.messenger.launch_blockers.create", "messenger_launch_blocker", blocker.id, { key, severity, title });
    res.status(201).json({ ok: true, blocker, control: saved, center: buildMessengerAdminCenter(options, store, providerStore) });
