  router.post("/messenger/safety/ai-signals", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    const body = readBodyObject(req);
    const state = readMessengerSafetyControlState();
    if (!state.settings.aiSafetySignalsEnabled) {
      res.status(409).json({ ok: false, error: "messenger_ai_safety_signals_disabled" });
      return;
    }

    const summary = readString(body.summary) ?? readString(body.description);
    if (!summary) {
      res.status(400).json({ ok: false, error: "messenger_ai_safety_signal_summary_required" });
      return;
    }

    const now = new Date().toISOString();
    const category = normalizeMessengerSafetyCategory(body.category);
    const severity = body.severity === "high" || body.severity === "critical" ? body.severity : messengerSafetyCategorySeverity(category);
    const by = req.admin?.id ?? "ai-safety";
    const signal: AdminMessengerAiSafetySignal = {
      id: createAdminLocalId("msg_ai_signal"),
      externalSignalId: readString(body.externalSignalId) ?? readString(body.signalId),
      source: readString(body.source) ?? "ai_safety_gateway",
      category,
      severity,
      confidence: normalizeConfidence(body.confidence),
      status: "received",
      summary,
      targetType: readString(body.targetType),
      targetId: readString(body.targetId),
      relatedUserId: readString(body.relatedUserId),
      relatedChatId: readString(body.relatedChatId),
      relatedMessageId: readString(body.relatedMessageId),
      provider: readString(body.provider),
      model: readString(body.model),
      evidenceHash: readString(body.evidenceHash),
      metadata: body.metadata && typeof body.metadata === "object" ? body.metadata as Record<string, unknown> : undefined,
      createdBy: by,
      createdAt: now,
      updatedBy: by,
      updatedAt: now,
    };

    const reports = [...state.reports];
    const aiSignals = [signal, ...state.aiSignals];
    let linkedReport: AdminMessengerSafetyReport | undefined;
    if (shouldAutoCreateReportForAiSignal(signal, state.settings)) {
      linkedReport = buildMessengerSafetyReportFromAiSignal(signal, by);
      reports.unshift(linkedReport);
      aiSignals[0] = { ...signal, status: "report_created", linkedReportId: linkedReport.id, updatedBy: by, updatedAt: now };
    }

    let nextState: AdminMessengerSafetyControlState = { ...state, reports, aiSignals };
    const vaultResult = attachVaultEvidenceToAiSignal(nextState, aiSignals[0], by, "ai_signal_ingested", linkedReport?.id);
    nextState = vaultResult.state;
    const saved = writeMessengerSafetyControlState(nextState);
    const savedSignal = saved.aiSignals.find((item) => item.id === signal.id) ?? aiSignals[0];
    const savedReport = linkedReport ? saved.reports.find((item) => item.id === linkedReport?.id) : undefined;
    audit(store, req, "admin.messenger.safety.ai_signals.ingest", "messenger_ai_safety_signal", signal.id, { category, severity, confidence: signal.confidence, linkedReportId: savedReport?.id, vaultEvidenceIds: vaultResult.items.map((item) => item.id) });
    res.status(201).json({ ok: true, signal: savedSignal, report: savedReport, signals: saved.aiSignals.slice(0, 100), reports: saved.reports.slice(0, 100), dashboard: buildMessengerSafetyDashboard() });
  });

  router.post("/messenger/safety/ai-signals/:id/convert", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    const id = getParam(req, "id");
    const state = readMessengerSafetyControlState();
    const signal = state.aiSignals.find((item) => item.id === id);
    if (!signal) {
      res.status(404).json({ ok: false, error: "messenger_ai_safety_signal_not_found" });
      return;
    }
    const by = req.admin?.id ?? "admin";
    const now = new Date().toISOString();
    const existing = signal.linkedReportId ? state.reports.find((item) => item.id === signal.linkedReportId) : undefined;
    const report = existing ?? buildMessengerSafetyReportFromAiSignal(signal, by);
    const reports = existing ? state.reports : [report, ...state.reports];
    const aiSignals = state.aiSignals.map((item) => item.id === id ? { ...item, status: "report_created" as const, linkedReportId: report.id, updatedBy: by, updatedAt: now } : item);
    const convertedSignal = aiSignals.find((item) => item.id === id) ?? signal;
    let nextState: AdminMessengerSafetyControlState = { ...state, reports, aiSignals };
    const vaultResult = attachVaultEvidenceToAiSignal(nextState, convertedSignal, by, "ai_signal_converted", report.id);
    nextState = vaultResult.state;
    const saved = writeMessengerSafetyControlState(nextState);
    const savedReport = saved.reports.find((item) => item.id === report.id) ?? report;
    audit(store, req, "admin.messenger.safety.ai_signals.convert", "messenger_ai_safety_signal", id, { linkedReportId: report.id, vaultEvidenceIds: vaultResult.items.map((item) => item.id) });
    res.json({ ok: true, signal: saved.aiSignals.find((item) => item.id === id), report: savedReport, dashboard: buildMessengerSafetyDashboard() });
  });

