  router.post("/messenger/safety/authority-requests", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const body = readBodyObject(req);
    const authorityName = readString(body.authorityName);
    const legalBasis = readString(body.legalBasis);
    const requestedScope = readString(body.requestedScope);
    if (!authorityName || !legalBasis || !requestedScope) {
      res.status(400).json({ ok: false, error: "authority_request_required_fields_missing" });
      return;
    }
    const now = new Date().toISOString();
    const by = req.admin?.id ?? "admin";
    const linkedReportIds = readStringArray(body.linkedReportIds);
    const linkedCaseIds = readStringArray(body.linkedCaseIds);
    const linkedEvidenceIds = readStringArray(body.linkedEvidenceIds);
    const requestDraft: AdminMessengerAuthorityRequest = {
      id: createAdminLocalId("authority_req"),
      authorityName,
      requestReference: readString(body.requestReference),
      requestKind: normalizeMessengerAuthorityRequestKind(body.requestKind),
      authorityCountry: readString(body.authorityCountry),
      authorityOfficerName: readString(body.authorityOfficerName),
      authorityContactHash: readString(body.authorityContactHash),
      legalBasis,
      requestedScope,
      priority: normalizeMessengerAuthorityRequestPriority(body.priority),
      dueAt: readString(body.dueAt),
      status: "received",
      linkedReportIds,
      linkedCaseIds,
      linkedEvidenceIds,
      checklist: {
        legalBasisProvided: true,
        scopeLimited: true,
        ownerApprovalRequired: true,
        ownerApproved: false,
        linkedCaseOrReport: false,
        linkedEvidence: false,
        rawContentHidden: true,
        auditAnchored: false,
      },
      disclosureLog: [],
      createdBy: by,
      createdAt: now,
      updatedBy: by,
      updatedAt: now,
    };
    const state = readMessengerSafetyControlState();
    const request = refreshMessengerAuthorityRequest(requestDraft, verifyMessengerEvidenceVaultIntegrity(state.evidenceVault).anchorHash);
    const caseReviews = state.caseReviews.map((item) => linkedCaseIds.includes(item.id) || item.linkedReportIds.some((id) => linkedReportIds.includes(id))
      ? refreshMessengerSafetyCaseReview(state, {
        ...item,
        linkedAuthorityRequestIds: Array.from(new Set([...(item.linkedAuthorityRequestIds ?? []), request.id])),
        timeline: [{ event: "authority_request_linked", by, at: now, note: request.requestReference ?? request.authorityName }, ...item.timeline],
        updatedBy: by,
        updatedAt: now,
      })
      : item);
    const saved = writeMessengerSafetyControlState({ ...state, caseReviews, authorityRequests: [request, ...state.authorityRequests] });
    audit(store, req, "admin.messenger.safety.authority_requests.create", "messenger_authority_request", request.id, { authorityName, requestReference: request.requestReference, linkedReportIds, linkedCaseIds, linkedEvidenceIds });
    res.status(201).json({ ok: true, request, authorityRequests: saved.authorityRequests, dashboard: buildMessengerSafetyDashboard() });
  });

  router.post("/messenger/safety/authority-requests/:id/status", requireAdminPermission("messenger:write"), requireRootOwner, (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const status = normalizeMessengerAuthorityRequestStatus(body.status);
    const decisionNote = readString(body.decisionNote);
    const linkedReportIds = Array.isArray(body.linkedReportIds) ? readStringArray(body.linkedReportIds) : undefined;
    const linkedCaseIds = Array.isArray(body.linkedCaseIds) ? readStringArray(body.linkedCaseIds) : undefined;
    const linkedEvidenceIds = Array.isArray(body.linkedEvidenceIds) ? readStringArray(body.linkedEvidenceIds) : undefined;
    const state = readMessengerSafetyControlState();
    const by = req.admin?.id ?? "root-owner";
    const now = new Date().toISOString();
    const auditAnchorHash = verifyMessengerEvidenceVaultIntegrity(state.evidenceVault).anchorHash;
    let changed: AdminMessengerAuthorityRequest | undefined;
    const authorityRequests = state.authorityRequests.map((item) => {
      if (item.id !== id) return item;
      const draft: AdminMessengerAuthorityRequest = {
        ...item,
        status,
        decisionNote: decisionNote ?? item.decisionNote,
        linkedReportIds: linkedReportIds ?? item.linkedReportIds,
        linkedCaseIds: linkedCaseIds ?? item.linkedCaseIds,
        linkedEvidenceIds: linkedEvidenceIds ?? item.linkedEvidenceIds,
        approvedBy: status === "approved" ? by : item.approvedBy,
        approvedAt: status === "approved" ? now : item.approvedAt,
        rejectedBy: status === "rejected" ? by : item.rejectedBy,
        rejectedAt: status === "rejected" ? now : item.rejectedAt,
        completedAt: status === "completed" ? now : item.completedAt,
        updatedBy: by,
        updatedAt: now,
      };
      changed = refreshMessengerAuthorityRequest(draft, auditAnchorHash);
      return changed;
    });
    if (!changed) {
      res.status(404).json({ ok: false, error: "authority_request_not_found" });
      return;
    }
    const caseReviews = state.caseReviews.map((item) => {
      const shouldLink = (changed?.linkedCaseIds ?? []).includes(item.id) || item.linkedReportIds.some((reportId) => (changed?.linkedReportIds ?? []).includes(reportId)) || item.linkedEvidenceIds.some((evidenceId) => (changed?.linkedEvidenceIds ?? []).includes(evidenceId));
      if (!shouldLink || !changed) return item;
      return refreshMessengerSafetyCaseReview(state, {
        ...item,
        linkedAuthorityRequestIds: Array.from(new Set([...(item.linkedAuthorityRequestIds ?? []), changed.id])),
        timeline: [{ event: `authority_request:${status}`, by, at: now, note: decisionNote }, ...item.timeline],
        updatedBy: by,
        updatedAt: now,
      });
    });
    const saved = writeMessengerSafetyControlState({ ...state, caseReviews, authorityRequests });
    audit(store, req, "admin.messenger.safety.authority_requests.status", "messenger_authority_request", id, { status, linkedReportIds: changed.linkedReportIds, linkedCaseIds: changed.linkedCaseIds, linkedEvidenceIds: changed.linkedEvidenceIds });
    res.json({ ok: true, request: changed, authorityRequests: saved.authorityRequests, dashboard: buildMessengerSafetyDashboard() });
  });

  router.get("/messenger/safety/authority-requests/:id/export", requireAdminPermission("audit:export"), requireRootOwner, (req: AdminRequest, res: Response) => {
    const id = getParam(req, "id");
    const state = readMessengerSafetyControlState();
    const request = state.authorityRequests.find((item) => item.id === id);
    if (!request) {
      res.status(404).json({ ok: false, error: "authority_request_not_found" });
      return;
    }
    if (request.status !== "approved" && request.status !== "completed") {
      res.status(409).json({ ok: false, error: "authority_request_owner_approval_required" });
      return;
    }
    const packagePayload = buildMessengerAuthorityRequestPackage(request, req, store);
    const disclosure: AdminMessengerAuthorityDisclosureLog = {
      id: createAdminLocalId("authority_disclosure"),
      packageId: packagePayload.packageId,
      packageHash: packagePayload.packageHash,
      deliveryStatus: "prepared",
      legalBasis: request.legalBasis,
      scope: request.requestedScope,
      linkedReportIds: packagePayload.linkedReports.map((item) => item.id),
      linkedCaseIds: packagePayload.linkedCaseReviews.map((item) => item.id),
      linkedEvidenceIds: packagePayload.linkedVaultEvidence.map((item) => item.id),
      auditAnchorHash: packagePayload.auditAnchorHash,
      note: readString(req.query.note),
      exportedBy: req.admin?.id ?? "root-owner",
      exportedAt: packagePayload.exportedAt,
    };
    const authorityRequests = state.authorityRequests.map((item) => item.id === id
      ? refreshMessengerAuthorityRequest({ ...item, disclosureLog: [disclosure, ...item.disclosureLog], updatedBy: req.admin?.id ?? "root-owner", updatedAt: packagePayload.exportedAt }, packagePayload.auditAnchorHash)
      : item);
    writeMessengerSafetyControlState({ ...state, authorityRequests });
    audit(store, req, "admin.messenger.safety.authority_requests.export", "messenger_authority_request", id, { packageId: packagePayload.packageId, packageHash: packagePayload.packageHash, linkedReports: disclosure.linkedReportIds.length, linkedCases: disclosure.linkedCaseIds.length, linkedEvidence: disclosure.linkedEvidenceIds.length });
    res.json({ ...packagePayload, disclosureLog: disclosure });
  });

