  router.post("/messenger/safety/restrictions", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const body = readBodyObject(req);
    const state = readMessengerSafetyControlState();
    const by = req.admin?.id ?? "admin";
    const restriction = createMessengerSafetyRestriction(state, {
      scope: body.scope,
      status: req.admin?.rootOwner && readBoolean(body.activateNow, false) ? "active" : "pending_owner_decision",
      category: body.category,
      severity: body.severity,
      targetType: body.targetType,
      targetId: body.targetId,
      relatedUserId: body.relatedUserId,
      relatedChatId: body.relatedChatId,
      relatedMessageId: body.relatedMessageId,
      linkedReportIds: body.linkedReportIds,
      linkedCaseIds: body.linkedCaseIds,
      linkedAiSignalIds: body.linkedAiSignalIds,
      linkedEvidenceIds: body.linkedEvidenceIds,
      reason: body.reason,
      legalBasis: body.legalBasis,
      expiresAt: body.expiresAt,
      metadata: body.metadata,
    }, by, "restriction_created_manual");
    if (!restriction) {
      res.status(400).json({ ok: false, error: "messenger_safety_restriction_target_required" });
      return;
    }
    const now = new Date().toISOString();
    const finalRestriction = req.admin?.rootOwner && restriction.status === "active" ? refreshMessengerSafetyRestriction({ ...restriction, ownerApprovedBy: by, ownerApprovedAt: now, activeFrom: now, enforcementRef: restriction.enforcementRef ?? createAdminLocalId("msg_enf") }) : restriction;
    const saved = writeMessengerSafetyControlState({ ...state, restrictions: [finalRestriction, ...state.restrictions] });
    audit(store, req, "admin.messenger.safety.restrictions.create", "messenger_safety_restriction", finalRestriction.id, { scope: finalRestriction.scope, status: finalRestriction.status, targetType: finalRestriction.targetType, targetId: finalRestriction.targetId });
    res.status(201).json({ ok: true, restriction: finalRestriction, restrictions: saved.restrictions.map(refreshMessengerSafetyRestriction).slice(0, 100), dashboard: buildMessengerSafetyDashboard() });
  });

