  router.post("/messenger/safety/reports/:id/review-case", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const state = readMessengerSafetyControlState();
    let nextState = state;
    const vaultResult = attachVaultEvidenceToReport(nextState, id, req.admin?.id ?? "admin", "review_case_opened");
    nextState = vaultResult.state;
    const result = upsertMessengerSafetyReviewCaseForReport(nextState, id, req.admin?.id ?? "admin", readString(body.note));
    if (!result.caseReview) {
      res.status(404).json({ ok: false, error: "messenger_safety_report_not_found" });
      return;
    }
    const saved = writeMessengerSafetyControlState(result.state);
    const savedCase = saved.caseReviews.find((item) => item.id === result.caseReview?.id) ?? result.caseReview;
    audit(store, req, "admin.messenger.safety.case_review.open", "messenger_safety_case", savedCase.id, { reportId: id, created: result.created, linkedEvidenceIds: savedCase.linkedEvidenceIds });
    res.status(result.created ? 201 : 200).json({ ok: true, caseReview: savedCase, cases: saved.caseReviews.slice(0, 100), dashboard: buildMessengerSafetyDashboard() });
  });

  router.post("/messenger/safety/cases/:id/status", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    if (!isAdminWriteEnabled()) {
      res.status(423).json({ ok: false, error: "admin_write_disabled" });
      return;
    }
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const status = normalizeMessengerSafetyCaseStatus(body.status, "evidence_review");
    const assignedTo = readString(body.assignedTo);
    const note = readString(body.note);
    const state = readMessengerSafetyControlState();
    const by = req.admin?.id ?? "admin";
    const now = new Date().toISOString();
    let changed: AdminMessengerSafetyCaseReview | undefined;
    const caseReviews = state.caseReviews.map((item) => {
      if (item.id !== id) return item;
      changed = refreshMessengerSafetyCaseReview(state, {
        ...item,
        status,
        assignedTo: assignedTo ?? item.assignedTo,
        timeline: [{ event: `status:${status}`, by, at: now, note }, ...item.timeline],
        updatedBy: by,
        updatedAt: now,
      });
      return changed;
    });
    if (!changed) {
      res.status(404).json({ ok: false, error: "messenger_safety_case_not_found" });
      return;
    }
    const saved = writeMessengerSafetyControlState({ ...state, caseReviews });
    audit(store, req, "admin.messenger.safety.case_review.status", "messenger_safety_case", id, { status, assignedTo });
    res.json({ ok: true, caseReview: changed, cases: saved.caseReviews.slice(0, 100), dashboard: buildMessengerSafetyDashboard() });
  });

