    const incident = createMessengerSafetyIncidentResponse(readBodyObject(req), req.admin?.id ?? "unknown", previousTraceHash);
    const saved = writeMessengerSafetyControlState({ ...current, incidentResponses: [incident, ...current.incidentResponses].slice(0, 1000), updatedAt: new Date().toISOString() });
    const snapshot = buildMessengerSafetyIncidentResponseSnapshot(req, store);
