  router.post("/messenger/safety/incidents/:id/status", requireAdminPermission("messenger:write"), (req: AdminRequest, res: Response) => {
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const current = readMessengerSafetyControlState();
    const existing = current.incidentResponses.find((item) => item.id === id);
    if (!existing) return res.status(404).json({ error: "incident_not_found" });
    const now = new Date().toISOString();
    const status = normalizeMessengerSafetyIncidentResponseStatus(body.status, existing.status);
    const updatedBase = { ...existing, status, updatedBy: req.admin?.id ?? "unknown", updatedAt: now, timeline: [{ at: now, by: req.admin?.id ?? "unknown", action: "status_changed" as const, status, note: readString(body.note) }, ...existing.timeline].slice(0, 100) };
    const incidentHash = sha256Text({ id: updatedBase.id, source: updatedBase.source, sourceKey: updatedBase.sourceKey, status: updatedBase.status, linkedReportIds: updatedBase.linkedReportIds, linkedCaseIds: updatedBase.linkedCaseIds, linkedEvidenceIds: updatedBase.linkedEvidenceIds });
    const traceHash = sha256Text({ incidentHash, previousTraceHash: updatedBase.previousTraceHash, updatedAt: now, timeline: updatedBase.timeline });
    const updated = { ...updatedBase, containmentRequired: isMessengerSafetyIncidentOpen(status) ? updatedBase.containmentRequired : false, incidentHash, traceHash } as AdminMessengerSafetyIncidentResponse;
    const normalized = { ...updated, checklist: buildMessengerSafetyIncidentResponseChecklist(updated) };
    const saved = writeMessengerSafetyControlState({ ...current, incidentResponses: current.incidentResponses.map((item) => item.id === id ? normalized : item), updatedAt: now });
    const snapshot = buildMessengerSafetyIncidentResponseSnapshot(req, store);
    audit(store, req, "admin.messenger.safety.incidents.status", "messenger_safety_incident_response", id, { status: normalized.status, rawContentIncluded: false, traceHash: normalized.traceHash });
    res.json({ ok: true, incident: normalized, incidents: saved.incidentResponses.slice(0, 100), snapshot, dashboard: buildMessengerSafetyDashboard() });
  });

