  router.post("/messenger/safety/emergency-actions/:id/status", requireAdminPermission("messenger:write"), requireRootOwner, (req: AdminRequest, res: Response) => {
    const id = getParam(req, "id");
    const body = readBodyObject(req);
    const current = readMessengerSafetyControlState();
    const merged = mergeMessengerSafetyEmergencyActions(current, req.admin?.id ?? "unknown");
    const existing = merged.find((item) => item.id === id);
    if (!existing) return res.status(404).json({ error: "messenger_safety_emergency_action_not_found" });
    const now = new Date().toISOString();
    const status = normalizeMessengerSafetyEmergencyActionStatus(body.status, existing.status);
    const timelineAction: AdminMessengerSafetyEmergencyActionTimelineItem["action"] = status === "activated" || status === "containment" ? "activated" : status === "resolved" ? "resolved" : status === "released" ? "released" : status === "rejected" ? "rejected" : "status_changed";
    const updatedBase = {
      ...existing,
      status,
      ownerApprovedBy: status === "activated" || status === "containment" ? req.admin?.id ?? "root-owner" : existing.ownerApprovedBy,
      ownerApprovedAt: status === "activated" || status === "containment" ? now : existing.ownerApprovedAt,
      activeFrom: status === "activated" || status === "containment" ? existing.activeFrom ?? now : existing.activeFrom,
      resolvedAt: status === "resolved" ? now : existing.resolvedAt,
      releasedBy: status === "released" ? req.admin?.id ?? "root-owner" : existing.releasedBy,
      releasedAt: status === "released" ? now : existing.releasedAt,
      releaseReason: status === "released" ? readString(body.note) ?? existing.releaseReason : existing.releaseReason,
      updatedBy: req.admin?.id ?? "root-owner",
      updatedAt: now,
      timeline: [{ at: now, by: req.admin?.id ?? "root-owner", action: timelineAction, status, note: readString(body.note) }, ...existing.timeline].slice(0, 100),
    };
    const emergencyHash = sha256Text({ id: updatedBase.id, source: updatedBase.source, sourceId: updatedBase.sourceId, status: updatedBase.status, scope: updatedBase.scope, targetId: updatedBase.targetId, linkedIncidentIds: updatedBase.linkedIncidentIds, linkedEvidenceIds: updatedBase.linkedEvidenceIds });
    const traceHash = sha256Text({ emergencyHash, previousTraceHash: updatedBase.previousTraceHash, updatedAt: now, timeline: updatedBase.timeline });
    const updated = { ...updatedBase, emergencyHash, traceHash } as AdminMessengerSafetyEmergencyAction;
    const normalized = { ...updated, checklist: buildMessengerSafetyEmergencyActionChecklist(updated) };
    const storedWithoutAuto = current.emergencyActions.filter((item) => item.id !== id);
    const saved = writeMessengerSafetyControlState({ ...current, emergencyActions: [normalized, ...storedWithoutAuto].slice(0, 1000), updatedAt: now });
    const snapshot = buildMessengerSafetyEmergencyActionSnapshot(req, store);
    audit(store, req, "admin.messenger.safety.emergency_actions.status", "messenger_safety_emergency_action", id, { status: normalized.status, scope: normalized.scope, rawContentIncluded: false, traceHash: normalized.traceHash });
    res.json({ ok: true, action: normalized, actions: saved.emergencyActions.slice(0, 100), snapshot, dashboard: buildMessengerSafetyDashboard() });
  });

